function translateBetaiDynamicTemplateV1850(value, lang) {
  const text = String(value || '').trim()
  if (!text) return text

  if (lang === 'en') {
    let match
    if ((match = text.match(/^Pokazano\s+(\d+)\s+z\s+(\d+)\s+typów$/i))) return `Showing ${match[1]} of ${match[2]} picks`
    if ((match = text.match(/^Pokazano\s+(\d+)\s+z\s+(\d+)\s+typerów$/i))) return `Showing ${match[1]} of ${match[2]} tipsters`
    if ((match = text.match(/^Pokaż kolejne\s+(\d+)\s+typy\s+\((\d+)\s+pozostało\)$/i))) return `Show next ${match[1]} picks (${match[2]} remaining)`
    if ((match = text.match(/^Zwiń do\s+(\d+)\s+typów$/i))) return `Collapse to ${match[1]} picks`
    if ((match = text.match(/^Top\s+(\d+)\s+z\s+(\d+)$/i))) return `Top ${match[1]} of ${match[2]}`
    if ((match = text.match(/^(\d+)\s+min(?:ut(?:a|y|ę)?|uty|uta)?\s+temu$/i))) return `${match[1]} min ago`
    if ((match = text.match(/^(\d+)\s*min\s+temu$/i))) return `${match[1]} min ago`
    if ((match = text.match(/^(\d+)\s*h\s+temu$/i))) return `${match[1]}h ago`
    if ((match = text.match(/^(\d+)\s+godzin(?:a|y|ę)?\s+temu$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'hour' : 'hours'} ago`
    if ((match = text.match(/^(\d+)\s+(?:dzień|dni)\s+temu$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'day' : 'days'} ago`
    if ((match = text.match(/^Wysłałeś\s+(\d+)\s+coin(?:a|y|ów)?\s+do\s+(.+?)\.?$/i))) return `You sent ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'} to ${match[2]}.`
    if ((match = text.match(/^Dostałeś\s+\+(\d+)\s+(?:żeton(?:y|ów)?|coin(?:y|ów)?)\s+Premium\s+za\s+pierwszą\s+wiadomość\s+dnia\s+na\s+BetAI\s+Live\s+Chat\.\s+Kolejne\s+(?:wiadomości|messages)\s+dzisiaj\s+nie\s+dają\s+już\s+tego\s+bonusu\.?$/i))) return `You received +${match[1]} Premium ${Number(match[1]) === 1 ? 'coin' : 'coins'} for your first message of the day in BetAI Live Chat. Further messages today do not grant this bonus.`
    if ((match = text.match(/^(\d+)\s+wiadomości\s+dziś$/i))) return `${match[1]} messages today`
    if ((match = text.match(/^(\d+)\s+wiadomości$/i))) return `${match[1]} messages`
    if ((match = text.match(/^(\d+)\s+zdarzenia$/i))) return `${match[1]} events`
    if ((match = text.match(/^(\d+)\s+łącznie$/i))) return `${match[1]} total`
    if ((match = text.match(/^Typ:\s*(.+?)\s+•\s+Kurs:\s*(.+)$/i))) return `Pick: ${match[1]} • Odds: ${match[2]}`
    if ((match = text.match(/^Kurs\s+(.+)$/i))) return `Odds ${match[1]}`
    if ((match = text.match(/^Pozostało dziś:\s*(\d+)$/i))) return `Remaining today: ${match[1]}`
    if ((match = text.match(/^([+-]?\d+(?:[.,]\d+)?)\s+pkt$/i))) return `${match[1]} pts`
    if ((match = text.match(/^(\d+)\s*\/\s*7\s+dni$/i))) return `${match[1]} / 7 days`
    if ((match = text.match(/^(\d+)\s+dni$/i))) return `${match[1]} days`
    if ((match = text.match(/^(\d+)%\s+obecności$/i))) return `${match[1]}% attendance`
    if ((match = text.match(/^Nagroda gotowa:\s*(\d+)\s+coin$/i))) return `Reward ready: ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'}`
    if ((match = text.match(/^Obecność tygodnia:\s*(\d+)\s+coin$/i))) return `Weekly attendance: ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'}`
    if ((match = text.match(/^Seria typów gotowa:\s*(\d+)\s+coin$/i))) return `Pick streak ready: ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'}`
    if ((match = text.match(/^Seria typów:\s*(\d+)\/7\s+dni$/i))) return `Pick streak: ${match[1]}/7 days`
    if ((match = text.match(/^Odbierz\s+(\d+)\s+coin$/i))) return `Claim ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'}`
    if ((match = text.match(/^Masz nagrodę do odebrania:\s*(\d+)\s+coin\.?$/i))) return `You have a reward to claim: ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'}.`
    if ((match = text.match(/^Odebrano dzienną obecność:\s*\+(\d+)\s+coin\.?$/i))) return `Daily attendance claimed: +${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'}.`
    if ((match = text.match(/^Odebrano nagrodę tygodniową:\s*\+(\d+)\s+coin\.?$/i))) return `Weekly reward claimed: +${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'}.`
    if ((match = text.match(/^Odebrano nagrodę za serię typów:\s*\+(\d+)\s+coin\.?$/i))) return `Pick streak reward claimed: +${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'}.`
    if ((match = text.match(/^Odebrano nagrodę za win streak:\s*\+(\d+)\s+coin\.?$/i))) return `Win streak reward claimed: +${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'}.`
    if ((match = text.match(/^Dodano\s+(\d+)\s+coin za dzisiejszą obecność\.?$/i))) return `Added ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'} for today's attendance.`
    if ((match = text.match(/^Dodano\s+(\d+)\s+coin za pełny tydzień obecności\.?$/i))) return `Added ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'} for a full week of attendance.`
    if ((match = text.match(/^Dodano\s+(\d+)\s+coin za 7 dni dodawania typów\.?$/i))) return `Added ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'} for 7 days of adding picks.`
    if ((match = text.match(/^Dodano\s+(\d+)\s+coin za trafione 5\/5\.?$/i))) return `Added ${match[1]} ${Number(match[1]) === 1 ? 'coin' : 'coins'} for a 5/5 win streak.`
    if ((match = text.match(/^(\d+)\s+(mecz|mecze|meczów)$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'match' : 'matches'}`
    if ((match = text.match(/^(\d+)\s+wydarzeń\s+•\s+godziny rosnąco$/i))) return `${match[1]} events • time ascending`
    if ((match = text.match(/^(\d+)\s+wydarze(?:nie|nia|ń)$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'event' : 'events'}`
    if ((match = text.match(/^Najbliższe mecze\s+•\s+(.+?)\s+•\s+(.+)$/i))) return `Upcoming matches • ${match[1]} • ${match[2]}`
    if ((match = text.match(/^AKO\s+(\d+)\s+zdarzenia?$/i))) return `Accumulator ${match[1]} events`
    if ((match = text.match(/^Kupon AKO\s*\((\d+)\)$/i))) return `Accumulator coupon (${match[1]})`
    if ((match = text.match(/^Ty:\s*([0-9.,]+)\s*zł\s*•\s*Platforma:\s*([0-9.,]+)\s*zł$/i))) return `You: ${match[1]} PLN • Platform: ${match[2]} PLN`
    if ((match = text.match(/^Zostało\s+(\d+)\s+(dzień|dni)$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'day' : 'days'} left`
    if ((match = text.match(/^(\d+)\s+wyników$/i))) return `${match[1]} results`
    if ((match = text.match(/^(\d+)\s+sprzedaży$/i))) return `${match[1]} sales`
    if ((match = text.match(/^(\d+)\s+transakcji$/i))) return `${match[1]} transactions`
    if ((match = text.match(/^(\d+)\s+aktywnych kont$/i))) return `${match[1]} active accounts`
    if ((match = text.match(/^(\d+)\s+gotowych$/i))) return `${match[1]} ready`
    if ((match = text.match(/^(\d+)\s+zgłoszeń na\s+(.+)$/i))) return `${match[1]} requests totaling ${match[2]}`
    if ((match = text.match(/^(\d+)\s+zgłoszeń poniżej 50 zł$/i))) return `${match[1]} requests below 50 PLN`
    if ((match = text.match(/^(\d+)\s+zaznaczonych oczekujących$/i))) return `${match[1]} selected pending`
    if ((match = text.match(/^(\d+)\s+z nich gotowych do wypłaty$/i))) return `${match[1]} of them ready for payout`
    if ((match = text.match(/^Pokaż więcej\s*\((\d+)\)$/i))) return `Show more (${match[1]})`
    if ((match = text.match(/^Wpłać\s+(.+)\s+przez Stripe$/i))) return `Deposit ${match[1]} via Stripe`
    if ((match = text.match(/^Faktura\s+(.+)$/i))) return `Invoice ${match[1]}`
    if ((match = text.match(/^Tip wysłany do\s+(.+)$/i))) return `Tip sent to ${match[1]}`
    if ((match = text.match(/^Tip od\s+(.+)$/i))) return `Tip from ${match[1]}`
    if ((match = text.match(/^Nagroda społeczności:\s*(.+)$/i))) return `Community reward: ${match[1]}`
    if ((match = text.match(/^(\d+)\s+wiadomości$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'message' : 'messages'}`
    if ((match = text.match(/^(\d+)\s+aktywności$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'activity' : 'activities'}`
    if ((match = text.match(/^(\d+)\s+(post|posty|postów)$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'post' : 'posts'}`
    if ((match = text.match(/^(\d+)\s+typów$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'pick' : 'picks'}`
    if ((match = text.match(/^Post w kanale\s+#(.+)$/i))) return `Post in channel #${match[1]}`
    if ((match = text.match(/^Napisz post w\s+#(.+)\.\.\.$/i))) return `Write a post in #${match[1]}...`
    if ((match = text.match(/^Opublikuj pierwszy realny wpis w\s+#(.+)\.$/i))) return `Publish the first real post in #${match[1]}.`
    if ((match = text.match(/^Napisz pierwszą wiadomość na\s+#(.+)\.$/i))) return `Write the first message in #${match[1]}.`
    if ((match = text.match(/^Napisz wiadomość w\s+#(.+)\.\.\.$/i))) return `Write a message in #${match[1]}...`
    if ((match = text.match(/^Dodano plik:\s*(.+)$/i))) return `File added: ${match[1]}`
    if ((match = text.match(/^(.+?) została już odebrana w ostatnich 24h\.$/i))) return `${match[1]} has already been claimed in the last 24 hours.`
    if ((match = text.match(/^Najpierw wykonaj misję:\s*(.+?)\. Coin można odebrać raz na 24h\.$/i))) return `Complete the mission first: ${match[1]}. A coin can be claimed once every 24 hours.`
    if ((match = text.match(/^Nagroda rankingowa:\s*(.+)$/i))) return `Ranking reward: ${match[1]}`
    if ((match = text.match(/^Premium ważne do:\s*(.+?)\s*·\s*zostało\s+(\d+)\s+(dzień|dni)$/i))) return `Premium valid until: ${match[1]} · ${match[2]} ${Number(match[2]) === 1 ? 'day' : 'days'} left`
    if ((match = text.match(/^(.+?)%\s+vs poprzedni okres$/i))) return `${match[1]}% vs previous period`
    if ((match = text.match(/^(.+?)%\s+wypłaconych zarobków typerów\.$/i))) return `${match[1]}% of tipster earnings paid out.`
    if ((match = text.match(/^(.+?)\s+oczekuje na obsługę\.$/i))) return `${match[1]} is awaiting processing.`
    if ((match = text.match(/^Łącznie\s+(.+?)\s+realnego przychodu\.$/i))) return `Total real revenue: ${match[1]}.`
    if ((match = text.match(/^(\d+)\s+łącznie$/i))) return `${match[1]} total`
    if ((match = text.match(/^Pokazano\s+(\d+)\s+z\s+(\d+)$/i))) return `Showing ${match[1]} of ${match[2]}`
    if ((match = text.match(/^(\d+)\s+opinii$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'review' : 'reviews'}`
    if ((match = text.match(/^Na podstawie\s+(\d+)\s+opinii$/i))) return `Based on ${match[1]} ${Number(match[1]) === 1 ? 'review' : 'reviews'}`
    if ((match = text.match(/^(\d+)\s+pozycji$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'entry' : 'entries'}`
    if ((match = text.match(/^(\d+)\s+aktywne pakiety$/i))) return `${match[1]} active packages`
    if ((match = text.match(/^(\d+)\s+dni dostępu$/i))) return `${match[1]} days of access`
    if ((match = text.match(/^Zostało\s+(\d+)\s+dni dostępu$/i))) return `${match[1]} days of access left`
    if ((match = text.match(/^Następna:\s*(.+)$/i))) return `Next: ${match[1]}`
    if ((match = text.match(/^Pokaż kolejne\s+(\d+)$/i))) return `Show next ${match[1]}`
    if ((match = text.match(/^Pokaż kolejne\s+(\d+)\s+typy\s*\((\d+)\s+pozostało\)$/i))) return `Show next ${match[1]} picks (${match[2]} remaining)`
    if ((match = text.match(/^(\d+)\/500 znaków$/i))) return `${match[1]}/500 characters`
    if ((match = text.match(/^(.+?)\s+•\s+ważne do\s+(.+)$/i))) return `${match[1]} • valid until ${match[2]}`
    if ((match = text.match(/^Pokazano\s+(\d+)$/i))) return `Showing ${match[1]}`
    if ((match = text.match(/^Zgłoszono\s+(wygraną|przegraną|zwrot)\.\s*Typ zostaje widoczny jako oczekujący, a statystyki dopiszą się dopiero po zatwierdzeniu admina\.$/i))) {
      const result = match[1].toLowerCase() === 'wygraną' ? 'a win' : match[1].toLowerCase() === 'przegraną' ? 'a loss' : 'a void'
      return `Submitted ${result}. The pick remains pending and statistics will be added only after admin approval.`
    }
    if ((match = text.match(/^(.+?)\s+wygra\s+do\s+przerwy$/i))) return `${match[1]} to win at half-time`
    if ((match = text.match(/^(.+?)\s+lub\s+remis$/i))) return `${match[1]} or draw`
    if ((match = text.match(/^(.+?)\s+wygra$/i))) return `${match[1]} to win`
    if ((match = text.match(/^\+(\d+)\s+więcej\s+zdarzeń$/i))) return `+${match[1]} more events`
  }

  if (lang === 'pl') {
    let match
    if ((match = text.match(/^Showing\s+(\d+)\s+of\s+(\d+)\s+picks$/i))) return `Pokazano ${match[1]} z ${match[2]} typów`
    if ((match = text.match(/^Showing\s+(\d+)\s+of\s+(\d+)\s+tipsters$/i))) return `Pokazano ${match[1]} z ${match[2]} typerów`
    if ((match = text.match(/^Show next\s+(\d+)\s+picks\s+\((\d+)\s+remaining\)$/i))) return `Pokaż kolejne ${match[1]} typy (${match[2]} pozostało)`
    if ((match = text.match(/^Collapse to\s+(\d+)\s+picks$/i))) return `Zwiń do ${match[1]} typów`
    if ((match = text.match(/^(\d+)\s+min\s+ago$/i))) return `${match[1]} min temu`
    if ((match = text.match(/^(\d+)h\s+ago$/i))) return `${match[1]}h temu`
    if ((match = text.match(/^(\d+)\s+hours?\s+ago$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'godzinę' : Number(match[1]) < 5 ? 'godziny' : 'godzin'} temu`
    if ((match = text.match(/^(\d+)\s+days?\s+ago$/i))) return `${match[1]} ${Number(match[1]) === 1 ? 'dzień' : 'dni'} temu`
    if ((match = text.match(/^(.+?)\s+to\s+win\s+at\s+half-time$/i))) return `${match[1]} wygra do przerwy`
    if ((match = text.match(/^(.+?)\s+or\s+draw$/i))) return `${match[1]} lub remis`
    if ((match = text.match(/^(.+?)\s+to\s+win$/i))) return `${match[1]} wygra`
  }

  return text
}

