const BETAI_TRANSLATION_DICTIONARY_CACHE = new Map()
const BETAI_TRANSLATION_KEYS_CACHE = new Map()

function buildBetaiTranslationDictionary(lang) {
  const cacheKey = BETAI_LANGUAGES.includes(lang) ? lang : 'pl'
  if (BETAI_TRANSLATION_DICTIONARY_CACHE.has(cacheKey)) {
    return BETAI_TRANSLATION_DICTIONARY_CACHE.get(cacheKey)
  }
  const allSources = [
    BETAI_DASHBOARD_TRANSLATIONS,
    BETAI_EXTRA_DASHBOARD_TRANSLATIONS,
    BETAI_FULL_TRANSLATIONS_V1824,
    BETAI_EN_DASHBOARD_FIX_TRANSLATIONS_V1850,
    BETAI_STARTED_FILTER_TRANSLATIONS_V1833,
    BETAI_ADD_PICK_TRANSLATIONS_V1853,
    BETAI_UNLOCKED_TIPS_TRANSLATIONS_V1858,
    BETAI_FINANCE_TRANSLATIONS_V1856,
    BETAI_PROFILE_TRANSLATIONS_V1857,
    BETAI_RANKING_TRANSLATIONS_V1859,
    BETAI_COMMUNITY_TRANSLATIONS_V1860,
    BETAI_AI_TOP_TIPSTERS_TRANSLATIONS_V1863,
    BETAI_AI_LEAGUE_MODAL_TRANSLATIONS_V1864,
    BETAI_REWARDS_TRANSLATIONS_V1865
  ]
  const allTargetDictionaries = allSources.map(source => source?.[lang] || {})
  const target = Object.assign({}, ...allTargetDictionaries)
  const allDictionaries = []
  allSources.forEach(source => {
    BETAI_LANGUAGES.filter(code => code !== 'pl').forEach(code => {
      if (source?.[code]) allDictionaries.push(source[code])
    })
  })
  const reverse = {}
  const polishKeys = new Set()
  allSources.forEach(source => {
    BETAI_LANGUAGES.filter(code => code !== 'pl').forEach(code => {
      Object.keys(source?.[code] || {}).forEach(key => polishKeys.add(key))
    })
  })
  polishKeys.forEach(pl => {
    const translated = lang === 'pl' ? pl : (target[pl] || pl)
    reverse[pl] = translated
    allDictionaries.forEach(dict => {
      const value = dict?.[pl]
      if (value) reverse[value] = translated
    })
  })
  BETAI_TRANSLATION_DICTIONARY_CACHE.set(cacheKey, reverse)
  BETAI_TRANSLATION_KEYS_CACHE.set(cacheKey, Object.keys(reverse).sort((a, b) => b.length - a.length))
  return reverse
}

function translateBetaiTextValue(value, lang) {
  const raw = String(value || '')
  const trimmed = raw.trim()
  if (!trimmed) return value
  const dynamicDirectV1850 = translateBetaiDynamicTemplateV1850(trimmed, lang)
  if (dynamicDirectV1850 !== trimmed) return raw.replace(trimmed, dynamicDirectV1850)
  const dictionary = buildBetaiTranslationDictionary(lang)
  const direct = dictionary[trimmed]
  if (direct) return raw.replace(trimmed, direct)
  const prefixMatch = trimmed.match(/^([+\-•\s]*[\p{Extended_Pictographic}\p{Emoji_Presentation}]?\s*)(.+)$/u)
  if (prefixMatch && prefixMatch[2] && dictionary[prefixMatch[2]]) {
    return raw.replace(trimmed, `${prefixMatch[1]}${dictionary[prefixMatch[2]]}`)
  }
  let next = trimmed
  const cacheKey = BETAI_LANGUAGES.includes(lang) ? lang : 'pl'
  const keys = BETAI_TRANSLATION_KEYS_CACHE.get(cacheKey) || Object.keys(dictionary).sort((a, b) => b.length - a.length)
  const escapeRegExp = (text) => String(text).replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
  const isWordChar = (char) => char ? /[\p{L}\p{N}_]/u.test(char) : false

  // Tłumaczymy wyłącznie całe słowa lub całe frazy. Poprzednia wersja
  // podmieniała np. angielskie "Popular" wewnątrz polskiego "Popularne".
  // MutationObserver uruchamiał podmianę ponownie i tekst rósł w nieskończoność.
  for (const key of keys) {
    const replacement = dictionary[key]
    if (!key || key.length < 3 || !replacement || replacement === key) continue
    const escaped = escapeRegExp(key)
    const needsLeftBoundary = isWordChar(key[0])
    const needsRightBoundary = isWordChar(key[key.length - 1])
    const left = needsLeftBoundary ? '(^|[^\\p{L}\\p{N}_])' : '(^|)'
    const right = needsRightBoundary ? '(?=$|[^\\p{L}\\p{N}_])' : ''
    const pattern = new RegExp(`${left}(${escaped})${right}`, 'gu')
    next = next.replace(pattern, (match, prefix) => `${prefix || ''}${replacement}`)
  }

  if (lang !== 'pl') {
    next = next
      .replace(/\bTypy\b/g, 'Picks')
      .replace(/\bWygrane\b/g, 'Won')
      .replace(/\bKurs\b/g, dictionary['Kurs'] || 'Odds')
  }
  return next !== trimmed ? raw.replace(trimmed, next) : value
}

const PLATFORM_COMMISSION_RATE = 0.20

function getMonthlyCount(rows = []) {
  const now = new Date()
  return rows.filter(row => {
    const date = new Date(row.created_at)
    return date.getFullYear() === now.getFullYear() && date.getMonth() === now.getMonth()
  }).length
}


class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props)
    this.state = { error: null }
  }

  static getDerivedStateFromError(error) {
    return { error }
  }

  componentDidCatch(error, info) {
    console.error('BetAI render error:', error, info)
  }

  render() {
    if (this.state.error) {
      return (
        <div className="auth-screen">
          <div className="auth-card">
            <div className="auth-brand">Bet<span>+AI</span></div>
            <h1>Błąd aplikacji</h1>
            <p>{this.state.error.message}</p>
            <button className="auth-submit" onClick={() => {
              localStorage.clear()
              window.location.href = '/'
            }}>
              Wyczyść cache i wróć
            </button>
          </div>
        </div>
      )
    }

    return this.props.children
  }
}



function normalizePublicSlug(value) {
  return String(value || '')
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48)
}

function getTipsterPublicUrl(profile, fallbackId) {
  const rawSlug = profile?.public_slug || profile?.username || (profile?.email ? profile.email.split('@')[0] : '') || fallbackId || ''
  const slug = normalizePublicSlug(rawSlug) || fallbackId
  if (typeof window === 'undefined') return `/tipster/${slug}`
  return `${window.location.origin}/tipster/${slug}`
}

function normalizeReferralCodeInput(code) {
  return String(code || '')
    .trim()
    .replace(/[^a-zA-Z0-9]+/g, '')
    .slice(0, 32)
    .toUpperCase()
}

function getStoredReferralCode() {
  if (typeof window === 'undefined') return ''
  return normalizeReferralCodeInput(localStorage.getItem('betai_referral_code') || '')
}

function setStoredReferralCode(code) {
  if (typeof window === 'undefined') return
  const clean = normalizeReferralCodeInput(code)
  if (clean) localStorage.setItem('betai_referral_code', clean)
}

function getAiConfidence(tip) {
  return Math.max(0, Math.min(100, Math.round(Number(tip?.ai_confidence ?? tip?.ai_probability ?? tip?.confidence ?? 0) || 0)))
}

function isAiGeneratedTip(tip) {
  const source = String(tip?.ai_source || '').toLowerCase()
  return source === 'real_ai_engine'
}

function isUserTip(tip) {
  return !isAiGeneratedTip(tip)
}

function isLiveAiTip(tip) {
  const aiSource = String(tip?.ai_source || '').toLowerCase()
  const liveStatus = String(tip?.live_status || '').trim().toUpperCase()
  const status = String(tip?.status || '').toLowerCase()
  return aiSource === 'real_ai_engine' && liveStatus !== 'NS' && (status === 'live' || Number(tip?.live_minute || 0) > 0)
}

function isPreMatchAiTip(tip) {
  return isAiGeneratedTip(tip) && !isLiveAiTip(tip)
}

function getAiScore(tip) {
  const confidence = getAiConfidence(tip)
  const odds = Number(tip?.odds || 0)
  const computed = odds > 1 ? Math.round((confidence / 100) * odds * 100) : confidence
  return Math.max(0, Math.min(100, Math.round(Number(tip?.ai_score ?? computed) || 0)))
}

function getAiAnalysis(tip) {
  const confidence = getAiConfidence(tip)
  const score = getAiScore(tip)
  if (tip?.ai_analysis) return tip.ai_analysis
  if (tip?.analysis) return tip.analysis
  if (confidence >= 85 || score >= 85) return 'AI wykrywa mocny value pick: wysoka pewność, korzystny kurs i dobry stosunek ryzyka do potencjalnego zysku.'
  if (confidence >= 70 || score >= 70) return 'AI ocenia ten typ jako solidny wybór z dodatnią wartością przy aktualnym kursie.'
  return 'AI zaleca ostrożność i dodatkowe sprawdzenie danych przed zakupem lub grą.'
}

function getAiBadges(tip) {
  const confidence = getAiConfidence(tip)
  const score = getAiScore(tip)
  const odds = Number(tip?.odds || 0)
  const badges = []
  if (confidence >= 80) badges.push('🧠 AI PICK')
  if (score >= 85) badges.push('🔥 HOT')
  if (odds >= 1.8 && confidence >= 65) badges.push('💎 VALUE')
  return badges
}

function getReferralUrl(code) {
  const clean = String(code || '').trim()
  if (!clean) return ''
  if (typeof window === 'undefined') return '/ref/' + clean
  return window.location.origin + '/ref/' + clean
}

function getReferralProfileUrl(code) {
  const clean = String(code || '').trim()
  if (!clean) return ''
  if (typeof window === 'undefined') return '/?ref=' + clean
  return window.location.origin + '/?ref=' + clean
}

function getTipAuthorId(tip) {
  return tip?.author_id || tip?.user_id || tip?.created_by || tip?.owner_id || tip?.tipster_id || null
}

function getTipAuthorStatsKey(tip) {
  return String(
    getTipAuthorId(tip) ||
    tip?.author_email ||
    tip?.email ||
    tip?.user_email ||
    tip?.author_name ||
    tip?.username ||
    'unknown'
  ).toLowerCase()
}

function normalizeTipSettlementStatus(value) {
  const clean = String(value || '').trim().toLowerCase()
  if (['won', 'win', 'wygrał', 'wygral', 'wygrany', 'green'].includes(clean)) return 'won'
  if (['lost', 'loss', 'przegrał', 'przegral', 'przegrany', 'red'].includes(clean)) return 'lost'
  if (['void', 'push', 'zwrot', 'cancelled', 'canceled', 'anulowany'].includes(clean)) return 'void'
  return 'pending'
}

function normalizeResult(value) {
  const clean = String(value || '').trim().toLowerCase()
  if (['won', 'win', 'wygrał', 'wygral', 'wygrany', 'green', 'success'].includes(clean) || clean.includes('won') || clean.includes('win')) return 'win'
  if (['lost', 'lose', 'loss', 'przegrał', 'przegral', 'przegrany', 'red', 'failed'].includes(clean) || clean.includes('lost') || clean.includes('lose') || clean.includes('loss')) return 'loss'
  if (['void', 'push', 'zwrot', 'cancelled', 'canceled', 'anulowany', 'return'].includes(clean)) return 'void'
  return 'pending'
}

function readTipStakeValue(tip) {
  return Number(tip?.stake ?? tip?.amount ?? tip?.stawka ?? tip?.bet_amount ?? tip?.total_staked ?? 0) || 0
}

function readTipProfitValue(tip) {
  const stake = readTipStakeValue(tip)
  const odds = Number(tip?.odds ?? tip?.course ?? 0) || 0
  const status = normalizeTipSettlementStatus(tip?.status ?? tip?.result ?? tip?.result_status)

  // Po resecie profit w bazie może mieć domyślne 0.
  // Dla rozliczonego typu NIE wolno traktować profit=0 jako prawdy, bo wygrany typ z kursem 1.21 musi dać +21 zł.
  if (status === 'won') return stake * Math.max(odds - 1, 0)
  if (status === 'lost') return -stake
  if (status === 'void') return 0

  const explicit = tip?.profit ?? tip?.profit_amount ?? tip?.result_profit ?? tip?.payout_profit
  if (explicit !== undefined && explicit !== null && String(explicit) !== '') return Number(explicit) || 0
  return 0
}

function buildAuthorStatsFromTips(tips = []) {
  const statsMap = new Map()
  ;(tips || []).forEach(rawTip => {
    const tip = normalizeTipRow(rawTip)
    const key = getTipAuthorStatsKey(tip)
    if (!key || key === 'unknown') return
    const current = statsMap.get(key) || {
      totalTips: 0,
      wonTips: 0,
      lostTips: 0,
      voidTips: 0,
      pendingTips: 0,
      totalStaked: 0,
      profit: 0,
      highestOdds: 0,
      avgOddsSum: 0,
      avgOddsCount: 0,
    }
    const status = normalizeTipSettlementStatus(tip.status ?? tip.result)
    const stake = readTipStakeValue(tip)
    const odds = Number(tip.odds ?? tip.course ?? 0) || 0
    current.totalTips += 1
    if (status === 'won') current.wonTips += 1
    else if (status === 'lost') current.lostTips += 1
    else if (status === 'void') current.voidTips += 1
    else current.pendingTips += 1
    if (status === 'won' || status === 'lost') current.totalStaked += stake
    current.profit += readTipProfitValue(tip)
    if (odds > 0) {
      current.highestOdds = Math.max(current.highestOdds, odds)
      current.avgOddsSum += odds
      current.avgOddsCount += 1
    }
    statsMap.set(key, current)
  })
  return statsMap
}


// WERSJA 1791 — łączne statystyki dla profilu mającego kilka aliasów/rekordów autora.
// Dotyczy szczególnie betai-multisport-ai, którego stare i nowe typy mogły mieć
// różne author_id / username. Zamiast brać pierwszy fragment statystyk, sumujemy
// wszystkie realne rekordy tego samego kanonicznego profilu.
function buildCombinedTipStatsV1791(tips = []) {
  const combined = {
    totalTips: 0,
    wonTips: 0,
    lostTips: 0,
    voidTips: 0,
    pendingTips: 0,
    totalStaked: 0,
    profit: 0,
    highestOdds: 0,
    avgOddsSum: 0,
    avgOddsCount: 0,
  }

  ;(tips || []).forEach(rawTip => {
    const tip = normalizeTipRow(rawTip)
    const status = normalizeTipSettlementStatus(
      tip.status ?? tip.result ?? tip.result_status ?? tip.settlement_status
    )
    const stake = readTipStakeValue(tip)
    const odds = Number(tip.odds ?? tip.course ?? 0) || 0

    combined.totalTips += 1
    if (status === 'won') combined.wonTips += 1
    else if (status === 'lost') combined.lostTips += 1
    else if (status === 'void') combined.voidTips += 1
    else combined.pendingTips += 1

    if (status === 'won' || status === 'lost') combined.totalStaked += stake
    combined.profit += readTipProfitValue(tip)

    if (odds > 0) {
      combined.highestOdds = Math.max(combined.highestOdds, odds)
      combined.avgOddsSum += odds
      combined.avgOddsCount += 1
    }
  })

  return combined
}

function hasExplicitImportedStatsFields(profile = {}) {
  if (!profile || typeof profile !== 'object') return false
  return [
    'imported_total_tips',
    'imported_won_tips',
    'imported_lost_tips',
    'imported_void_tips',
    'imported_pending_tips',
    'imported_profit',
    'imported_yield',
    'imported_total_staked',
    'imported_avg_odds',
    'imported_highest_odds',
    'stats_imported_at',
  ].some(key => Object.prototype.hasOwnProperty.call(profile, key))
}

function getImportedProfileStats(profile) {
  if (!profile) return null

  const explicitImported = hasExplicitImportedStatsFields(profile)
  const importedTotalTips = Number(profile.imported_total_tips ?? 0) || 0
  const totalTips = explicitImported
    ? importedTotalTips
    : (importedTotalTips || (Number(profile.total_tips ?? profile.tips_count ?? 0) || 0))
  const wonTips = explicitImported ? (Number(profile.imported_won_tips ?? 0) || 0) : (Number(profile.imported_won_tips ?? profile.wins ?? 0) || 0)
  const lostTips = explicitImported ? (Number(profile.imported_lost_tips ?? 0) || 0) : (Number(profile.imported_lost_tips ?? profile.losses ?? 0) || 0)
  const voidTips = explicitImported ? (Number(profile.imported_void_tips ?? 0) || 0) : (Number(profile.imported_void_tips ?? profile.void_tips ?? profile.voids ?? profile.pushes ?? 0) || 0)
  const pendingTips = explicitImported ? (Number(profile.imported_pending_tips ?? 0) || 0) : (Number(profile.imported_pending_tips ?? profile.pending_tips ?? 0) || 0)
  const totalStaked = explicitImported ? (Number(profile.imported_total_staked ?? 0) || 0) : (Number(profile.imported_total_staked ?? profile.total_staked ?? 0) || 0)
  const profit = explicitImported ? (Number(profile.imported_profit ?? 0) || 0) : (Number(profile.imported_profit ?? profile.profit ?? profile.earnings ?? 0) || 0)
  const avgOdds = explicitImported ? (Number(profile.imported_avg_odds ?? 0) || 0) : (Number(profile.imported_avg_odds ?? profile.avg_odds ?? 0) || 0)
  const highestOdds = explicitImported ? (Number(profile.imported_highest_odds ?? 0) || 0) : (Number(profile.imported_highest_odds ?? profile.highest_odds ?? 0) || 0)
  const yieldValue = explicitImported ? (Number(profile.imported_yield ?? 0) || 0) : (Number(profile.imported_yield ?? profile.yield ?? profile.roi ?? 0) || 0)

  // Po resecie imported_* = 0 oznacza brak importu. Nie wolno wtedy brać
  // starych author_imported_stats z cache/typów jako fallbacku, bo odtwarza stare 766.
  const hasRealImportedStats =
    totalTips > 0 ||
    wonTips > 0 ||
    lostTips > 0 ||
    voidTips > 0 ||
    pendingTips > 0 ||
    totalStaked > 0 ||
    profit !== 0 ||
    avgOdds > 0 ||
    highestOdds > 0 ||
    yieldValue !== 0

  if (!hasRealImportedStats) return null

  return {
    yield: yieldValue,
    totalTips,
    wonTips,
    lostTips,
    voidTips,
    pendingTips,
    totalStaked,
    profit,
    avgOdds,
    highestOdds,
    // v1805: historyczny import może być bazą, do której dopisujemy nowe typy.
    additive: Boolean(profile.imported_stats_additive || String(profile.imported_stats_mode || '').toLowerCase() === 'baseline'),
    statsImportedAt: profile.stats_imported_at || profile.imported_at || null,
  }
}

function finalizeAuthorStats(dynamicStats = null, importedStats = null) {
  const dynamicTotalStaked = Number(dynamicStats?.totalStaked || 0)
  const dynamicProfit = Number(dynamicStats?.profit || 0)
  const dynamicFinal = {
    yield: dynamicTotalStaked > 0 ? (dynamicProfit / dynamicTotalStaked) * 100 : 0,
    totalTips: Number(dynamicStats?.totalTips || 0) || 0,
    wonTips: Number(dynamicStats?.wonTips || 0) || 0,
    lostTips: Number(dynamicStats?.lostTips || 0) || 0,
    voidTips: Number(dynamicStats?.voidTips || 0) || 0,
    pendingTips: Number(dynamicStats?.pendingTips || 0) || 0,
    totalStaked: dynamicTotalStaked,
    profit: dynamicProfit,
    avgOdds: Number(dynamicStats?.avgOddsCount || 0) > 0 ? Number(dynamicStats.avgOddsSum || 0) / Number(dynamicStats.avgOddsCount || 1) : 0,
    highestOdds: Number(dynamicStats?.highestOdds || 0) || 0,
  }

  if (!importedStats || Number(importedStats.totalTips || 0) <= 0) return dynamicFinal

  // WERSJA 1805: dla profili z importem typu "baseline" stare statystyki są
  // punktem startowym. Każdy nowy rekord z tabeli tips jest do nich dodawany,
  // zamiast czekać aż liczba nowych typów przekroczy cały historyczny import.
  if (importedStats.additive) {
    const importedTotal = Number(importedStats.totalTips || 0) || 0
    const dynamicTotal = Number(dynamicFinal.totalTips || 0) || 0
    const combinedTotal = importedTotal + dynamicTotal
    const combinedStaked = Number(importedStats.totalStaked || 0) + Number(dynamicFinal.totalStaked || 0)
    const combinedProfit = Number(importedStats.profit || 0) + Number(dynamicFinal.profit || 0)
    const weightedOdds =
      (Number(importedStats.avgOdds || 0) * importedTotal) +
      (Number(dynamicFinal.avgOdds || 0) * dynamicTotal)

    return {
      totalTips: combinedTotal,
      wonTips: Number(importedStats.wonTips || 0) + Number(dynamicFinal.wonTips || 0),
      lostTips: Number(importedStats.lostTips || 0) + Number(dynamicFinal.lostTips || 0),
      voidTips: Number(importedStats.voidTips || 0) + Number(dynamicFinal.voidTips || 0),
      pendingTips: Number(importedStats.pendingTips || 0) + Number(dynamicFinal.pendingTips || 0),
      totalStaked: combinedStaked,
      profit: combinedProfit,
      avgOdds: combinedTotal > 0 ? weightedOdds / combinedTotal : 0,
      highestOdds: Math.max(Number(importedStats.highestOdds || 0), Number(dynamicFinal.highestOdds || 0)),
      yield: combinedStaked > 0 ? (combinedProfit / combinedStaked) * 100 : Number(importedStats.yield || 0),
      additive: true,
      statsImportedAt: importedStats.statsImportedAt || null,
    }
  }

  const importedTotalStaked = Number(importedStats.totalStaked || 0)
  const importedProfit = Number(importedStats.profit || 0)
  const importedLooksStaleAfterReset =
    Number(importedStats.totalTips || 0) > 0 &&
    importedTotalStaked <= 0 &&
    importedProfit === 0 &&
    Number(importedStats.avgOdds || 0) <= 0 &&
    (dynamicFinal.totalStaked > 0 || dynamicFinal.avgOdds > 0 || dynamicFinal.profit !== 0)

  if (importedLooksStaleAfterReset) {
    return {
      ...importedStats,
      ...dynamicFinal,
      totalTips: Math.max(Number(importedStats.totalTips || 0), Number(dynamicFinal.totalTips || 0)),
      wonTips: Math.max(Number(importedStats.wonTips || 0), Number(dynamicFinal.wonTips || 0)),
      lostTips: Math.max(Number(importedStats.lostTips || 0), Number(dynamicFinal.lostTips || 0)),
      voidTips: Math.max(Number(importedStats.voidTips || 0), Number(dynamicFinal.voidTips || 0)),
      pendingTips: Math.max(Number(importedStats.pendingTips || 0), Number(dynamicFinal.pendingTips || 0)),
    }
  }

  // FIX 1758:
  // Jeden kanon statystyk wszędzie: profil, karta typu i Top typerzy.
  // Jeśli dynamiczne statystyki z realnych rekordów tips mają więcej typów
  // niż stare imported_* z profilu/rankingu, używamy dynamicznych danych.
  if (dynamicFinal.totalTips > Number(importedStats.totalTips || 0)) {
    return dynamicFinal
  }

  return importedStats
}


// WERSJA 1797 — jeden kanon statystyk betai-multisport-ai dla profilu,
// dashboardu i rankingu. Przy tej samej liczbie typów pierwszeństwo ma
// zestaw policzony z realnych rekordów, a nie starsze imported_*.
function chooseBetaiBotCanonicalStatsV1797(dynamicStats = null, importedStats = null, visibleStats = null) {
  const dynamicFinal = dynamicStats ? finalizeAuthorStats(dynamicStats, null) : null
  const emptyStats = {
    totalTips: 0,
    wonTips: 0,
    lostTips: 0,
    voidTips: 0,
    pendingTips: 0,
    totalStaked: 0,
    profit: 0,
    avgOdds: 0,
    highestOdds: 0,
    yield: 0,
  }

  const candidates = [
    dynamicFinal ? { ...emptyStats, ...dynamicFinal, _priorityV1797: 3 } : null,
    visibleStats ? { ...emptyStats, ...visibleStats, _priorityV1797: 2 } : null,
    importedStats ? { ...emptyStats, ...importedStats, _priorityV1797: 1 } : null,
  ].filter(Boolean)

  if (!candidates.length) return null

  const chosen = [...candidates].sort((a, b) => {
    const totalDiff = Number(b.totalTips || 0) - Number(a.totalTips || 0)
    if (totalDiff !== 0) return totalDiff

    const completenessA =
      (Number(a.totalStaked || 0) > 0 ? 4 : 0) +
      (Number(a.profit || 0) !== 0 ? 3 : 0) +
      (Number(a.yield || 0) !== 0 ? 2 : 0) +
      (Number(a.wonTips || 0) + Number(a.lostTips || 0) > 0 ? 1 : 0)
    const completenessB =
      (Number(b.totalStaked || 0) > 0 ? 4 : 0) +
      (Number(b.profit || 0) !== 0 ? 3 : 0) +
      (Number(b.yield || 0) !== 0 ? 2 : 0) +
      (Number(b.wonTips || 0) + Number(b.lostTips || 0) > 0 ? 1 : 0)

    if (completenessB !== completenessA) return completenessB - completenessA
    return Number(b._priorityV1797 || 0) - Number(a._priorityV1797 || 0)
  })[0]

  const cleaned = { ...chosen }
  delete cleaned._priorityV1797
  cleaned.voidTips = Math.max(...candidates.map(stats => Number(stats.voidTips || 0)))
  return cleaned
}


function normalizeBetTypeForStats(marketValue = '', pickValue = '', source = {}) {
  const stored = String(
    source?.bet_market_type ||
    source?.market_type ||
    source?.stats_bet_type ||
    source?.type_label ||
    source?.pick_type ||
    source?.selection_type ||
    source?.prediction_type ||
    ''
  ).trim()
  if (stored) return stored

  const market = String(marketValue || source?.market || source?.market_name || source?.marketName || '').trim()
  const pick = String(pickValue || source?.pick || source?.prediction || source?.selection || source?.bet_type || source?.betType || source?.bet || source?.tip || '').trim()
  const combined = `${market} ${pick}`.toLowerCase()
  const cleanPick = pick || 'Inny typ'

  const hasAny = (...words) => words.some(word => combined.includes(word))
  const numberMatch = combined.match(/(\d+(?:[.,]\d+)?)/)
  const line = numberMatch ? numberMatch[1].replace(',', '.') : ''

  if (hasAny('wynik do przerwy', 'first half winner', 'half time result', 'halftime result')) return 'Wynik do przerwy'
  if (hasAny('wygra jedną z połów', 'wygra jedna z polow', 'win either half', 'to win either half')) return 'Drużyna wygra jedną z połów'
  if (hasAny('gole w 1. połowie', 'gole w 1 polowie', 'goals over/under first half', 'over/under first half')) {
    if (hasAny('under', 'poniżej', 'mniej')) return line ? `Under ${line} gola — 1. połowa` : 'Under gole — 1. połowa'
    if (hasAny('over', 'powyżej', 'więcej')) return line ? `Over ${line} gola — 1. połowa` : 'Over gole — 1. połowa'
    return 'Gole — 1. połowa'
  }
  if (hasAny('dnb', 'draw no bet', 'bez remisu')) return 'DNB'
  if (hasAny('podwójna szansa', 'double chance') || /\b1x\b|\bx2\b|\b12\b/.test(combined)) return 'Podwójna szansa'
  if (hasAny('handicap', 'azjatycki')) return 'Handicap'
  if (hasAny('btts', 'obie strzel')) return 'BTTS'
  if (hasAny('rzut', 'rożn', 'corner')) {
    if (hasAny('under', 'poniżej', 'mniej')) return line ? `Under ${line} rożnych` : 'Under rożne'
    if (hasAny('over', 'powyżej', 'więcej')) return line ? `Over ${line} rożnych` : 'Over rożne'
    return 'Rzuty rożne'
  }
  if (hasAny('kartk', 'żółt', 'yellow card', 'cards')) {
    if (hasAny('under', 'poniżej', 'mniej')) return line ? `Under ${line} kartek` : 'Under kartki'
    if (hasAny('over', 'powyżej', 'więcej')) return line ? `Over ${line} kartek` : 'Over kartki'
    return 'Kartki'
  }
  if (hasAny('gol', 'bramk', 'goal', 'goals')) {
    if (hasAny('under', 'poniżej', 'mniej')) return line ? `Under ${line} gola` : 'Under gole'
    if (hasAny('over', 'powyżej', 'więcej')) return line ? `Over ${line} gola` : 'Over gole'
    return 'Gole'
  }
  if (hasAny('wynik końcowy', '1x2', 'match winner', 'full time result') || /(^|\s)(1|x|2)(\s|$)/.test(combined) || hasAny('wygra', 'zwycięzca', 'remis')) return '1X2'

  return cleanPick
}

function compactNumberLabel(value, decimals = 2) {
  const num = Number(value || 0)
  if (Number.isInteger(num)) return String(num)
  return num.toFixed(decimals).replace(/\.?0+$/, '')
}

function getAuthorStatsLabels(sourceStats) {
  const stats = sourceStats || finalizeAuthorStats(null, null)
  const yieldValue = Number(stats.yield || 0)
  const profit = Number(stats.profit || 0)
  return {
    yieldLabel: `${compactNumberLabel(yieldValue, 2)}%`,
    yieldValue,
    totalTipsLabel: String(Number(stats.totalTips || 0) || 0),
    profitLabel: `${profit >= 0 ? '+' : ''}${profit.toFixed(2)}`,
    profitValue: profit,
  }
}

function getTipFallbackAuthorStats(tip) {
  return finalizeAuthorStats(buildAuthorStatsFromTips([tip]).get(getTipAuthorStatsKey(tip)), null)
}

// WERSJA 1794 — jeden kanon statystyk bota na dashboardzie.
// Karty betai-multisport-ai nie mogą liczyć wyniku wyłącznie z aktualnie
// widocznych rekordów marketplace, bo wtedy pokazywały np. -20%, 20 i -3.00.
// Pobieramy pełny dziennik ai_bets dokładnie raz, liczymy realne wyniki i
// współdzielimy cache pomiędzy wszystkimi kartami bota.
const BETAI_BOT_DASHBOARD_STATS_CACHE_KEY_V1794 = 'betai_bot_dashboard_stats_v1794'
const BETAI_BOT_DASHBOARD_STATS_TTL_V1794 = 5 * 60 * 1000
let betaiBotDashboardStatsCacheV1794 = {
  value: null,
  loadedAt: 0,
  promise: null,
}

function isBetaiMultisportRecordV1794(row = {}) {
  if (normalizeRankingBotKeyV1761(row) === 'user:betai-multisport-ai') return true
  const identity = String([
    row?.author_name,
    row?.username,
    row?.user_name,
    row?.display_name,
    row?.public_slug,
    row?.email,
    row?.author_email,
    row?.ai_source,
    row?.source,
    row?.publisher,
  ].filter(Boolean).join(' '))
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '')
  return identity.includes('betaimultisportai') || identity.includes('betaimultisport')
}

function isBetaiMultisportPublicTipHiddenV28(row = {}) {
  // BetAI MultiSport AI ma być widoczny tylko w zakładce Typy AI / AI Typy dnia.
  // Ukrywamy jego stare i nowe kopie z tabeli tips, żeby ten sam typ nie dublował się
  // jako zwykły typer w feedzie, profilu i rankingu.
  return isBetaiMultisportRecordV1794(row)
}

function readStoredBotDashboardStatsV1794() {
  if (typeof window === 'undefined') return null
  try {
    const parsed = JSON.parse(window.localStorage.getItem(BETAI_BOT_DASHBOARD_STATS_CACHE_KEY_V1794) || 'null')
    if (!parsed || !parsed.value || !Number(parsed.value.totalTips || 0)) return null
    // WERSJA 1799: pokazujemy ostatnie poprawne statystyki natychmiast,
    // nawet jeśli cache jest starszy. Odświeżenie odbywa się w tle.
    // Dzięki temu prawa kolumna nie czeka na Supabase/Netlify i nie miga.
    return parsed
  } catch (_) {
    return null
  }
}

function dedupeBotAiRowsV1794(rows = []) {
  const map = new Map()
  ;(rows || []).forEach((raw, index) => {
    const tip = normalizeTipRow({
      ...raw,
      author_name: raw?.author_name || raw?.username || 'betai-multisport-ai',
      username: raw?.username || raw?.author_name || 'betai-multisport-ai',
      public_slug: raw?.public_slug || 'betai-multisport-ai',
    })
    const fixture = String(tip.fixture_id || tip.api_fixture_id || tip.event_id || tip.match_id || tip.game_id || '').trim().toLowerCase()
    const match = String(tip.match || tip.match_name || `${tip.team_home || ''}-${tip.team_away || ''}`).trim().toLowerCase()
    const pick = String(tip.prediction || tip.pick || tip.bet_type || tip.selection || '').trim().toLowerCase()
    const kickoff = String(tip.match_time || tip.event_time || tip.event_date || tip.kickoff_at || tip.commence_time || tip.match_date || '').trim().toLowerCase()
    const key = String(tip.id || raw?.id || '').trim() || `${fixture}|${match}|${pick}|${kickoff}|${index}`
    const previous = map.get(key)
    if (!previous) {
      map.set(key, tip)
      return
    }
    const previousStatus = normalizeTipSettlementStatus(previous.status ?? previous.result ?? previous.result_status ?? previous.settlement_status)
    const nextStatus = normalizeTipSettlementStatus(tip.status ?? tip.result ?? tip.result_status ?? tip.settlement_status)
    map.set(key, previousStatus === 'pending' && nextStatus !== 'pending' ? { ...previous, ...tip } : { ...tip, ...previous })
  })
  return [...map.values()]
}

async function loadBetaiBotDashboardStatsV1794({ force = false } = {}) {
  const now = Date.now()
  if (!force && betaiBotDashboardStatsCacheV1794.value && now - betaiBotDashboardStatsCacheV1794.loadedAt < BETAI_BOT_DASHBOARD_STATS_TTL_V1794) {
    return betaiBotDashboardStatsCacheV1794.value
  }
  if (betaiBotDashboardStatsCacheV1794.promise) return betaiBotDashboardStatsCacheV1794.promise

  const stored = readStoredBotDashboardStatsV1794()
  if (stored?.value && !betaiBotDashboardStatsCacheV1794.value) {
    betaiBotDashboardStatsCacheV1794.value = stored.value
    betaiBotDashboardStatsCacheV1794.loadedAt = Number(stored.loadedAt || 0)
  }

  betaiBotDashboardStatsCacheV1794.promise = (async () => {
    let aiRows = []
    let manualRows = []
    let importedProfileStats = null

    // WERSJA 1799: źródła pobieramy RÓWNOLEGLE, a nie jedno po drugim.
    // Poprzednio wolna funkcja Netlify mogła opóźniać Supabase nawet o 8 sekund.
    const journalPromise = (async () => {
      try {
        const controller = new AbortController()
        const timer = setTimeout(() => controller.abort(), 2500)
        try {
          const response = await fetch('/.netlify/functions/get-ai-bets?journal=1&limit=250', {
            cache: 'no-store',
            signal: controller.signal,
          })
          if (!response.ok) return []
          const payload = await response.json().catch(() => ({}))
          return Array.isArray(payload?.bets) ? payload.bets : []
        } finally {
          clearTimeout(timer)
        }
      } catch (_) {
        return []
      }
    })()

    const supabasePromise = (async () => {
      if (!isSupabaseConfigured || !supabase) return { ai: [], tips: [], profiles: [] }
      try {
        const [aiResult, tipsResult, profilesResult] = await Promise.all([
          supabase.from('ai_bets').select('*').order('created_at', { ascending: false }).limit(250),
          supabase.from('tips').select('*').order('created_at', { ascending: false }).limit(300),
          supabase.from('profiles').select('*').order('created_at', { ascending: false }).limit(100),
        ])
        return {
          ai: !aiResult?.error && Array.isArray(aiResult?.data) ? aiResult.data : [],
          tips: !tipsResult?.error && Array.isArray(tipsResult?.data) ? tipsResult.data : [],
          profiles: !profilesResult?.error && Array.isArray(profilesResult?.data) ? profilesResult.data : [],
        }
      } catch (_) {
        return { ai: [], tips: [], profiles: [] }
      }
    })()

    const [journalRows, supabaseRows] = await Promise.all([journalPromise, supabasePromise])
    aiRows = journalRows.length ? journalRows : supabaseRows.ai
    manualRows = supabaseRows.tips

    if (supabaseRows.profiles.length) {
      const botProfiles = supabaseRows.profiles.filter(isBetaiMultisportRecordV1794)
      const mergedBotProfile = typeof mergeProfilesPreferStats === 'function'
        ? (mergeProfilesPreferStats(botProfiles)[0] || botProfiles[0] || null)
        : (botProfiles[0] || null)
      importedProfileStats = getImportedProfileStats(mergedBotProfile)
    }

    const allBotRows = dedupeBotAiRowsV1794([
      ...aiRows.filter(isBetaiMultisportRecordV1794),
      ...manualRows.filter(isBetaiMultisportRecordV1794),
    ])
    const dynamicStats = buildCombinedTipStatsV1791(allBotRows)
    const visibleStats = allBotRows
      .map(row => row?.author_visible_stats)
      .filter(stats => stats && typeof stats === 'object')
      .sort((a, b) => {
        const totalDiff = Number(b?.totalTips || 0) - Number(a?.totalTips || 0)
        if (totalDiff !== 0) return totalDiff
        const profitDiff = Math.abs(Number(b?.profit || 0)) - Math.abs(Number(a?.profit || 0))
        if (profitDiff !== 0) return profitDiff
        return Math.abs(Number(b?.yield || 0)) - Math.abs(Number(a?.yield || 0))
      })[0] || null

    const value = Number(dynamicStats.totalTips || 0) > 0 || importedProfileStats || visibleStats
      ? chooseBetaiBotCanonicalStatsV1797(dynamicStats, importedProfileStats, visibleStats)
      : (betaiBotDashboardStatsCacheV1794.value || null)

    if (value) {
      betaiBotDashboardStatsCacheV1794.value = value
      betaiBotDashboardStatsCacheV1794.loadedAt = Date.now()
      try {
        window.localStorage.setItem(BETAI_BOT_DASHBOARD_STATS_CACHE_KEY_V1794, JSON.stringify({
          value,
          loadedAt: betaiBotDashboardStatsCacheV1794.loadedAt,
        }))
      } catch (_) {}
    }
    return value
  })().finally(() => {
    betaiBotDashboardStatsCacheV1794.promise = null
  })

  return betaiBotDashboardStatsCacheV1794.promise
}

function useBetaiBotDashboardStatsV1794(tip) {
  const isBot = isBetaiMultisportRecordV1794(tip)
  const stored = isBot ? readStoredBotDashboardStatsV1794() : null
  const immediateFallback = isBot
    ? (betaiBotDashboardStatsCacheV1794.value || stored?.value || tip?.author_visible_stats || getImportedProfileStats(tip) || getTipFallbackAuthorStats(tip))
    : null
  const [stats, setStats] = useState(() => immediateFallback)

  useEffect(() => {
    if (!isBot) {
      setStats(null)
      return undefined
    }
    let active = true
    loadBetaiBotDashboardStatsV1794().then(value => {
      if (active && value) setStats(value)
    }).catch(() => {})
    const refresh = () => {
      loadBetaiBotDashboardStatsV1794().then(value => {
        if (active && value) setStats(value)
      }).catch(() => {})
    }
    window.addEventListener('betai:tips-updated', refresh)
    window.addEventListener('betai:ai-bets-updated', refresh)
    return () => {
      active = false
      window.removeEventListener('betai:tips-updated', refresh)
      window.removeEventListener('betai:ai-bets-updated', refresh)
    }
  }, [isBot])

  return stats
}


