const BETAI_RECENT_SAVED_TIPS_KEY = 'betai_recent_saved_tips_v1263'

// WERSJA 1804: pełny reset statystyk profilu smilhytv musi również usunąć
// techniczne kopie typów i statystyk zapisane wcześniej w przeglądarce. Nowy marker
// uruchamia czyszczenie ponownie także u osób, które miały już wykonany reset v1606.
// Nie ruszamy sesji logowania, języka, Stripe, portfela, monet ani ustawień konta.
function runBetAiStatsResetCachePurgeV1804() {
  try {
    if (typeof window === 'undefined') return
    const marker = 'betai_stats_reset_cache_purge_v1804_smilhytv'
    const patterns = [
      'recent_saved_tips',
      'author_imported_stats',
      'visible_stats',
      'tip_stats_cache',
      'public_tips_cache',
      'profile_stats_cache',
      'tipster_stats_cache',
      'profile_history_cache',
      'profile_chart_cache',
      'local_settlement_patch',
    ]

    const purgeStorage = (storage) => {
      if (!storage || storage.getItem(marker) === '1') return
      const keysToRemove = []
      for (let i = 0; i < storage.length; i += 1) {
        const key = storage.key(i) || ''
        const lower = key.toLowerCase()
        if (key === BETAI_RECENT_SAVED_TIPS_KEY || patterns.some(pattern => lower.includes(pattern))) {
          keysToRemove.push(key)
        }
      }
      keysToRemove.forEach(key => storage.removeItem(key))
      storage.setItem(marker, '1')
    }

    purgeStorage(window.localStorage)
    purgeStorage(window.sessionStorage)
  } catch (_) {}
}
runBetAiStatsResetCachePurgeV1804()

function readRecentSavedTips(userId = '') {
  try {
    const raw = window.localStorage.getItem(BETAI_RECENT_SAVED_TIPS_KEY)
    const rows = raw ? JSON.parse(raw) : []
    if (!Array.isArray(rows)) return []
    const cutoff = Date.now() - (48 * 60 * 60 * 1000)
    const uid = String(userId || '').trim()
    return rows
      .filter(Boolean)
      .map(normalizeTipRow)
      .filter(tip => {
        const created = Date.parse(tip.created_at || '')
        if (Number.isFinite(created) && created < cutoff) return false
        if (!uid) return true
        return String(tip.user_id || tip.author_id || '') === uid || !tip.user_id && !tip.author_id
      })
  } catch (_) {
    return []
  }
}

function rememberRecentSavedTip(tip = {}, userId = '') {
  try {
    const normalized = normalizeTipRow({
      status: 'pending',
      settlement_status: 'pending',
      manual_settlement_status: 'none',
      admin_approval_status: 'none',
      ...tip,
      user_id: tip.user_id || tip.author_id || userId || null,
      author_id: tip.author_id || tip.user_id || userId || null,
      created_at: tip.created_at || new Date().toISOString(),
    })
    const current = readRecentSavedTips('')
    const next = [normalized, ...current.filter(row => String(row.id || '') !== String(normalized.id || ''))]
      .slice(0, 20)
    window.localStorage.setItem(BETAI_RECENT_SAVED_TIPS_KEY, JSON.stringify(next))
  } catch (_) {}
}

