  const getFootballLeaguesForCountry = (country) => {
    const cleanCountry = normalizeFootballCountryName(country)
    const countryLeagueMap = footballMatchCounts?.countryLeagues || {}
    const cachedLeagues = [
      ...(countryLeagueMap[country] || []),
      ...(countryLeagueMap[cleanCountry] || []),
      ...(countryLeagueMap[normalizeCountKey(country)] || []),
      ...(countryLeagueMap[normalizeCountKey(cleanCountry)] || []),
    ].filter(Boolean)
    const staticLeagues = countryMap?.[country]
      ? Object.keys(countryMap[country])
      : (footballLeagueMap[country] || footballLeagueMap[cleanCountry] || [])
    const merged = [...new Set([...cachedLeagues, ...staticLeagues])]
    return merged.length ? merged : ['1 Liga', '2 Liga', 'Puchar kraju', 'Liga kobiet']
  }

  const normalizeCountKey = (value) => String(value || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim()

  const getCountryMatchCount = (country) => {
    const counts = footballMatchCounts?.countries || {}
    return Number(counts[country] ?? counts[normalizeFootballCountryName(country)] ?? counts[normalizeCountKey(country)] ?? 0)
  }

  const getLeagueMatchCount = (country, league) => {
    const leagues = footballMatchCounts?.leagues || {}
    const cleanCountry = normalizeFootballCountryName(country)
    const directKey = `${cleanCountry}|||${league}`
    const normalizedKey = `${normalizeCountKey(cleanCountry)}|||${normalizeCountKey(league)}`
    return Number(leagues[directKey] ?? leagues[normalizedKey] ?? leagues[league] ?? leagues[normalizeCountKey(league)] ?? 0)
  }

  function normalizeFootballCountsData(input = {}) {
    const countries = {}
    const leagues = {}
    const countryLeagues = {}
    Object.entries(input.countries || {}).forEach(([key, value]) => {
      const clean = normalizeFootballCountryName(key)
      ;[clean, normalizeCountKey(clean)].filter(Boolean).forEach(alias => {
        countries[alias] = Math.max(Number(countries[alias] || 0), Number(value || 0))
      })
    })
    Object.entries(input.countryLeagues || {}).forEach(([key, value]) => {
      const clean = normalizeFootballCountryName(key)
      const list = Array.isArray(value) ? value : []
      ;[clean, normalizeCountKey(clean)].filter(Boolean).forEach(alias => {
        countryLeagues[alias] = [...new Set([...(countryLeagues[alias] || []), ...list])].sort((a, b) => a.localeCompare(b, 'pl'))
      })
    })
    Object.entries(input.leagues || {}).forEach(([key, value]) => {
      const rawValue = Number(value || 0)
      const parts = String(key).split('|||')
      if (parts.length >= 2) {
        const cleanCountry = normalizeFootballCountryName(parts[0])
        const league = parts.slice(1).join('|||')
        const directKey = `${cleanCountry}|||${league}`
        const normalizedKey = `${normalizeCountKey(cleanCountry)}|||${normalizeCountKey(league)}`
        leagues[directKey] = Math.max(Number(leagues[directKey] || 0), rawValue)
        leagues[normalizedKey] = Math.max(Number(leagues[normalizedKey] || 0), rawValue)
      } else {
        leagues[key] = Math.max(Number(leagues[key] || 0), rawValue)
        leagues[normalizeCountKey(key)] = Math.max(Number(leagues[normalizeCountKey(key)] || 0), rawValue)
      }
    })
    return {
      countries,
      leagues,
      countryLeagues,
      total: Number(input.total || 0),
      source: input.source || 'normalized'
    }
  }

  function mergeFootballCountsData(previous = {}, incoming = {}) {
    const prev = normalizeFootballCountsData(previous || {})
    const next = normalizeFootballCountsData(incoming || {})
    const countries = { ...(prev.countries || {}) }
    Object.entries(next.countries || {}).forEach(([key, value]) => {
      countries[key] = Math.max(Number(countries[key] || 0), Number(value || 0))
    })
    const leagues = { ...(prev.leagues || {}) }
    Object.entries(next.leagues || {}).forEach(([key, value]) => {
      leagues[key] = Math.max(Number(leagues[key] || 0), Number(value || 0))
    })
    const countryLeagues = { ...(prev.countryLeagues || {}) }
    Object.entries(next.countryLeagues || {}).forEach(([key, value]) => {
      const merged = [...new Set([...(countryLeagues[key] || []), ...(Array.isArray(value) ? value : [])])]
      countryLeagues[key] = merged.sort((a, b) => a.localeCompare(b, 'pl'))
    })
    return {
      countries,
      leagues,
      countryLeagues,
      total: Math.max(Number(prev.total || 0), Number(next.total || 0)),
      source: next.source || prev.source || 'merged-cache'
    }
  }

  function buildFootballCountsFromFixtures(fixtures = [], source = 'loaded-fixtures') {
    const countries = {}
    const leagues = {}
    const countryLeagues = {}
    const seen = new Set()
    ;(Array.isArray(fixtures) ? fixtures : []).forEach(item => {
      if (!item) return
      const country = String(item.country || 'Świat').trim() || 'Świat'
      const cleanCountry = normalizeFootballCountryName(country)
      const league = String(item.league || 'Liga').trim() || 'Liga'
      const eventKey = String(item.apiFixtureId || item.id || `${country}|${league}|${item.home}|${item.away}|${item.commence_time || item.date || ''}`).toLowerCase()
      if (seen.has(eventKey)) return
      seen.add(eventKey)
      ;[country, cleanCountry, normalizeCountKey(country), normalizeCountKey(cleanCountry)].filter(Boolean).forEach(key => {
        countries[key] = (countries[key] || 0) + 1
        if (!countryLeagues[key]) countryLeagues[key] = []
        if (!countryLeagues[key].includes(league)) countryLeagues[key].push(league)
      })
      const directKey = `${cleanCountry}|||${league}`
      const normalizedKey = `${normalizeCountKey(cleanCountry)}|||${normalizeCountKey(league)}`
      leagues[directKey] = (leagues[directKey] || 0) + 1
      leagues[normalizedKey] = (leagues[normalizedKey] || 0) + 1
      leagues[league] = (leagues[league] || 0) + 1
      leagues[normalizeCountKey(league)] = (leagues[normalizeCountKey(league)] || 0) + 1
    })
    Object.keys(countryLeagues).forEach(key => countryLeagues[key].sort((a, b) => a.localeCompare(b, 'pl')))
    return { countries, leagues, countryLeagues, total: seen.size, source }
  }

  async function fetchFootballMatchCountsFromCache(force = false) {
    const todayKey = getTodayLocalKey()
    const cacheKey = `betai_football_country_league_counts_v1088_${todayKey}`
    if (!force) {
      try {
        const cachedRaw = localStorage.getItem(cacheKey)
        if (cachedRaw) {
          const cached = JSON.parse(cachedRaw)
          if (cached && typeof cached === 'object') {
            const normalizedCached = normalizeFootballCountsData(cached)
            setFootballMatchCounts(normalizedCached)
            return normalizedCached
          }
        }
      } catch (error) {
        console.warn('football count cache read skipped', error)
      }
    }

    setFootballMatchCountsLoading(true)
    try {
      const params = new URLSearchParams({ date: todayKey })
      const response = await fetch(`/.netlify/functions/get-fixture-counts-cache?${params.toString()}`)
      const data = await response.json().catch(() => ({}))
      if (!response.ok) throw new Error(data.error || 'Nie udało się pobrać liczników meczów.')
      const nextCounts = normalizeFootballCountsData({
        countries: data.countries || {},
        leagues: data.leagues || {},
        countryLeagues: data.countryLeagues || {},
        total: Number(data.total || 0),
        source: data.source || 'cache'
      })
      setFootballMatchCounts(nextCounts)
      try { localStorage.setItem(cacheKey, JSON.stringify(nextCounts)) } catch (_) {}
      return nextCounts
    } catch (error) {
      console.warn('football match counts skipped', error)
      return footballMatchCounts
    } finally {
      setFootballMatchCountsLoading(false)
    }
  }

  function selectSidebarCountry(nextCountry) {
    setOpenSidebarSport('Piłka nożna')

    if (openFootballCountry === nextCountry) {
      setOpenFootballCountry('')
      return
    }

    setOpenFootballCountry(nextCountry)
    setLiveFixtures([])
    setHasTriedLiveLoad(false)
    setLiveDataSource('manual')
    setFootballViewMode('league-today')
    setLiveFixturesStatus('Wybierz ligę po lewej, a pokażę tylko dzisiejsze mecze tej ligi.')
    updateForm({
      sport: 'Piłka nożna',
      country: nextCountry,
      league: '',
      matchId: '',
      market: '',
      betType: '',
      odds: '',
    })
  }

  function matchStartsAfterBuffer(match) {
    const dateText = String(match?.date || '').trim()
    const timeText = String(match?.time || '').trim()
    let kick = null
    const isoCandidate = match?.commence_time || match?.start_time || match?.match_time
    if (isoCandidate) {
      const parsed = new Date(isoCandidate)
      if (!Number.isNaN(parsed.getTime())) kick = parsed
    }
    if (!kick && /^\d{1,2}\.\d{1,2}\.\d{4}$/.test(dateText)) {
      const [day, month, year] = dateText.split('.')
      kick = new Date(`${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}T${timeText || '00:00'}:00`)
    }
    if (!kick || Number.isNaN(kick.getTime())) return true
    return kick.getTime() > Date.now() + 1 * 60 * 1000
  }

  const matchOptions = liveFixtures.filter(matchStartsAfterBuffer)
  const selectedMatch = matchOptions.find(item => item.id === form.matchId) || matchOptions[0] || null
  const effectiveSelectedMatch = addTipMode === 'manual' && manualSelectedMatch ? manualSelectedMatch : selectedMatch
  const akoCouponOdds = akoSelections.reduce((product, leg) => product * (Number(leg.odds || 0) || 1), 1)
  const akoCouponOddsLabel = akoSelections.length ? akoCouponOdds.toFixed(2) : '0.00'
  const isAkoTicketMode = couponMode === 'ako'

