function AdminCouponApprovalView({ user, onToast }) {
  const lang = useBetaiLanguageState()
  const isEn = lang === 'en'
  const [rows, setRows] = useState([])
  const [tab, setTab] = useState('pending')
  const [loading, setLoading] = useState(false)

  const resultLabel = (value) => {
    const clean = String(value || '').toLowerCase()
    if (clean === 'won') return isEn ? 'Won' : 'Wygrana'
    if (clean === 'lost') return isEn ? 'Lost' : 'Przegrana'
    if (clean === 'void') return isEn ? 'Void' : 'Zwrot'
    return '—'
  }
  const statusOf = (row) => String(row?.admin_approval_status || row?.manual_settlement_status || row?.status || '').toLowerCase()
  const pendingRows = rows.filter(row => ['pending', 'pending_admin'].includes(statusOf(row)) )
  const approvedRows = rows.filter(row => statusOf(row) === 'approved')
  const rejectedRows = rows.filter(row => statusOf(row) === 'rejected')
  const visibleRows = tab === 'approved' ? approvedRows : tab === 'rejected' ? rejectedRows : pendingRows

  async function loadRows() {
    if (!isSupabaseConfigured || !supabase || !isAdminUser(user)) return
    setLoading(true)
    try {
      const { data, error } = await supabase
        .from('tips').select('*')
        .or('manual_settlement_status.eq.pending_admin,admin_approval_status.eq.pending,admin_approval_status.eq.approved,admin_approval_status.eq.rejected')
        .order('manual_settlement_requested_at', { ascending: false, nullsFirst: false })
        .limit(300)
      if (error) throw error
      setRows((data || []).map(normalizeTipRow))
    } catch (error) {
      onToast?.({ type: 'error', title: isEn ? 'Admin coupons' : 'Kupony admin', message: formatAppErrorMessage(error.message || (isEn ? 'Could not load coupons.' : 'Nie udało się pobrać kuponów.')) })
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    loadRows()
    const handler = () => loadRows()
    window.addEventListener('betai:admin-coupon-approval-changed', handler)
    return () => window.removeEventListener('betai:admin-coupon-approval-changed', handler)
  }, [user?.id])

  async function approveRow(row, result) {
    if (!isAdminUser(user)) return
    const clean = String(result || '').toLowerCase()
    try {
      const patch = {
        status: clean,
        result: clean,
        manual_settlement_status: 'approved',
        admin_approval_status: 'approved',
        admin_approved_result: clean,
        admin_approved_at: new Date().toISOString(),
        admin_approved_by: user?.id || null,
        settlement_source: 'manual_admin_approved'
      }
      await updateTipField(row.id, patch)
      onToast?.({ type: 'success', title: isEn ? 'Coupon approved' : 'Kupon zatwierdzony', message: isEn ? `Approved: ${resultLabel(clean)}. Statistics can now be updated.` : `Zatwierdzono: ${resultLabel(clean)}. Statystyki mogą zostać dopisane.` })
      loadRows()
      window.dispatchEvent(new CustomEvent('betai:admin-coupon-approval-changed'))
    } catch (error) {
      onToast?.({ type: 'error', title: isEn ? 'Approval error' : 'Błąd zatwierdzenia', message: formatAppErrorMessage(error.message) })
    }
  }

  async function rejectRow(row) {
    const reason = window.prompt(isEn ? 'Reason for rejection:' : 'Powód odrzucenia:', isEn ? 'The result needs correction' : 'Wynik wymaga poprawy') || ''
    try {
      const patch = {
        status: 'pending',
        manual_settlement_status: 'rejected',
        admin_approval_status: 'rejected',
        admin_rejected_at: new Date().toISOString(),
        admin_rejection_reason: reason,
        settlement_source: 'manual_admin_rejected'
      }
      await updateTipField(row.id, patch)
      onToast?.({ type: 'success', title: isEn ? 'Submission rejected' : 'Zgłoszenie odrzucone', message: isEn ? 'The pick returned to unsettled status. Statistics were not updated.' : 'Typ wrócił do nierozliczonych. Statystyki nie zostały dopisane.' })
      loadRows()
      window.dispatchEvent(new CustomEvent('betai:admin-coupon-approval-changed'))
    } catch (error) {
      onToast?.({ type: 'error', title: isEn ? 'Rejection error' : 'Błąd odrzucenia', message: formatAppErrorMessage(error.message) })
    }
  }

  return (
    <section className="admin-coupon-approval-page-v945">
      <div className="admin-coupon-hero-v945 glass-v2-panel">
        <div>
          <span>{isEn ? 'ADMINISTRATOR ONLY' : 'Tylko administrator'}</span>
          <h1>{isEn ? 'Coupons awaiting approval' : 'Kupony do zatwierdzenia'}</h1>
          <p>{isEn ? 'Every manual settlement submitted by a user waits here for administrator approval. Statistics are updated only after approval.' : 'Każde ręczne rozliczenie użytkownika czeka tutaj na potwierdzenie admina. Statystyki dopisują się dopiero po zatwierdzeniu.'}</p>
        </div>
        <button type="button" onClick={loadRows}>{loading ? (isEn ? 'Loading...' : 'Ładowanie...') : (isEn ? 'Refresh' : 'Odśwież')}</button>
      </div>
      <div className="admin-coupon-tabs-v945">
        <button className={tab === 'pending' ? 'active' : ''} onClick={() => setTab('pending')}>{isEn ? 'Pending' : 'Czekają'} <b>{pendingRows.length}</b></button>
        <button className={tab === 'approved' ? 'active' : ''} onClick={() => setTab('approved')}>{isEn ? 'Approved' : 'Zatwierdzone'} <b>{approvedRows.length}</b></button>
        <button className={tab === 'rejected' ? 'active' : ''} onClick={() => setTab('rejected')}>{isEn ? 'Rejected' : 'Odrzucone'} <b>{rejectedRows.length}</b></button>
      </div>
      <div className="admin-coupon-list-v945">
        {visibleRows.length ? visibleRows.map(row => {
          const home = row.team_home || row.home_team || (isEn ? 'Home team' : 'Gospodarze')
          const away = row.team_away || row.away_team || (isEn ? 'Away team' : 'Goście')
          const author = row.author_name || row.username || row.author_email || (isEn ? 'Tipster' : 'Typer')
          const pending = ['pending', 'pending_admin'].includes(statusOf(row)) 
          return (
            <article className="admin-coupon-card-v945 glass-v2-panel" key={row.id}>
              <div>
                <strong>{home} — {away}</strong>
                <span>{author} · {isEn ? 'pick' : 'typ'}: {row.pick || row.bet_type || row.prediction || '—'} · {isEn ? 'odds' : 'kurs'} {row.odds || '—'} · {isEn ? 'stake' : 'stawka'} {row.stake || row.amount || '—'}</span>
                <em>{isEn ? 'Submitted result' : 'Zgłoszony wynik'}: {resultLabel(row.manual_settlement_result || row.admin_approved_result)}</em>
              </div>
              {pending ? (
                <div className="admin-coupon-actions-v945">
                  <button className="won" onClick={() => approveRow(row, 'won')}>{isEn ? 'Confirm win' : 'Potwierdź wygraną'}</button>
                  <button className="lost" onClick={() => approveRow(row, 'lost')}>{isEn ? 'Confirm loss' : 'Potwierdź przegraną'}</button>
                  <button className="void" onClick={() => approveRow(row, 'void')}>{isEn ? 'Void' : 'Zwrot'}</button>
                  <button className="reject" onClick={() => rejectRow(row)}>{isEn ? 'Reject' : 'Odrzuć'}</button>
                </div>
              ) : <small>{statusOf(row) === 'approved' ? (isEn ? 'Approved' : 'Zatwierdzony') : (isEn ? 'Rejected' : 'Odrzucony')}</small>}
            </article>
          )
        }) : <div className="profile-live-tip-empty">{isEn ? 'No coupons in this tab.' : 'Brak kuponów w tej zakładce.'}</div>}
      </div>
    </section>
  )
}


function AdminFinanceView({ report, onRefresh, onViewChange }) {
  const lang = useBetaiLanguageState()
  const t = (value) => translateBetaiTextValue(value, lang)
  const [adminFinanceFilter, setAdminFinanceFilter] = useState('all')
  const [expandedTransactionTabs, setExpandedTransactionTabs] = useState({})
  const [marketplaceSalesExpanded, setMarketplaceSalesExpanded] = useState(false)
  const transactions = Array.isArray(report?.transactions) ? report.transactions : []
  const marketplaceSales = Array.isArray(report?.marketplace_sales) ? report.marketplace_sales : []
  const getTxType = row => {
    const raw = String(row?.type || row?.source || row?.provider || '').toLowerCase()
    if (row?.tip_id || raw.includes('earning') || raw.includes('sale') || raw.includes('tip_purchase') || raw.includes('marketplace') || raw.includes('single')) return 'marketplace'
    if (raw.includes('premium')) return 'premium'
    if (raw.includes('payout')) return 'payout'
    if (raw.includes('topup') || raw.includes('deposit')) return 'topup'
    return 'other'
  }
  const getTxLabel = row => {
    const type = getTxType(row)
    if (type === 'marketplace') return t('Sprzedaż marketplace')
    if (type === 'premium') return t('Subskrypcja Premium')
    if (type === 'payout') return t('Wypłata typera')
    if (type === 'topup') return t('Wpłata do portfela')
    return row?.label ? t(row.label) : (row?.type || t('Operacja'))
  }
  const getStatusLabel = status => {
    const clean = String(status || '').toLowerCase()
    if (clean === 'completed' || clean === 'paid' || clean === 'succeeded') return t('Zakończona')
    if (clean === 'pending') return t('Oczekuje')
    if (clean === 'approved') return t('Zatwierdzona')
    if (clean === 'rejected') return t('Odrzucona')
    return status || '—'
  }
  const txCounts = {
    all: transactions.length,
    marketplace: transactions.filter(row => getTxType(row) === 'marketplace').length,
    premium: transactions.filter(row => getTxType(row) === 'premium').length,
    payout: transactions.filter(row => getTxType(row) === 'payout').length,
    topup: transactions.filter(row => getTxType(row) === 'topup').length
  }
  const sortByNewest = (a, b) => new Date(b?.created_at || 0).getTime() - new Date(a?.created_at || 0).getTime()
  const sortedTransactions = [...transactions].sort(sortByNewest)
  const sortedMarketplaceSales = [...marketplaceSales].sort(sortByNewest)
  const filteredTransactions = sortedTransactions.filter(row => adminFinanceFilter === 'all' || getTxType(row) === adminFinanceFilter)
  const currentTabExpanded = !!expandedTransactionTabs[adminFinanceFilter]
  const visibleTransactions = currentTabExpanded ? filteredTransactions : filteredTransactions.slice(0, 4)
  const hiddenTransactionsCount = Math.max(0, filteredTransactions.length - 4)
  const visibleMarketplaceSales = marketplaceSalesExpanded ? sortedMarketplaceSales : sortedMarketplaceSales.slice(0, 4)
  const hiddenMarketplaceSalesCount = Math.max(0, sortedMarketplaceSales.length - 4)
  const changeFinanceFilter = filter => {
    setAdminFinanceFilter(filter)
  }
  const totalPlatformRevenue = Number(report?.total_platform_revenue || (Number(report?.platform_commission || 0) + Number(report?.premium_revenue || 0)))
  const platformCommission = Number(report?.platform_commission || 0)
  const premiumRevenue = Number(report?.premium_revenue || 0)
  const grossSales = Number(report?.gross_sales || 0)
  const tipsterEarnings = Number(report?.tipster_earnings || 0)
  const paidOut = Number(report?.total_payouts || 0)
  const pendingPayouts = Number(report?.pending_payouts || 0)
  const availableToPayout = Number(report?.available_to_payout || Math.max(0, tipsterEarnings - paidOut - pendingPayouts))
  const walletTopups = Number(report?.wallet_topups || 0)
  const activePremiumUsers = Number(report?.active_premium_users || 0)
  const payoutCoverage = tipsterEarnings > 0 ? Math.min(100, (paidOut / tipsterEarnings) * 100) : 0

  return (
    <section className="admin-finance-live-page">
      <div className="admin-finance-live-hero glass-v2-panel">
        <div>
          <span>Tylko administrator</span>
          <h1>Finanse platformy</h1>
          <p>Prawdziwy raport Bet+AI: przychód platformy, obrót marketplace, zobowiązania wobec typerów, wpłaty i ostatnie operacje.</p>
          {report?.generated_at ? <small className="admin-finance-generated-v1042">Ostatnie odświeżenie: {new Date(report.generated_at).toLocaleString('pl-PL')}</small> : null}
        </div>
        <button type="button" onClick={onRefresh}>Odśwież raport</button>
      </div>

      <div className="admin-finance-live-kpis">
        <div className="glass-v2-panel primary">
          <span>Przychód platformy</span>
          <b>{formatMoney(totalPlatformRevenue)}</b>
          <small>Premium + prowizja marketplace</small>
        </div>
        <div className="glass-v2-panel">
          <span>Premium</span>
          <b>{formatMoney(premiumRevenue)}</b>
          <small>{activePremiumUsers} aktywnych kont</small>
        </div>
        <div className="glass-v2-panel">
          <span>Prowizja marketplace</span>
          <b>{formatMoney(platformCommission)}</b>
          <small>20% od sprzedaży</small>
        </div>
        <div className="glass-v2-panel">
          <span>Wpłaty do portfeli</span>
          <b>{formatMoney(walletTopups)}</b>
          <small>Przepływ środków, nie zysk</small>
        </div>
      </div>

      <div className="admin-finance-live-grid">
        <div className="glass-v2-panel admin-finance-overview-card">
          <div className="admin-finance-live-card-head">
            <h2>Marketplace</h2>
            <span>{Number(report?.total_sales || 0)} sprzedaży</span>
          </div>
          <div className="admin-finance-overview-list">
            <div><span>Obrót brutto</span><b>{formatMoney(grossSales)}</b></div>
            <div><span>Zarobki typerów</span><b>{formatMoney(tipsterEarnings)}</b></div>
            <div><span>Prowizja platformy</span><b>{formatMoney(platformCommission)}</b></div>
          </div>
          <div className="admin-finance-split">
            <span style={{ width: grossSales > 0 ? `${Math.min(100, (tipsterEarnings / grossSales) * 100)}%` : '0%' }}></span>
          </div>
          <small>Podział sprzedaży: 80% typerzy / 20% platforma.</small>
        </div>

        <div className="glass-v2-panel admin-finance-overview-card">
          <div className="admin-finance-live-card-head">
            <h2>Wypłaty typerów</h2>
            <button type="button" onClick={() => onViewChange?.('adminPayouts')}>Przejdź</button>
          </div>
          <div className="admin-finance-overview-list">
            <div><span>Wypłacono</span><b>{formatMoney(paidOut)}</b></div>
            <div><span>Oczekuje</span><b>{formatMoney(pendingPayouts)}</b></div>
            <div><span>Do wypłaty</span><b>{formatMoney(availableToPayout)}</b></div>
          </div>
          <div className="admin-finance-payout-progress">
            <span style={{ width: `${payoutCoverage}%` }}></span>
          </div>
          <small>{payoutCoverage.toFixed(1)}% wypłaconych zarobków typerów.</small>
        </div>

        <div className="glass-v2-panel admin-finance-health-card">
          <div className="admin-finance-live-card-head"><h2>Szybki stan</h2></div>
          <div className="admin-finance-health-list">
            <div className={pendingPayouts > 0 ? 'warning' : 'ok'}>
              <strong>{pendingPayouts > 0 ? 'Wypłaty wymagają uwagi' : 'Brak zaległych wypłat'}</strong>
              <span>{pendingPayouts > 0 ? `${formatMoney(pendingPayouts)} oczekuje na obsługę.` : 'Nie ma zgłoszonych wypłat do ręcznej obsługi.'}</span>
            </div>
            <div className={totalPlatformRevenue > 0 ? 'ok' : 'neutral'}>
              <strong>{totalPlatformRevenue > 0 ? 'Platforma zarabia' : 'Brak przychodu platformy'}</strong>
              <span>{totalPlatformRevenue > 0 ? `Łącznie ${formatMoney(totalPlatformRevenue)} realnego przychodu.` : 'Po pierwszych sprzedażach pojawią się tu dane.'}</span>
            </div>
          </div>
        </div>
      </div>

      <div className="glass-v2-panel admin-marketplace-sales-card">
        <div className="admin-finance-live-card-head">
          <h2>Sprzedaż typów między użytkownikami</h2>
          <span>{marketplaceSales.length} transakcji</span>
        </div>
        <div className="admin-marketplace-sales-table">
          <div className="admin-marketplace-sales-row header">
            <span>Data</span>
            <span>Typ / mecz</span>
            <span>Kupujący</span>
            <span>Typer</span>
            <span>Brutto</span>
            <span>Platforma 20%</span>
            <span>Typer 80%</span>
          </div>
          {sortedMarketplaceSales.length ? visibleMarketplaceSales.map((sale, idx) => (
            <div className="admin-marketplace-sales-row" key={sale.id || idx}>
              <span>{sale.created_at ? new Date(sale.created_at).toLocaleString('pl-PL') : '—'}</span>
              <span><strong>{sale.tip_title || sale.match_label || 'Zakup typu'}</strong><small>{sale.selection || sale.market || sale.tip_id || '—'}</small></span>
              <span>{sale.buyer_name || sale.buyer_id || '—'}</span>
              <span>{sale.seller_name || sale.seller_id || '—'}</span>
              <span className="amount">{formatMoney(sale.gross_amount || sale.amount)}</span>
              <span className="amount commission">{formatMoney(sale.platform_commission)}</span>
              <span className="amount seller">{formatMoney(sale.tipster_earning)}</span>
            </div>
          )) : (
            <div className="admin-marketplace-sales-empty">
              <strong>Brak sprzedaży typów między użytkownikami</strong>
              <span>Gdy ktoś kupi płatny typ innego typera, zobaczysz tutaj kupującego, sprzedawcę, prowizję i zarobek typera.</span>
            </div>
          )}
          {sortedMarketplaceSales.length > 4 ? (
            <button
              type="button"
              className="admin-finance-show-more-btn"
              onClick={() => setMarketplaceSalesExpanded(prev => !prev)}
            >
              {marketplaceSalesExpanded ? 'Zwiń listę' : `Pokaż więcej (${hiddenMarketplaceSalesCount})`}
            </button>
          ) : null}
        </div>
      </div>

      <div className="glass-v2-panel admin-finance-transactions-card">
        <div className="admin-finance-live-card-head">
          <h2>{t('Ostatnie operacje finansowe')}</h2>
          <span>{t(`${filteredTransactions.length} wyników`)}</span>
        </div>

        <div className="admin-finance-live-filters">
          <button type="button" className={adminFinanceFilter === 'all' ? 'active' : ''} onClick={() => changeFinanceFilter('all')}>{t('Wszystkie')} <b>{txCounts.all}</b></button>
          <button type="button" className={adminFinanceFilter === 'marketplace' ? 'active' : ''} onClick={() => changeFinanceFilter('marketplace')}>Marketplace <b>{txCounts.marketplace}</b></button>
          <button type="button" className={adminFinanceFilter === 'premium' ? 'active' : ''} onClick={() => changeFinanceFilter('premium')}>Premium <b>{txCounts.premium}</b></button>
          <button type="button" className={adminFinanceFilter === 'payout' ? 'active' : ''} onClick={() => changeFinanceFilter('payout')}>{t('Wypłaty')} <b>{txCounts.payout}</b></button>
          <button type="button" className={adminFinanceFilter === 'topup' ? 'active' : ''} onClick={() => changeFinanceFilter('topup')}>{t('Wpłaty')} <b>{txCounts.topup}</b></button>
        </div>

        <div className="admin-finance-live-table">
          <div className="admin-finance-live-row header">
            <span>{t('Data')}</span>
            <span>{t('Operacja')}</span>
            <span>{t('Użytkownik')}</span>
            <span>{t('Kwota')}</span>
            <span>{t('Status')}</span>
          </div>
          {filteredTransactions.length ? visibleTransactions.map((row, idx) => (
            <div className="admin-finance-live-row" key={row.id || idx}>
              <span>{new Date(row.created_at).toLocaleString(lang === 'en' ? 'en-GB' : 'pl-PL')}</span>
              <span><strong>{getTxLabel(row)}</strong><small>{row.type || row.source || '—'}</small></span>
              <span className="admin-finance-user-cell-v1044">
                <strong>{row.display_user || row.user_username || row.username || row.user_email || row.user_id || '—'}</strong>
                {row.raw_user_id || row.user_id ? <small>{row.raw_user_id || row.user_id}</small> : null}
              </span>
              <span className="amount">{formatMoney(row.amount)}</span>
              <span className={`status status-${String(row.status || '').toLowerCase()}`}>{getStatusLabel(row.status)}</span>
            </div>
          )) : (
            <div className="admin-finance-empty">
              <strong>{t('Brak operacji finansowych')}</strong>
              <span>{t('Po pierwszych prawdziwych płatnościach i wypłatach zobaczysz je tutaj.')}</span>
            </div>
          )}
          {filteredTransactions.length > 4 ? (
            <button
              type="button"
              className="admin-finance-show-more-btn"
              onClick={() => setExpandedTransactionTabs(prev => ({ ...prev, [adminFinanceFilter]: !prev[adminFinanceFilter] }))}
            >
              {currentTabExpanded ? t('Zwiń listę') : `${t('Pokaż więcej')} (${hiddenTransactionsCount})`}
            </button>
          ) : null}
        </div>
      </div>
    </section>
  )
}

function AdminPayoutsView({ user, requests = [], onUpdateStatus, onRunCron }) {
  const profile = getUserProfileView(user)
  const [statusFilter, setStatusFilter] = useState('all')
  const [query, setQuery] = useState('')
  const [amountFilter, setAmountFilter] = useState('all')
  const [selectedIds, setSelectedIds] = useState([])

  const normalizedRequests = requests.map(request => ({
    ...request,
    normalizedStatus: String(request.status || 'pending').toLowerCase(),
    normalizedStripeStatus: String(request.stripe_status || '').toLowerCase(),
    amountNumber: Number(request.amount || 0),
    searchText: String([
      request.id,
      request.display_user,
      request.username,
      request.display_name,
      request.user_id,
      request.user_email,
      request.email,
      request.status,
      request.stripe_status,
      request.stripe_transfer_id
    ].filter(Boolean).join(' ')).toLowerCase()
  }))

  const pendingRequests = normalizedRequests.filter(request => request.normalizedStatus === 'pending')
  const processingRequests = normalizedRequests.filter(request => request.normalizedStatus === 'processing')
  const paidRequests = normalizedRequests.filter(request => ['paid', 'approved'].includes(request.normalizedStatus))
  const rejectedRequests = normalizedRequests.filter(request => request.normalizedStatus === 'rejected')
  const failedRequests = normalizedRequests.filter(request => request.normalizedStatus === 'failed' || request.normalizedStripeStatus === 'failed')
  const readyRequests = pendingRequests.filter(request => request.amountNumber >= 50)
  const smallPendingRequests = pendingRequests.filter(request => request.amountNumber < 50)
  const totalPending = pendingRequests.reduce((sum, request) => sum + request.amountNumber, 0)
  const totalReady = readyRequests.reduce((sum, request) => sum + request.amountNumber, 0)
  const totalPaid = paidRequests.reduce((sum, request) => sum + request.amountNumber, 0)
  const attentionCount = processingRequests.length + failedRequests.length
  const automationReady = readyRequests.length > 0

  const filteredRequests = normalizedRequests.filter(request => {
    const matchesStatus = statusFilter === 'all' || request.normalizedStatus === statusFilter
    const matchesQuery = !query.trim() || request.searchText.includes(query.trim().toLowerCase())
    const matchesAmount = amountFilter === 'all'
      || (amountFilter === 'ready' && request.normalizedStatus === 'pending' && request.amountNumber >= 50)
      || (amountFilter === 'small' && request.normalizedStatus === 'pending' && request.amountNumber < 50)
    return matchesStatus && matchesQuery && matchesAmount
  })

  const selectedRequests = normalizedRequests.filter(request => selectedIds.includes(request.id))
  const selectedPending = selectedRequests.filter(request => request.normalizedStatus === 'pending')
  const selectedReady = selectedPending.filter(request => request.amountNumber >= 50)

  const toggleSelected = id => {
    setSelectedIds(current => current.includes(id) ? current.filter(item => item !== id) : [...current, id])
  }

  const toggleAllVisible = () => {
    const visiblePendingIds = filteredRequests.filter(request => request.normalizedStatus === 'pending').map(request => request.id)
    const allSelected = visiblePendingIds.length > 0 && visiblePendingIds.every(id => selectedIds.includes(id))
    setSelectedIds(current => allSelected ? current.filter(id => !visiblePendingIds.includes(id)) : Array.from(new Set([...current, ...visiblePendingIds])))
  }

  const bulkUpdate = status => {
    const rows = status === 'paid' ? selectedReady : selectedPending
    rows.forEach(request => onUpdateStatus(request.id, status))
    setSelectedIds([])
  }

  const exportCsv = () => {
    const headers = ['id', 'user_id', 'created_at', 'amount', 'status', 'stripe_status', 'stripe_transfer_id']
    const rows = filteredRequests.map(request => headers.map(key => '"' + String(request[key] ?? '').replaceAll('"', '""') + '"').join(','))
    const blob = new Blob([[headers.join(','), ...rows].join('\n')], { type: 'text/csv;charset=utf-8;' })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.download = 'admin-wyplaty-' + new Date().toISOString().slice(0, 10) + '.csv'
    link.click()
    URL.revokeObjectURL(url)
  }

  const getStripeLabel = request => {
    if (request.stripe_transfer_id) return request.stripe_transfer_id
    if (request.normalizedStatus === 'rejected') return 'nie dotyczy'
    if (request.normalizedStatus === 'processing') return 'transfer w toku'
    if (request.normalizedStatus === 'failed' || request.normalizedStripeStatus === 'failed') return 'błąd Stripe'
    if (request.normalizedStatus === 'pending' && request.amountNumber < 50) return 'poniżej minimum'
    return 'czeka na transfer'
  }

  const getStatusLabel = status => {
    if (status === 'pending') return t('Oczekuje')
    if (status === 'processing') return 'Przetwarzana'
    if (status === 'paid' || status === 'approved') return 'Wypłacona'
    if (status === 'rejected') return t('Odrzucona')
    if (status === 'failed') return 'Błąd'
    return status || '—'
  }

  if (!profile.isAdmin) {
    return (
      <section className="admin-payout-live-page">
        <div className="admin-denied">
          <strong>Brak dostępu</strong>
          <span>Ten panel jest dostępny tylko dla administratora.</span>
        </div>
      </section>
    )
  }

  return (
    <section className="admin-payout-live-page">
      <div className="admin-payout-live-hero glass-v2-panel">
        <div>
          <span>Tylko administrator</span>
          <h1>Admin wypłaty</h1>
          <p>Centrum realizacji wypłat typerów: kolejka oczekujących, transfery Stripe, akcje ręczne, cron i pełna historia zgłoszeń.</p>
        </div>
        <button type="button" onClick={onRunCron} disabled={!automationReady}>
          {automationReady ? 'Uruchom cron' : 'Brak gotowych wypłat'}
        </button>
      </div>

      <div className="admin-payout-live-kpis">
        <div className="glass-v2-panel primary">
          <span>Gotowe do wypłaty</span>
          <b>{readyRequests.length}</b>
          <small>{formatMoney(totalReady)} od minimum 50 zł</small>
        </div>
        <div className="glass-v2-panel">
          <span>Oczekujące łącznie</span>
          <b>{pendingRequests.length}</b>
          <small>{formatMoney(totalPending)}</small>
        </div>
        <div className="glass-v2-panel">
          <span>Wypłacone</span>
          <b>{paidRequests.length}</b>
          <small>{formatMoney(totalPaid)}</small>
        </div>
        <div className={`glass-v2-panel ${attentionCount > 0 ? 'warning' : ''}`}>
          <span>Wymaga uwagi</span>
          <b>{attentionCount}</b>
          <small>Processing / failed</small>
        </div>
      </div>

      <div className="admin-payout-live-grid">
        <div className="glass-v2-panel admin-payout-queue-card">
          <div className="admin-payout-live-card-head">
            <h2>Kolejka wypłat</h2>
            <span>{readyRequests.length} gotowych</span>
          </div>
          <div className="admin-payout-queue-list">
            <div>
              <strong>Gotowe do przelewu Stripe</strong>
              <span>{readyRequests.length} zgłoszeń na {formatMoney(totalReady)}</span>
            </div>
            <div>
              <strong>Poniżej minimum</strong>
              <span>{smallPendingRequests.length} zgłoszeń poniżej 50 zł</span>
            </div>
            <div className={attentionCount > 0 ? 'warning' : 'ok'}>
              <strong>{attentionCount > 0 ? 'Sprawdź ręcznie' : 'Brak błędów'}</strong>
              <span>{attentionCount > 0 ? `${attentionCount} pozycji processing / failed.` : 'Nie ma pozycji wymagających interwencji.'}</span>
            </div>
          </div>
        </div>

        <div className="glass-v2-panel admin-payout-cron-card">
          <div className="admin-payout-live-card-head">
            <h2>Automatyka wypłat</h2>
            <span className={automationReady ? 'ready' : 'idle'}>{automationReady ? 'Gotowe' : 'Pusto'}</span>
          </div>
          <p>Cron uruchamia tylko pending wypłaty od 50 zł i zabezpiecza transfery przed duplikacją przez status processing.</p>
          <code>/.netlify/functions/process-payouts</code>
          <button type="button" onClick={onRunCron} disabled={!automationReady}>
            {automationReady ? 'Przetwórz gotowe wypłaty' : 'Brak pending ≥ 50 zł'}
          </button>
        </div>

        <div className="glass-v2-panel admin-payout-actions-card">
          <div className="admin-payout-live-card-head"><h2>Akcje zaznaczonych</h2></div>
          <strong>{selectedPending.length} zaznaczonych oczekujących</strong>
          <span>{selectedReady.length} z nich gotowych do wypłaty</span>
          <div>
            <button type="button" disabled={!selectedReady.length} onClick={() => bulkUpdate('paid')}>Zatwierdź wypłaty</button>
            <button type="button" className="danger" disabled={!selectedPending.length} onClick={() => bulkUpdate('rejected')}>Odrzuć</button>
          </div>
        </div>
      </div>

      <div className="glass-v2-panel admin-payout-transactions-card">
        <div className="admin-payout-live-card-head">
          <h2>Zgłoszenia wypłat</h2>
          <button type="button" onClick={exportCsv}>Eksport CSV</button>
        </div>

        <div className="admin-payout-live-toolbar">
          <label>
            <span>⌕</span>
            <input value={query} onChange={event => setQuery(event.target.value)} placeholder="Szukaj po ID, e-mailu, statusie, Stripe ID..." />
          </label>
          <select value={statusFilter} onChange={event => setStatusFilter(event.target.value)}>
            <option value="all">Status: wszystkie</option>
            <option value="pending">Oczekuje</option>
            <option value="processing">Przetwarzana</option>
            <option value="paid">Wypłacona</option>
            <option value="rejected">Odrzucona</option>
            <option value="failed">Błąd</option>
          </select>
          <select value={amountFilter} onChange={event => setAmountFilter(event.target.value)}>
            <option value="all">Kwota: wszystkie</option>
            <option value="ready">Gotowe ≥ 50 zł</option>
            <option value="small">Poniżej 50 zł</option>
          </select>
        </div>

        <div className="admin-payout-live-table">
          <div className="admin-payout-live-row header">
            <span><input type="checkbox" onChange={toggleAllVisible} checked={filteredRequests.some(row => row.normalizedStatus === 'pending') && filteredRequests.filter(row => row.normalizedStatus === 'pending').every(row => selectedIds.includes(row.id))} /></span>
            <span>Użytkownik</span>
            <span>Data</span>
            <span>Kwota</span>
            <span>Status</span>
            <span>Stripe</span>
            <span>Akcje</span>
          </div>
          {filteredRequests.length ? filteredRequests.map(request => (
            <div className="admin-payout-live-row" key={request.id}>
              <span><input type="checkbox" disabled={request.normalizedStatus !== 'pending'} checked={selectedIds.includes(request.id)} onChange={() => toggleSelected(request.id)} /></span>
              <span className="admin-payout-user-cell-v1047">
                <strong>{request.display_user || request.user_username || request.username || request.user_email || request.email || (request.user_id ? request.user_id.slice(0, 8) + '…' : '—')}</strong>
                <small>{request.raw_user_id || request.user_id || '—'}</small>
              </span>
              <span>{request.created_at ? new Date(request.created_at).toLocaleString('pl-PL') : '—'}</span>
              <span className="amount">{formatMoney(request.amountNumber)}</span>
              <span className={`status status-${request.normalizedStatus}`}>{getStatusLabel(request.normalizedStatus)}</span>
              <span>
                <strong>{request.stripe_status || '—'}</strong>
                <small>{getStripeLabel(request)}</small>
              </span>
              <span className="actions">
                {request.normalizedStatus === 'pending' ? (
                  <>
                    <button type="button" disabled={request.amountNumber < 50} onClick={() => onUpdateStatus(request.id, 'paid')}>Zatwierdź</button>
                    <button type="button" className="danger" onClick={() => onUpdateStatus(request.id, 'rejected')}>Odrzuć</button>
                  </>
                ) : (
                  <em>Zamknięte</em>
                )}
              </span>
            </div>
          )) : (
            <div className="admin-payout-empty">
              <strong>Brak zgłoszeń dla wybranych filtrów</strong>
              <span>Zmień filtr albo poczekaj na nowe prawdziwe wypłaty użytkowników.</span>
            </div>
          )}
        </div>
      </div>
    </section>
  )
}

function TopTipstersView({ tips = [], ranking = [], user = null, onOpenTipster = null, onSubscribeToTipster = null, onToggleFollow = null, followingTipsters = new Set(), followStats = {} }) {
  const lang = useBetaiLanguageState()
  const t = (value) => translateBetaiTextValue(value, lang)
  const locale = lang === 'en' ? 'en-GB' : 'pl-PL'
  const [profiles, setProfiles] = useState([])
  const [topAvatarOverrides, setTopAvatarOverrides] = useState({})
  const [publicTopAvatarRows, setPublicTopAvatarRows] = useState([])
  const [loadingProfiles, setLoadingProfiles] = useState(true)
  const [selectedTopSport, setSelectedTopSport] = useState('Piłka nożna')
  const [topAccountFilter, setTopAccountFilter] = useState('all')
  const [sortOpen, setSortOpen] = useState(false)
  const [topBotCanonicalStatsV1802, setTopBotCanonicalStatsV1802] = useState(() => {
    const stored = readStoredBotDashboardStatsV1794()
    return betaiBotDashboardStatsCacheV1794.value || stored?.value || null
  })

  useEffect(() => {
    let active = true
    const refreshTopBotStatsV1802 = () => {
      loadBetaiBotDashboardStatsV1794().then(value => {
        if (active && value) setTopBotCanonicalStatsV1802(value)
      }).catch(() => {})
    }
    refreshTopBotStatsV1802()
    window.addEventListener('betai:tips-updated', refreshTopBotStatsV1802)
    window.addEventListener('betai:ai-bets-updated', refreshTopBotStatsV1802)
    return () => {
      active = false
      window.removeEventListener('betai:tips-updated', refreshTopBotStatsV1802)
      window.removeEventListener('betai:ai-bets-updated', refreshTopBotStatsV1802)
    }
  }, [])

  const isBlockedTopTipsterProfile = (profile = {}) => {
    const values = [
      profile.username,
      profile.public_slug,
      profile.display_name,
      profile.full_name,
      profile.profile_name,
      profile.email,
    ].map(v => normalizeEmail(v)).filter(Boolean)
    return isHiddenDemoProfileV1712(profile) || values.some(value =>
      value === 'bet-ai-model' ||
      value === 'u-ytkownik' ||
      value === 'użytkownik' ||
      value === 'uzytkownik' ||
      value.includes('bet-ai-model')
    )
  }

  const addAvatarHint = (map, key, avatar) => {
    const cleanKey = normalizeEmail(key)
    const cleanAvatar = String(avatar || '').trim()
    if (!cleanKey || !cleanAvatar || isGenericProfileName(cleanKey)) return
    // Pierwsze dopasowanie ma pierwszeństwo: najpierw dane już poprawione w innych zakładkach,
    // potem dopiero fallback z Supabase. Dzięki temu Top typerzy nie podmienią realnego avatara na stary/fake zapis z tips.
    if (!map.has(cleanKey)) map.set(cleanKey, cleanAvatar)
    if (cleanKey.includes('@')) {
      const localKey = normalizeEmail(cleanKey.split('@')[0])
      if (localKey && !isGenericProfileName(localKey) && !map.has(localKey)) map.set(localKey, cleanAvatar)
    }
  }

  const addAvatarHintsFromRow = (map, row = {}) => {
    const avatar = getProfileAvatarUrl(row)
    if (!avatar) return
    ;[
      row.id,
      row.user_id,
      row.author_id,
      row.tipster_id,
      row.email,
      row.user_email,
      row.author_email,
      row.username,
      row.user_name,
      row.author_name,
      row.public_slug,
      row.slug,
      row.display_name,
      row.profile_name,
      row.name,
      resolveRealProfileUsername(row),
    ].forEach(key => addAvatarHint(map, key, avatar))
  }

  const buildTopTipsterAvatarHintsFromLoadedData = () => {
    const map = new Map()
    ;(tips || []).forEach(row => addAvatarHintsFromRow(map, row))
    ;(ranking || []).forEach(row => addAvatarHintsFromRow(map, row))
    cacheBetaiCurrentUserAvatar(user)
    addAvatarHintsFromRow(map, user || {})
    ;(readBetaiPublicAvatarCache() || []).forEach(row => addAvatarHintsFromRow(map, row))
    return map
  }

  const fetchPublicStorageAvatarForProfile = async (profile = {}) => {
    if (!isSupabaseConfigured || !supabase?.storage || !profile?.id) return ''
    try {
      const folder = String(profile.id)
      const { data, error } = await supabase.storage.from('avatars').list(folder, { limit: 20, sortBy: { column: 'created_at', order: 'desc' } })
      if (error || !Array.isArray(data) || !data.length) return ''
      const file = data.find(item => /\.(png|jpe?g|webp|gif)$/i.test(item?.name || '')) || data[0]
      if (!file?.name) return ''
      const path = `${folder}/${file.name}`
      const { data: publicData } = supabase.storage.from('avatars').getPublicUrl(path)
      return publicData?.publicUrl || ''
    } catch (_) {
      return ''
    }
  }

  const fetchTopTipsterStorageAvatars = async (rows = []) => {
    const map = new Map()
    if (!isSupabaseConfigured || !supabase?.storage) return map
    const candidates = (rows || [])
      .filter(row => row?.id && !getProfileAvatarUrl(row))
      .slice(0, 30)
    for (const profile of candidates) {
      const avatar = await fetchPublicStorageAvatarForProfile(profile)
      if (!avatar) continue
      addAvatarHint(map, profile.id, avatar)
      addAvatarHint(map, profile.email, avatar)
      addAvatarHint(map, profile.username, avatar)
      addAvatarHint(map, profile.public_slug, avatar)
    }
    return map
  }

  const buildTopTipsterRowsFromExistingRanking = () => {
    // Najpewniejsze źródło avatarów to te same dane, z których korzysta zakładka Ranking / inne widoki.
    // W poprzednich wersjach Top typerzy budowali listę głównie z profiles i dlatego, jeśli RLS/RPC nie oddał avatar_url,
    // karta kończyła z inicjałami typu BU/SM. Teraz dokładamy realne wiersze z rankingu/tipów jako równorzędne profile.
    return buildLiveLeaderboardRows(ranking || [], tips || []).map(row => {
      const name = formatRankingName(row) || resolveRealProfileUsername(row)
      return {
        ...row,
        id: row.tipster_id || row.id || row.user_id || row.author_id || row.email || name,
        user_id: row.user_id || row.tipster_id || row.author_id || row.id || null,
        author_id: row.author_id || row.tipster_id || row.user_id || row.id || null,
        username: name,
        public_slug: row.public_slug || row.slug || normalizePublicSlug(name),
        email: row.email || row.author_email || row.user_email || '',
        avatar_url: getProfileAvatarUrl(row),
        profile_avatar_url: getProfileAvatarUrl(row),
        author_avatar_url: getProfileAvatarUrl(row),
        bio: row.bio || row.description || row.about || 'Zweryfikowany typer Bet+AI',
        preferred_sport: row.preferred_sport || row.sport || row.discipline || 'Piłka nożna',
        plan: row.plan || row.subscription_status || row.account_type || '',
        subscription_status: row.subscription_status || row.plan || row.account_type || '',
        followers_count: row.followers_count ?? row.followers ?? 0,
        imported_yield: normalizeRankingYield(row),
        imported_total_tips: normalizeRankingTipsCount(row),
        imported_won_tips: normalizeRankingWins(row),
        imported_lost_tips: normalizeRankingLosses(row),
        imported_profit: normalizeRankingProfit(row),
      }
    }).filter(row => {
      const name = resolveRealProfileUsername(row)
      return name && !isGenericProfileName(name) && !isBlockedTopTipsterProfile(row)
    })
  }

  const fetchTopTipsterAvatarHints = async (profileRows = []) => {
    const map = buildTopTipsterAvatarHintsFromLoadedData()
    const profileAvatarRows = []
    const tipAvatarRows = []
    ;(profileRows || []).forEach(row => {
      addAvatarHintsFromRow(map, row)
      profileAvatarRows.push(row)
    })
    ;(tips || []).forEach(row => tipAvatarRows.push(row))
    ;(ranking || []).forEach(row => profileAvatarRows.push(row))
    if (!isSupabaseConfigured || !supabase) return map

    // Najważniejsze: pobierz avatary bezpośrednio z publicznych profili, bo inne zakładki używają właśnie profilu/cache,
    // a stare rekordy w tips potrafią mieć puste albo nieaktualne avatary.
    // v1125: najpewniejszy kanał dla Top typerów — publiczna funkcja z avatarami profili.
    // Wystarczy raz odpalić SQL z paczki, wtedy avatary są pobierane bez zgadywania po tips/rankingu.
    // v1126: obsługujemy też starszą nazwę funkcji, którą mogłeś wkleić ręcznie w Supabase.
    // Najważniejsza funkcja to betai_public_profile_avatars_for_ui — ona czyta profiles + auth.users metadata.
    const publicAvatarRowsFromRpc = []
    for (const rpcName of ['betai_public_profile_avatars_for_ui', 'get_public_tipster_avatars']) {
      try {
        const { data, error } = await supabase.rpc(rpcName)
        if (!error && Array.isArray(data)) {
          data.forEach(row => {
            profileAvatarRows.push(row)
            publicAvatarRowsFromRpc.push(row)
            addAvatarHintsFromRow(map, row)
          })
        }
      } catch (_) {}
    }

    if (publicAvatarRowsFromRpc.length) {
      setPublicTopAvatarRows(publicAvatarRowsFromRpc)
    }

    const profileSelects = [
      'id,email,username,public_slug,avatar_url,profile_avatar_url,author_avatar_url,photo_url,picture,image_url,updated_at,created_at',
      'id,email,username,public_slug,avatar_url,updated_at,created_at',
      'id,email,username,avatar_url,updated_at,created_at',
    ]
    for (const columns of profileSelects) {
      try {
        const { data, error } = await supabase.from('profiles').select('*').order('updated_at', { ascending: false }).limit(200)
        if (error || !Array.isArray(data)) continue
        data.forEach(row => {
          profileAvatarRows.push(row)
          addAvatarHintsFromRow(map, row)
        })
      } catch (_) {}
    }

    const selects = ['*']
    for (const columns of selects) {
      try {
        const { data, error } = await supabase.from('tips').select('*').order('created_at', { ascending: false }).limit(200)
        if (error || !Array.isArray(data)) continue
        data.forEach(row => {
          tipAvatarRows.push(row)
          addAvatarHintsFromRow(map, row)
        })
      } catch (_) {}
    }

    // v1124: dopnij Top typerów do tego samego avatara, który widzisz po kliknięciu w profil użytkownika.
    // Dla każdego nicku szukamy realnego avatara po ID/email/nick/public_slug w profiles oraz w jego typach.
    ;(profileRows || []).forEach(profile => {
      const avatar = findProfilePageAvatarForTopTipster(profile, profileAvatarRows, tipAvatarRows)
      if (!avatar) return
      getTopAvatarLookupKeys(profile).forEach(key => addAvatarHint(map, key, avatar))
    })

    const storageHints = await fetchTopTipsterStorageAvatars((profileRows || []).map(row => attachRealAvatarToProfile(row, map)))
    storageHints.forEach((avatar, key) => { if (!map.has(key)) map.set(key, avatar) })

    return map
  }

  const getTopAvatarLookupKeys = (row = {}) => {
    const values = [
      row.id,
      row.user_id,
      row.author_id,
      row.tipster_id,
      row.profile_id,
      row.email,
      row.user_email,
      row.author_email,
      row.username,
      row.user_name,
      row.author_name,
      row.public_slug,
      row.slug,
      row.display_name,
      row.profile_name,
      row.name,
      resolveRealProfileUsername(row),
    ]
    const keys = []
    values.forEach(value => {
      const clean = normalizeEmail(value)
      if (!clean || isGenericProfileName(clean)) return
      keys.push(clean)
      if (clean.includes('@')) keys.push(clean.split('@')[0])
    })
    return [...new Set(keys.filter(Boolean))]
  }

  const rowMatchesTopAvatarKeys = (row = {}, wantedKeys = new Set()) => {
    if (!row || !wantedKeys?.size) return false
    const rowKeys = getTopAvatarLookupKeys(row)
    return rowKeys.some(key => wantedKeys.has(key) || wantedKeys.has(String(key || '').split('@')[0]))
  }

  const findProfilePageAvatarForTopTipster = (profile = {}, profileRows = [], tipRows = []) => {
    const wantedKeys = new Set(getTopAvatarLookupKeys(profile))
    if (!wantedKeys.size) return ''

    // Dokładnie ta sama logika co po wejściu w profil: najpierw profiles.avatar_url, potem avatar z typów autora.
    const profileMatch = (profileRows || []).find(row => rowMatchesTopAvatarKeys(row, wantedKeys) && getProfileAvatarUrl(row))
    if (profileMatch) return getProfileAvatarUrl(profileMatch)

    const tipMatch = (tipRows || []).find(row => rowMatchesTopAvatarKeys(row, wantedKeys) && getProfileAvatarUrl(row))
    if (tipMatch) return getProfileAvatarUrl(tipMatch)

    return ''
  }

  const attachRealAvatarToProfile = (profile = {}, avatarHints = new Map()) => {
    const keys = getTopAvatarLookupKeys(profile)
    const hintedAvatar = keys.map(key => avatarHints.get(normalizeEmail(key))).find(Boolean)
    const realAvatar = hintedAvatar || getProfileAvatarUrl(profile)
    return realAvatar ? { ...profile, avatar_url: realAvatar, profile_avatar_url: realAvatar, author_avatar_url: realAvatar } : profile
  }

  const buildTopAvatarOverrideObject = (avatarHints = new Map()) => {
    const out = {}
    if (!(avatarHints instanceof Map)) return out
    avatarHints.forEach((avatar, key) => {
      const cleanKey = normalizeEmail(key)
      const cleanAvatar = String(avatar || '').trim()
      if (cleanKey && cleanAvatar) out[cleanKey] = cleanAvatar
    })
    return out
  }

  const findTopAvatarInPublicRows = (profile = {}) => {
    const wantedKeys = new Set(getTopAvatarLookupKeys(profile))
    if (!wantedKeys.size || !Array.isArray(publicTopAvatarRows) || !publicTopAvatarRows.length) return ''
    const wantedName = normalizeEmail(resolveRealProfileUsername(profile))
    const match = publicTopAvatarRows.find(row => {
      const rowKeys = getTopAvatarLookupKeys(row)
      if (rowKeys.some(key => wantedKeys.has(key))) return true
      const rowName = normalizeEmail(resolveRealProfileUsername(row))
      return rowName && wantedName && rowName === wantedName
    })
    return match ? getProfileAvatarUrl(match) : ''
  }

  const findTopAvatarOverrideForProfile = (profile = {}) => {
    const keys = getTopAvatarLookupKeys(profile)
    for (const key of keys) {
      const clean = normalizeEmail(key)
      if (clean && topAvatarOverrides?.[clean]) return topAvatarOverrides[clean]
      if (clean?.includes('@')) {
        const local = normalizeEmail(clean.split('@')[0])
        if (local && topAvatarOverrides?.[local]) return topAvatarOverrides[local]
      }
    }
    const publicRowAvatar = findTopAvatarInPublicRows(profile)
    if (publicRowAvatar) return publicRowAvatar
    const name = normalizeEmail(resolveRealProfileUsername(profile))
    if (name && topAvatarOverrides?.[name]) return topAvatarOverrides[name]
    return ''
  }

  const isUuidLike = (value) => /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(value || '').trim())

  const getTopTipsterProfileId = (profile = {}) => {
    return [profile.id, profile.user_id, profile.author_id, profile.tipster_id, profile.profile_id]
      .find(value => isUuidLike(value)) || ''
  }

  const fetchTopTipsterReviewStats = async (rows = []) => {
    const map = new Map()
    ;(rows || []).forEach(profile => {
      const profileId = getTopTipsterProfileId(profile)
      const ratingAvg = Number(profile.rating_avg ?? profile.profile_rating_avg ?? profile.review_rating_avg ?? 0) || 0
      const ratingCount = Number(profile.rating_count ?? profile.reviews_count ?? profile.profile_rating_count ?? profile.review_rating_count ?? 0) || 0
      if (profileId && ratingCount > 0) map.set(profileId, { avg: ratingAvg, count: ratingCount })
    })

    if (!isSupabaseConfigured || !supabase) return map
    const ids = [...new Set((rows || []).map(getTopTipsterProfileId).filter(Boolean))]
    if (!ids.length) return map

    try {
      const { data, error } = await supabase
        .from('profile_reviews')
        .select('profile_id,rating,is_approved')
        .in('profile_id', ids)
        .eq('is_approved', true)
        .limit(5000)

      if (error || !Array.isArray(data)) return map
      const buckets = new Map()
      data.forEach(review => {
        const profileId = String(review.profile_id || '')
        const ratingValue = Number(review.rating || 0)
        if (!profileId || !Number.isFinite(ratingValue) || ratingValue <= 0) return
        const prev = buckets.get(profileId) || { sum: 0, count: 0 }
        prev.sum += ratingValue
        prev.count += 1
        buckets.set(profileId, prev)
      })
      buckets.forEach((bucket, profileId) => {
        map.set(profileId, { avg: Math.round((bucket.sum / bucket.count) * 100) / 100, count: bucket.count })
      })
    } catch (error) {
      console.warn('top typerzy review stats skipped', error)
    }
    return map
  }

  const attachRealReviewStatsToProfile = (profile = {}, reviewStats = new Map()) => {
    const profileId = getTopTipsterProfileId(profile)
    const remoteStats = profileId ? reviewStats.get(profileId) : null
    const avg = Number(remoteStats?.avg ?? profile.rating_avg ?? profile.profile_rating_avg ?? profile.review_rating_avg ?? 0) || 0
    const count = Number(remoteStats?.count ?? profile.rating_count ?? profile.reviews_count ?? profile.profile_rating_count ?? profile.review_rating_count ?? 0) || 0
    return {
      ...profile,
      top_review_rating_avg: count > 0 ? avg : 0,
      top_review_rating_count: count > 0 ? count : 0,
    }
  }

  const loadRealTopTipsters = async () => {
    setLoadingProfiles(true)
    try {
      const rankingProfileRows = buildTopTipsterRowsFromExistingRanking()
      const publicProfileRows = await fetchBetaiPublicProfiles()
      const mergedRows = mergeProfilesPreferStats(publicProfileRows || [], rankingProfileRows || [])
      const avatarHints = await fetchTopTipsterAvatarHints(mergedRows || [])
      setTopAvatarOverrides(buildTopAvatarOverrideObject(avatarHints))
      const reviewStats = await fetchTopTipsterReviewStats(mergedRows || [])
      const hydratedRows = []
      for (const row of (mergedRows || [])) {
        let topPlans = []
        try { topPlans = await loadTipsterPlansForSource(row) } catch (_) { topPlans = [] }
        hydratedRows.push({ ...row, top_subscription_plans: topPlans })
      }
      setProfiles(hydratedRows
        .map(profile => attachRealAvatarToProfile(profile, avatarHints))
        .map(profile => attachRealReviewStatsToProfile(profile, reviewStats))
        .filter(profile => {
          const name = resolveRealProfileUsername(profile)
          return name && !isGenericProfileName(name) && !isBlockedTopTipsterProfile(profile)
        }))
    } catch (error) {
      console.warn('top typerzy real profiles load failed', error)
      const fallbackRows = buildTopTipsterRowsFromExistingRanking()
      setProfiles(fallbackRows.filter(profile => {
        const name = resolveRealProfileUsername(profile)
        return name && !isGenericProfileName(name) && !isBlockedTopTipsterProfile(profile)
      }))
    } finally {
      setLoadingProfiles(false)
    }
  }

  useEffect(() => {
    // Odświeżanie Top typerów tylko co 10 minut + ręczny przycisk "Odśwież".
    // Nie podpinamy już realtime na każde INSERT/UPDATE, bo przy aktywnej stronie potrafiło to mielić co chwilę.
    loadRealTopTipsters()
    const timer = window.setInterval(() => {
      loadRealTopTipsters()
    }, 10 * 60 * 1000)
    return () => window.clearInterval(timer)
  }, [user?.id, user?.email])

  const toNumber = (value, fallback = 0) => {
    const n = Number(value)
    return Number.isFinite(n) ? n : fallback
  }
  // WERSJA 1802 — w Top typerzy pokazujemy samą kwotę, bez sufiksu waluty.
  const formatMoney = (value) => `${toNumber(value, 0) >= 0 ? '+' : ''}${toNumber(value, 0).toLocaleString('pl-PL', { maximumFractionDigits: 2 })}`
  const formatTopPlanPrice = (value) => `${Number(value || 0).toLocaleString('pl-PL', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} zł`
  const getActiveTopTipsterPlans = (profile = {}) => {
    const sourcePlans = Array.isArray(profile.top_subscription_plans) ? profile.top_subscription_plans : (Array.isArray(profile.subscription_plans) ? profile.subscription_plans : [])
    return normalizeTipsterPlanRows(sourcePlans).filter(plan => plan.active !== false && Number(plan.price || 0) > 0)
  }
  const getMainTopTipsterPlan = (plans = []) => {
    const active = (plans || []).filter(plan => plan.active !== false && Number(plan.price || 0) > 0)
    return active.find(plan => plan.key === 'month') || active[0] || null
  }
  const initialsFor = (name = '') => {
    const clean = String(name || 'U').replace('@', '').trim()
    const parts = clean.split(/[\s._-]+/).filter(Boolean)
    return (parts.length > 1 ? parts[0][0] + parts[1][0] : clean.slice(0, 2)).toUpperCase()
  }
  const isPremiumProfile = (profile = {}) => {
    const plan = normalizeEmail(profile.plan || profile.subscription_status || profile.account_type || profile.role)
    return plan.includes('premium') || plan.includes('pro') || plan.includes('paid') || BETAI_PREMIUM_USERNAMES.includes(normalizeEmail(profile.username)) || BETAI_PREMIUM_EMAILS.includes(normalizeEmail(profile.email))
  }
  const normalizeTopSport = (value = '') => {
    const raw = String(Array.isArray(value) ? value[0] : value || '').toLowerCase()
    if (raw.includes('pił') || raw.includes('pil') || raw.includes('football') || raw.includes('soccer')) return 'Piłka nożna'
    if (raw.includes('tenis') || raw.includes('tennis')) return 'Tenis'
    if (raw.includes('kosz') || raw.includes('basket')) return 'Koszykówka'
    if (raw.includes('hoke') || raw.includes('hockey')) return 'Hokej'
    if (raw.includes('esport') || raw.includes('e-sport') || raw.includes('gaming')) return 'E-sport'
    if (raw.includes('siatk') || raw.includes('volley')) return 'Siatkówka'
    if (raw.includes('mma')) return 'MMA'
    if (raw.includes('baseball')) return 'Baseball'
    return 'Piłka nożna'
  }

  const getProfileTopSport = (profile = {}) => normalizeTopSport(
    profile.preferred_sport ||
    profile.main_sport ||
    profile.sport ||
    profile.favorite_sport ||
    profile.specialization ||
    profile.category ||
    profile.sports
  )

  const normalizeTopFormStatus = (value) => {
    const raw = String(value || '').trim().toLowerCase()
    if (!raw) return 'pending'
    if (['w', 'win', 'won', 'wygrana', 'wygrany', 'wygrał', 'wygral', 'green', 'success'].includes(raw) || raw.includes('won') || raw.includes('win')) return 'won'
    if (['l', 'loss', 'lost', 'lose', 'przegrana', 'przegrany', 'przegrał', 'przegral', 'red', 'failed'].includes(raw) || raw.includes('lost') || raw.includes('loss') || raw.includes('lose')) return 'lost'
    if (['void', 'push', 'zwrot', 'return', 'cancelled', 'canceled', 'anulowany'].includes(raw)) return 'void'
    return 'pending'
  }

  const normalizeTopFormItem = (value) => {
    const status = normalizeTopFormStatus(value)
    if (status === 'won') return { status: 'won', label: 'W', title: 'Wygrany typ' }
    if (status === 'lost') return { status: 'lost', label: 'L', title: 'Przegrany typ' }
    if (status === 'void') return { status: 'void', label: '•', title: 'Zwrot' }
    return { status: 'pending', label: '•', title: 'Brak rozliczenia' }
  }

  const parseTopFormFromProfile = (profile = {}) => {
    const source = profile.recent_form || profile.last_results || profile.recent_results || profile.form || profile.results || profile.last_six_results
    if (!source) return []
    if (Array.isArray(source)) return source.map(item => normalizeTopFormItem(typeof item === 'object' ? (item.status || item.result || item.value || item.type) : item)).slice(0, 6)
    return String(source).split(/[\s,;|/-]+/).filter(Boolean).map(item => normalizeTopFormItem(item)).slice(0, 6)
  }

  const getTopTipsterIdentityTokens = (profile = {}) => {
    const tokens = [
      profile.id,
      profile.user_id,
      profile.author_id,
      profile.tipster_id,
      profile.profileRef,
      profile.email,
      profile.author_email,
      profile.user_email,
      profile.username,
      profile.author_name,
      profile.name,
      profile.public_slug,
      profile.slug,
      resolveRealProfileUsername(profile),
    ]
    const normalized = []
    tokens.forEach(value => {
      const clean = normalizeEmail(value)
      if (!clean || isGenericProfileName(clean)) return
      normalized.push(clean)
      if (clean.includes('@')) normalized.push(clean.split('@')[0])
    })
    return [...new Set(normalized.filter(Boolean))]
  }

  const getTopTipIdentityTokens = (tip = {}) => {
    const normalizedTip = normalizeTipRow(tip)
    const tokens = [
      normalizedTip.author_id,
      normalizedTip.user_id,
      normalizedTip.tipster_id,
      normalizedTip.created_by,
      normalizedTip.owner_id,
      normalizedTip.author_email,
      normalizedTip.user_email,
      normalizedTip.email,
      normalizedTip.author_name,
      normalizedTip.username,
      normalizedTip.author_username,
      normalizedTip.profile_username,
      normalizedTip.public_slug,
      normalizedTip.author_slug,
      normalizedTip.profile_slug,
      resolveRealProfileUsername(normalizedTip),
    ]
    const normalized = []
    tokens.forEach(value => {
      const clean = normalizeEmail(value)
      if (!clean || isGenericProfileName(clean)) return
      normalized.push(clean)
      if (clean.includes('@')) normalized.push(clean.split('@')[0])
    })
    return [...new Set(normalized.filter(Boolean))]
  }

  const getTopTipSortTime = (tip = {}) => {
    const raw = tip.settled_at || tip.result_at || tip.updated_at || tip.event_time || tip.match_time || tip.created_at
    const time = raw ? new Date(raw).getTime() : 0
    return Number.isFinite(time) ? time : 0
  }

  const buildRecentFormForProfile = (profile = {}) => {
    const directForm = parseTopFormFromProfile(profile)
    if (directForm.length) return [...directForm, ...Array.from({ length: Math.max(0, 6 - directForm.length) }, () => normalizeTopFormItem('pending'))].slice(0, 6)

    const profileTokens = new Set(getTopTipsterIdentityTokens(profile))
    const matchedTips = (tips || [])
      .filter(tip => getTopTipIdentityTokens(tip).some(token => profileTokens.has(token)))
      .sort((a, b) => getTopTipSortTime(b) - getTopTipSortTime(a))
      .slice(0, 6)
      .map(tip => normalizeTopFormItem(tip.result || tip.status || tip.result_status || tip.live_status))

    return [...matchedTips, ...Array.from({ length: Math.max(0, 6 - matchedTips.length) }, () => normalizeTopFormItem('pending'))].slice(0, 6)
  }

  const buildTopTipsterAchievements = ({ rank = 0, hitRate = 0, roi = 0, profit = 0, totalTips = 0, rating = 0, votes = 0, recentForm = [], premium = false } = {}) => {
    const recentWins = (recentForm || []).filter(item => item?.status === 'won').length
    const achievements = []

    if (rank === 1) achievements.push({ icon: '👑', title: '#1 · 2026', desc: 'Lider rankingu', tone: 'gold' })
    else if (rank > 1 && rank <= 3) achievements.push({ icon: '🏆', title: `TOP ${rank}`, desc: 'Top 3 rankingu', tone: 'gold' })

    if (recentWins >= 5) achievements.push({ icon: '🔥', title: 'Forma 5/6', desc: 'Minimum 5 wygranych z ostatnich 6', tone: 'orange' })
    else if (recentWins >= 4) achievements.push({ icon: '🔥', title: 'Forma 4/6', desc: 'Minimum 4 wygrane z ostatnich 6', tone: 'orange' })

    if (hitRate >= 80 && totalTips >= 5) achievements.push({ icon: '🎯', title: 'Snajper 80%', desc: 'Skuteczność minimum 80%', tone: 'cyan' })
    else if (hitRate >= 70 && totalTips >= 5) achievements.push({ icon: '🎯', title: 'Snajper 70%', desc: 'Skuteczność minimum 70%', tone: 'cyan' })

    if (profit >= 300) achievements.push({ icon: '💰', title: 'Profit +300 zł', desc: 'Zysk minimum +300 zł', tone: 'green' })
    else if (profit >= 100) achievements.push({ icon: '💰', title: 'Profit +100 zł', desc: 'Zysk minimum +100 zł', tone: 'green' })

    if (roi >= 60 && totalTips >= 3) achievements.push({ icon: '📈', title: 'ROI Master', desc: 'ROI minimum +60%', tone: 'cyan' })
    else if (roi >= 50 && totalTips >= 3) achievements.push({ icon: '📈', title: 'ROI +50%', desc: 'ROI minimum +50%', tone: 'cyan' })

    if (rating >= 4.8 && votes >= 3) achievements.push({ icon: '', title: 'Zaufany', desc: 'Ocena minimum 4.8 i 3 opinie', tone: 'gold' })
    if (premium) achievements.push({ icon: '💎', title: 'Premium typer', desc: 'Sprzedaje płatne typy', tone: 'violet' })

    return achievements.slice(0, 4)
  }

  const formatFollowersLabel = (count) => {
    const value = Math.max(0, Number(count || 0) || 0)
    if (value === 1) return 'obserwujący'
    return 'obserwujących'
  }

  const getVisibleTopFollowersCount = (tipster = {}, isFollowing = false) => {
    const keys = getTopTipsterFollowKeys(tipster)
    const statsValue = keys.reduce((max, key) => {
      const stat = followStats?.[key] || followStats?.[String(key || '').toLowerCase()]
      return Math.max(max, Number(stat?.followers || 0) || 0)
    }, 0)
    const baseValue = Math.max(Number(tipster.followersValue || 0) || 0, statsValue)
    return Math.max(0, isFollowing ? Math.max(baseValue, 1) : baseValue)
  }

  const buildRealTipster = (profile, idx) => {
    const name = resolveRealProfileUsername(profile)
    const isBotProfileV1802 = isBetaiMultisportRecordV1794(profile)
    const canonicalV1802 = isBotProfileV1802 && topBotCanonicalStatsV1802
      ? topBotCanonicalStatsV1802
      : null

    // WERSJA 1802 — konto betai-multisport-ai ma w Top typerzy dokładnie
    // ten sam kanon statystyk co Mój profil / Ranking / Dashboard.
    // Nie korzystamy dla niego ze starych imported_* z profiles.
    const totalTips = canonicalV1802
      ? toNumber(canonicalV1802.totalTips, 0)
      : toNumber(profile.imported_total_tips ?? profile.total_tips ?? profile.tips_count ?? profile.tips, 0)
    const won = canonicalV1802
      ? toNumber(canonicalV1802.wonTips, 0)
      : toNumber(profile.imported_won_tips ?? profile.won_tips ?? profile.won, 0)
    const lost = canonicalV1802
      ? toNumber(canonicalV1802.lostTips, 0)
      : toNumber(profile.imported_lost_tips ?? profile.lost_tips ?? profile.lost, 0)
    const settled = won + lost
    const hitRate = settled > 0 ? Math.round((won / settled) * 1000) / 10 : 0
    const roi = canonicalV1802
      ? toNumber(canonicalV1802.yield, 0)
      : toNumber(profile.imported_yield ?? profile.roi ?? profile.yield, 0)
    const profit = canonicalV1802
      ? toNumber(canonicalV1802.profit, 0)
      : toNumber(profile.imported_profit ?? profile.profit ?? profile.balance_profit, 0)
    const baseFollowers = toNumber(profile.followers_count ?? profile.followers, 0)
    const identityTokens = getTopTipsterIdentityTokens(profile)
    const statsFollowers = identityTokens.reduce((max, key) => {
      const stat = followStats?.[key] || followStats?.[String(key || '').toLowerCase()]
      return Math.max(max, Number(stat?.followers || 0) || 0)
    }, 0)
    const followers = Math.max(baseFollowers, statsFollowers)
    const premium = isPremiumSellerProfile(profile, profile.plan || profile.subscription_status || profile.status || profile.account_type) || isPremiumProfile(profile)
    const topSport = getProfileTopSport(profile)
    const activePlans = getActiveTopTipsterPlans(profile)
    const mainPlan = getMainTopTipsterPlan(activePlans)
    const priceLabel = premium && mainPlan ? `od ${formatTopPlanPrice(mainPlan.price)}` : (premium ? 'Subskrypcja' : 'Darmowe')
    const priceSubLabel = premium && mainPlan ? `/${mainPlan.label}` : '/ dostęp'
    const reviewRating = Number(profile.top_review_rating_avg ?? profile.rating_avg ?? 0) || 0
    const reviewVotes = Number(profile.top_review_rating_count ?? profile.rating_count ?? profile.reviews_count ?? 0) || 0
    const recentForm = buildRecentFormForProfile(profile)
    return {
      rank: idx + 1,
      id: profile.id || profile.user_id || profile.email || name,
      profileRef: profile.id || profile.user_id || profile.author_id || profile.tipster_id || profile.public_slug || profile.email || name,
      user_id: profile.user_id || profile.id || profile.author_id || profile.tipster_id || null,
      author_id: profile.author_id || profile.user_id || profile.id || profile.tipster_id || null,
      tipster_id: profile.tipster_id || profile.id || profile.user_id || profile.author_id || null,
      email: profile.email || profile.author_email || profile.user_email || '',
      author_email: profile.author_email || profile.email || profile.user_email || '',
      username: name,
      author_name: name,
      public_slug: profile.public_slug || profile.slug || normalizePublicSlug(name),
      plan: premium ? 'premium' : (profile.plan || profile.subscription_status || profile.status || 'free'),
      subscription_status: premium ? 'premium' : (profile.subscription_status || profile.plan || profile.status || 'free'),
      top_subscription_plans: activePlans,
      name,
      subtitle: profile.bio || profile.description || profile.about || 'Zweryfikowany typer Bet+AI',
      rating: reviewRating.toFixed(2),
      votes: String(reviewVotes),
      ratingValue: reviewRating,
      votesValue: reviewVotes,
      success: `${hitRate}%`,
      hitRateValue: hitRate,
      roi: `${roi >= 0 ? '+' : ''}${roi.toFixed(1)}%`,
      roiValue: roi,
      profit: formatMoney(profit),
      profitValue: profit,
      totalTipsValue: totalTips,
      picks: String(totalTips),
      chart: `${hitRate}%`,
      recentForm,
      price: priceLabel,
      priceSubLabel,
      followers: `${followers.toLocaleString('pl-PL')} ${formatFollowersLabel(followers)}`,
      followersValue: followers,
      achievements: [],
      avatar: initialsFor(name),
      avatarUrl: findTopAvatarOverrideForProfile(profile) || getProfileAvatarUrl(profile),
      premium,
      sport: topSport,
      sortScore: (profit * 0.3) + (roi * 20) + (hitRate * 10) + totalTips,
    }
  }

  const realTipsters = useMemo(() => {
    return (profiles || [])
      .filter(profile => !isBlockedTopTipsterProfile(profile))
      .map((profile, idx) => buildRealTipster(profile, idx))
      .sort((a, b) => (b.profitValue - a.profitValue) || (b.totalTipsValue - a.totalTipsValue) || (b.sortScore - a.sortScore))
      .map((item, idx) => {
        const rankedItem = { ...item, rank: idx + 1 }
        return {
          ...rankedItem,
          achievements: buildTopTipsterAchievements({
            rank: rankedItem.rank,
            hitRate: rankedItem.hitRateValue,
            roi: rankedItem.roiValue,
            profit: rankedItem.profitValue,
            totalTips: rankedItem.totalTipsValue,
            rating: rankedItem.ratingValue,
            votes: rankedItem.votesValue,
            recentForm: rankedItem.recentForm,
            premium: rankedItem.premium,
          })
        }
      })
  }, [profiles, topAvatarOverrides, publicTopAvatarRows, topBotCanonicalStatsV1802])

  const sportThemeMapV1510 = {
    'Piłka nożna': 'football',
    'Koszykówka': 'basketball',
    'Tenis': 'tennis',
    'Hokej': 'hockey',
    'MMA': 'mma',
    'E-sport': 'esports',
    'Siatkówka': 'volleyball',
    'Boks': 'boxing',
    'Piłka ręczna': 'handball',
    'Krykiet': 'cricket',
    'Rugby': 'rugby',
    'Rugby League': 'rugbyleague',
    'Baseball': 'baseball',
    'Dart': 'dart',
  }

  const sportCategoryDefs = [
    { label: 'Piłka nożna', icon: '⚽' },
    { label: 'Koszykówka', icon: '🏀' },
    { label: 'Tenis', icon: '🎾' },
    { label: 'Hokej', icon: '🏒' },
    { label: 'MMA', icon: '🥊' },
    { label: 'E-sport', icon: '🎮' },
    { label: 'Siatkówka', icon: '🏐' },
    { label: 'Boks', icon: '🥊' },
    { label: 'Piłka ręczna', icon: '🤾' },
    { label: 'Krykiet', icon: '🏏' },
    { label: 'Rugby', icon: '🏉' },
    { label: 'Rugby League', icon: '🏉' },
    { label: 'Baseball', icon: '⚾' },
    { label: 'Dart', icon: '🎯' },
  ]

  const sortOptions = [
    { value: 'all', label: 'Wszystkie konta' },
    { value: 'premium', label: 'Konta płatne' },
    { value: 'free', label: 'Konta darmowe' },
  ]

  const countTopSport = (sportName) => realTipsters.filter(item => item.sport === sportName).length

  const categories = sportCategoryDefs.map((item) => {
    const count = countTopSport(item.label)
    return {
      ...item,
      count,
      theme: sportThemeMapV1510[item.label] || 'default',
      enabled: true,
      soon: count === 0,
    }
  })

  const sportFilteredTipsters = realTipsters
    .filter(item => item.sport === selectedTopSport)
    .filter(item => !isHiddenDemoProfileV1712(item) && !isHiddenDemoUserV1712(item?.name || item?.username || item?.display_name || item?.profileRef))
  const filteredTipsters = sportFilteredTipsters.filter(item => {
    if (topAccountFilter === 'premium') return item.premium
    if (topAccountFilter === 'free') return !item.premium
    return true
  })

  const marketStats = [
    ['Typerzy', String(filteredTipsters.length)],
    ['Typy aktywne', String(filteredTipsters.reduce((sum, item) => sum + toNumber(item.picks, 0), 0))],
    ['Premium', String(filteredTipsters.filter(item => item.premium).length)],
    ['Darmowe', String(filteredTipsters.filter(item => !item.premium).length)],
  ]

  const steps = [
    ['1', 'Wybierz typera', 'Sprawdź realne konto i jego statystyki.'],
    ['2', 'Kup subskrypcję albo darmowy dostęp', 'Premium ma przycisk subskrypcji, darmowe konta są oznaczone jako Darmowe.'],
    ['3', 'Obserwuj wyniki', 'Nowi użytkownicy dopisują się automatycznie z Supabase.'],
  ]

  const openTopTipsterProfile = (tipster = {}) => {
    if (typeof onOpenTipster === 'function') {
      onOpenTipster(tipster.profileRef || tipster.id || tipster.name, tipster.name)
    }
  }

  const openTopTipsterSubscription = (tipster = {}) => {
    if (!tipster?.premium) {
      openTopTipsterProfile(tipster)
      return
    }
    if (typeof onSubscribeToTipster === 'function') {
      onSubscribeToTipster({
        ...tipster,
        id: tipster.tipster_id || tipster.user_id || tipster.author_id || tipster.profileRef || tipster.id,
        tipster_id: tipster.tipster_id || tipster.user_id || tipster.author_id || tipster.profileRef || tipster.id,
        user_id: tipster.user_id || tipster.tipster_id || tipster.author_id || tipster.profileRef || tipster.id,
        author_id: tipster.author_id || tipster.tipster_id || tipster.user_id || tipster.profileRef || tipster.id,
        username: tipster.name,
        author_name: tipster.name,
        email: tipster.email || tipster.author_email || '',
        author_email: tipster.author_email || tipster.email || '',
        plan: 'premium',
        subscription_status: 'premium'
      })
    }
  }


  const getTopTipsterFollowKeys = (tipster = {}) => {
    const values = [
      tipster.tipster_id,
      tipster.user_id,
      tipster.author_id,
      tipster.profileRef,
      tipster.id,
      tipster.name,
      tipster.username,
      tipster.email,
      tipster.author_email,
    ]
    const keys = values
      .map(value => String(value || '').trim().toLowerCase())
      .filter(Boolean)
    keys.forEach(key => {
      if (key.includes('@')) keys.push(key.split('@')[0])
    })
    return [...new Set(keys)]
  }

  const isTopTipsterFollowing = (tipster = {}) => {
    const activeSet = followingTipsters instanceof Set ? followingTipsters : new Set(followingTipsters || [])
    return getTopTipsterFollowKeys(tipster).some(key => activeSet.has(key) || activeSet.has(String(key).toLowerCase()))
  }

  const toggleTopTipsterFollow = (tipster = {}) => {
    if (typeof onToggleFollow !== 'function') return
    const targetId = tipster.tipster_id || tipster.user_id || tipster.author_id || tipster.profileRef || tipster.id || tipster.name
    const displayName = tipster.name || tipster.username || tipster.email || targetId
    onToggleFollow(targetId, displayName, getTopTipsterFollowKeys(tipster))
  }

  return (
    <section className="market-static-v7 top-tipsters-v1510">
      <div className="market-v7-layout">
        <div className="market-v7-main">
          <div className="glass-market-v7 market-v7-hero top-tipsters-hero-v1510">
            <div className="market-hero-copy-v7">
              <span>TOP TYPERZY • LIVE MARKETPLACE</span>
              <h1>Najlepsi typerzy
                <br />w sportowej <em>kratce</em></h1>
            </div>
            <div className="betfolio-add-hero-visual betfolio-sport-hero-v2 top-tipsters-hero-art-v1510" aria-hidden="true">
              <div className="sport-hero-grid"></div>
              <div className="sport-hero-data-line line-a"></div>
              <div className="sport-hero-data-line line-b"></div>
              <div className="sport-hero-data-line line-c"></div>
              <div className="sport-hero-orbit orbit-a"></div>
              <div className="sport-hero-orbit orbit-b"></div>
              <div className="sport-hero-ball main-ball">🏆</div>
              <div className="sport-hero-mini-ball mini-tennis">📈</div>
              <div className="sport-hero-mini-ball mini-basket">👥</div>
              <div className="sport-hero-mini-ball mini-hockey">⚡</div>
              <div className="sport-hero-scanner-card">
                <span>TOP TYPERZY</span>
                <strong>{filteredTipsters.length || realTipsters.length}</strong>
                <small>aktywnych profili w rankingu</small>
                <em></em>
              </div>
            </div>
          </div>

          <div className="betfolio-sport-cards-v1276 top-tipsters-sport-cards-v1510" aria-label="Popularne sporty Top typerzy">
            <div className="sport-cards-head-v1276">
              <span>{t('Popularne sporty')}</span>
            </div>
            <div className="sport-cards-track-v1276 all-sports top-tipsters-sports-grid-v1510">
              {categories.map((item) => {
                const isActive = selectedTopSport === item.label
                const count = Number(item.count || 0)
                return (
                  <button
                    type="button"
                    className={`sport-card-v1276 ${item.theme} ${isActive ? 'active' : ''} ${item.soon ? 'is-soon-v1510' : ''}`}
                    key={item.label}
                    onClick={() => setSelectedTopSport(item.label)}
                    aria-pressed={isActive}
                  >
                    <div className="sport-card-top-v1276"><i>{item.icon}</i><span>{item.label}</span></div>
                    <strong>{count ? `${count} ${count === 1 ? 'typer' : count < 5 ? 'typerów' : 'typerów'}` : 'WKRÓTCE'}</strong>
                    <small>{count ? 'Filtruj ranking po sporcie' : 'Aktywacja w kolejnych wersjach'}</small>
                    <b aria-hidden="true">{item.icon}</b>
                  </button>
                )
              })}
            </div>
          </div>

          <div className="market-v7-filters">
            <div className={`glass-market-v7 filter-v7 filter-v7-sort ${sortOpen ? 'open' : ''}`}>
              <button
                type="button"
                className="filter-v7-trigger"
                onClick={() => setSortOpen(value => !value)}
                aria-expanded={sortOpen}
              >
                <div>
                  <small>Sortuj</small>
                  <strong>{sortOptions.find(option => option.value === topAccountFilter)?.label || 'Wszystkie konta'}</strong>
                </div>
                <span>⌄</span>
              </button>
              {sortOpen ? (
                <div className="filter-v7-menu">
                  {sortOptions.map((option) => (
                    <button
                      key={option.value}
                      type="button"
                      className={topAccountFilter === option.value ? 'active' : ''}
                      onClick={() => {
                        setTopAccountFilter(option.value)
                        setSortOpen(false)
                      }}
                    >
                      {option.label}
                    </button>
                  ))}
                </div>
              ) : null}
            </div>
          </div>

          <div className="market-v7-section-head">
            <h2>NAJLEPSI TYPERZY</h2>
            <button type="button" onClick={loadRealTopTipsters}>Odśwież</button>
          </div>

          <div className="market-v7-list">
            {loadingProfiles && <div className="glass-market-v7 seller-card-v7"><strong>Ładuję realne konta...</strong></div>}
            {!loadingProfiles && !filteredTipsters.length && <div className="glass-market-v7 seller-card-v7"><strong>Brak realnych kont dla wybranego sportu.</strong><p>Po rejestracji użytkownika albo zmianie specjalizacji profil dopisze się automatycznie z Supabase.</p></div>}
            {!loadingProfiles && filteredTipsters.map((tipster, idx) => (
              <article className="glass-market-v7 seller-card-v7 seller-card-v1515" key={tipster.id || idx}>
                <div className="seller-main-v7 seller-main-v1515">
                  <div className="seller-profile-v7 seller-profile-v1515">
                    <button type="button" className={`seller-avatar-v7 seller-avatar-button-v1111 a${(idx % 3) + 1} ${tipster.avatarUrl ? 'has-real-avatar-v1128' : ''}`} onClick={() => openTopTipsterProfile(tipster)} title="Otwórz profil użytkownika">{tipster.avatarUrl ? <img src={tipster.avatarUrl} alt={tipster.name} loading="lazy" referrerPolicy="no-referrer" /> : tipster.avatar}</button>
                    <div className="seller-copy-v7 seller-copy-v1515">
                      <div className="seller-title-row-v7">
                        <span className={`rank-pill-v7 r${Math.min(tipster.rank, 3)}`}>{tipster.rank}</span>
                        <button type="button" className="seller-name-link-v1111" onClick={() => openTopTipsterProfile(tipster)} title="Otwórz profil użytkownika">{tipster.name}</button>
                        <i>✓</i>
                      </div>
                      <p>{tipster.subtitle}</p>
                      <div className="seller-rating-v7"> {tipster.rating} <span>({tipster.votes})</span> <em>{tipster.premium ? 'PREMIUM' : 'DARMOWE'}</em></div>
                    </div>
                  </div>

                  <div className="seller-stats-row-v7 seller-stats-row-v1515">
                    <div className="seller-stat-box-v1515"><small>Skuteczność</small><b>{tipster.success}</b></div>
                    <div className="seller-stat-box-v1515"><small>Yield</small><b>{tipster.roi}</b></div>
                    <div className="seller-stat-box-v1515"><small>Zysk</small><b>{tipster.profit}</b></div>
                    <div className="seller-stat-box-v1515"><small>Typy</small><b>{tipster.picks}</b></div>
                  </div>
                </div>

                <div className="seller-chart-v7 seller-chart-v1515">
                  <div className="success-head-v1117 success-head-v1515">
                    <small>Forma</small>
                    <b>{tipster.chart}</b>
                  </div>
                  <div className="recent-form-v1114" aria-label={`Ostatnie 6 typów: ${(tipster.recentForm || []).map(item => item.label).join(' ')}`}>
                    {(tipster.recentForm || []).map((item, formIdx) => (
                      <span key={formIdx} className={`form-pill-v1114 ${item.status}`} title={item.title}>{item.label}</span>
                    ))}
                  </div>
                  <div className="achievement-head-v1117 achievement-head-v1515">Osiągnięcia</div>
                  <div className="spec-list-v7 achievement-list-v1115 achievement-list-v1515">
                    {tipster.achievements?.length ? tipster.achievements.map((badge, i) => (
                      <i key={`${badge.title}-${i}`} className={`achievement-badge-v1115 ${badge.tone || ''}`} title={`${badge.title} — ${badge.desc}`}>{badge.icon}</i>
                    )) : <em className="no-achievement-v1115">Brak osiągnięć</em>}
                  </div>
                </div>

                <div className="seller-cta-v7 seller-cta-v1515">
                  <div className="price-v7 price-v1515"><strong>{tipster.price}</strong><span>{tipster.priceSubLabel || '/ dostęp'}</span></div>
                  {tipster.premium && tipster.top_subscription_plans?.length ? (
                    <div className="top-plan-mini-list-v1113 top-plan-mini-list-v1515" title="Cennik ustawiony przez użytkownika">
                      {tipster.top_subscription_plans.slice(0, 4).map(plan => <span key={plan.key}>{plan.label}: <b>{formatTopPlanPrice(plan.price)}</b></span>)}
                    </div>
                  ) : null}
                  <button type="button" className={`buy-btn-v7 ${tipster.premium ? '' : 'free-access-v1113'}`} onClick={() => openTopTipsterSubscription(tipster)}>{tipster.premium ? 'Kup subskrypcję' : 'Darmowe'}</button>
                  <div className="cta-bottom-v7 cta-bottom-v1515">
                    {(() => {
                      const isFollowing = isTopTipsterFollowing(tipster)
                      return (
                        <button
                          type="button"
                          className={`follow-btn-v7 top-follow-btn-v1119 ${isFollowing ? 'is-following' : ''}`}
                          onClick={() => toggleTopTipsterFollow(tipster)}
                          aria-label={isFollowing ? 'Przestań obserwować typera' : 'Obserwuj typera'}
                          title={isFollowing ? 'Kliknij, żeby przestać obserwować' : 'Kliknij, żeby obserwować'}
                        >
                          <span className="follow-icon-v1119" aria-hidden="true">{isFollowing ? '✓' : '+'}</span>
                          <span className="follow-label-v1119">{isFollowing ? 'Obserwujesz' : 'Obserwuj'}</span>
                        </button>
                      )
                    })()}
                    {(() => {
                      const isFollowing = isTopTipsterFollowing(tipster)
                      const count = getVisibleTopFollowersCount(tipster, isFollowing)
                      return <span>{count.toLocaleString(locale)} {formatFollowersLabel(count)}</span>
                    })()}
                  </div>
                </div>
              </article>
            ))}
          </div>
        </div>

        <aside className="market-v7-sidebar">
          <div className="glass-market-v7 side-market-card-v7">
            <div className="side-title-v7">PODSUMOWANIE RYNKU</div>
            <div className="market-summary-grid-v7">
              {marketStats.map((item, idx) => (
                <div key={idx}>
                  <small>{item[0]}</small>
                  <b>{item[1]}</b>
                </div>
              ))}
            </div>
          </div>

          <div className="glass-market-v7 side-market-card-v7">
            <div className="side-title-v7">JAK TO DZIAŁA?</div>
            <div className="steps-list-v7">
              {steps.map((step, idx) => (
                <div className="step-row-v7" key={idx}>
                  <span>{step[0]}</span>
                  <div><strong>{step[1]}</strong><small>{step[2]}</small></div>
                </div>
              ))}
            </div>
          </div>

        </aside>
      </div>
    </section>
  )
}


