  async function resolvePublicTipsterBySlug(slug) {
  const cleanSlug = String(slug || '').trim().toLowerCase()
  const systemProfileV1838 = getBetaiSystemTipsterProfileV1838(slug)
  if (systemProfileV1838) return systemProfileV1838
  if (!cleanSlug || !isSupabaseConfigured || !supabase) return null

  // WERSJA 1430:
  // Nie robimy już profiles?public_slug.eq / username.eq / email.eq w URL,
  // bo gdy kolumna lub filtr nie pasuje do schematu, Supabase daje czerwone 400.
  // Pobieramy małą paczkę profili i filtrujemy lokalnie.
  const rows = await safeSupabaseArray(
    supabase
      .from('profiles').select('*')
      .order('created_at', { ascending: false })
      .limit(250),
    [],
    4500
  )

  return rows.find(row => {
    const candidates = [
      row.public_slug,
      row.slug,
      row.username,
      row.email,
      String(row.email || '').split('@')[0],
      row.id
    ].filter(Boolean).map(value => String(value).trim().toLowerCase())

    return candidates.includes(cleanSlug)
  }) || null
}


  async function fetchRealRanking() {
    if (!isSupabaseConfigured || !supabase) {
      setRealRanking(buildLiveLeaderboardRows([], tips))
      return
    }

    const safeRows = async (query, fallback = []) => {
      try {
        const timeout = new Promise(resolve => setTimeout(() => resolve({ data: fallback, error: { message: 'timeout' } }), 5000))
        const result = await Promise.race([query, timeout])
        if (result?.error) return fallback
        return Array.isArray(result?.data) ? result.data : fallback
      } catch (_) {
        return fallback
      }
    }

    try {
      // WERSJA 1429: ranking/top typerzy bez ciężkich limitów 1000 i bez łańcucha wielu widoków.
      const [rankingRows, tipRows, profileRows] = await Promise.all([
        safeRows(supabase.from('betai_live_ranking_v999').select('*').order('profit', { ascending: false }).limit(100), []),
        safeRows(supabase.from('tips').select('*').order('created_at', { ascending: false }).limit(500), []),
        fetchBetaiPublicProfiles().catch(() => [])
      ])

      const cleanTipRows = (tipRows || []).filter(row => !isBlockedTestProfile(row) && !isHiddenDemoProfileV1712(row) && !isBetaiMultisportPublicTipHiddenV28(row))
      const profileRowsWithSystemV1837 = mergeProfilesPreferStats([
        ...(profileRows || []),
        ...BETAI_SYSTEM_TIPSTER_PROFILES_V1837,
      ])
      const profileRankingRows = profileRowsWithSystemV1837
        .filter(profile => !isBlockedTestProfile(profile) && !isHiddenDemoProfileV1712(profile) && !isBetaiMultisportPublicTipHiddenV28(profile))
        .map(profile => {
        const canonical = buildCanonicalProfileStatsV1817(profile, cleanTipRows)
        const profit = Number(canonical?.profit ?? profile.profit ?? profile.earnings ?? profile.imported_profit ?? 0) || 0
        const totalTips = Number(canonical?.totalTips ?? profile.total_tips ?? profile.tips_count ?? profile.imported_total_tips ?? 0) || 0
        const wins = Number(canonical?.wonTips ?? profile.wins ?? profile.imported_won_tips ?? 0) || 0
        const losses = Number(canonical?.lostTips ?? profile.losses ?? profile.imported_lost_tips ?? 0) || 0
        const voids = Number(canonical?.voidTips ?? profile.void_tips ?? profile.voids ?? profile.imported_void_tips ?? 0) || 0
        const pending = Number(canonical?.pendingTips ?? profile.pending_tips ?? profile.imported_pending_tips ?? 0) || 0
        const roi = Number(canonical?.yield ?? profile.yield ?? profile.roi ?? profile.imported_yield ?? 0) || 0
        return {
          ...profile,
          tipster_id: profile.id,
          username: profile.username || (profile.email ? String(profile.email).split('@')[0] : 'Użytkownik'),
          canonical_total_tips: totalTips,
          canonical_won_tips: wins,
          canonical_lost_tips: losses,
          canonical_void_tips: voids,
          canonical_pending_tips: pending,
          canonical_yield: roi,
          canonical_profit: profit,
          // W tym wierszu imported_* jest tylko aliasem UI i musi pokazywać
          // pełny aktualny stan, nie sam historyczny baseline.
          imported_total_tips: totalTips,
          imported_won_tips: wins,
          imported_lost_tips: losses,
          imported_void_tips: voids,
          imported_pending_tips: pending,
          imported_yield: roi,
          imported_profit: profit,
          total_tips: totalTips,
          totalTips,
          wins,
          losses,
          voids,
          voidTips: voids,
          pending,
          pendingTips: pending,
          winrate: (wins + losses) > 0 ? (wins / (wins + losses)) * 100 : Number(profile.winrate || 0),
          roi,
          yield: roi,
          earnings: profit,
          profit
        }
      })

      const cleanRankingRows = (rankingRows || []).filter(row => !isBlockedTestProfile(row) && !isHiddenDemoProfileV1712(row) && !isHiddenDemoUserV1712(formatRankingName(row)) && !isBetaiMultisportPublicTipHiddenV28(row))
      const finalRows = buildLiveLeaderboardRows(
        mergeRankingRows(profileRankingRows, cleanRankingRows, buildRankingFromTips(cleanTipRows)),
        cleanTipRows.length ? cleanTipRows : (tips || []).filter(row => !isBlockedTestProfile(row))
      )

      setRealRanking((finalRows || []).filter(row => !isHiddenDemoProfileV1712(row) && !isHiddenDemoUserV1712(formatRankingName(row)) && !isBetaiMultisportPublicTipHiddenV28(row)))
    } catch (error) {
      console.error('fetchRealRanking exception', error)
      setRealRanking(buildLiveLeaderboardRows([], tips))
    }
  }

  async function fetchReferralData(userId = sessionUser?.id) {
    if (!userId || !isSupabaseConfigured || !supabase) {
      setReferralData({ referral_code: '', referrals_count: 0, buyers_count: 0, reward_total: 0, referrals: [], rewards: [] })
      return
    }

    const safeQuery = async (promise, fallback = null) => {
      try {
        const timeout = new Promise(resolve => setTimeout(() => resolve({ data: fallback, error: { message: 'timeout' } }), 4500))
        const result = await Promise.race([promise, timeout])
        if (result?.error) return fallback
        return result?.data ?? fallback
      } catch (_) {
        return fallback
      }
    }

    setReferralLoading(true)
    try {
      const codeData = await safeQuery(supabase.rpc('ensure_referral_code', { p_user_id: userId }), '')
      const referralCode = typeof codeData === 'string' ? codeData : ''

      const dashboardData = await safeQuery(supabase.rpc('get_referral_dashboard', { p_user_id: userId }), null)
      const row = Array.isArray(dashboardData) ? dashboardData[0] : dashboardData

      const referralsRows = await safeQuery(
        supabase.from('referrals').select('*').eq('referrer_id', userId).order('created_at', { ascending: false }).limit(10),
        []
      )
      const rewardsRows = await safeQuery(
        supabase.from('referral_rewards').select('*').eq('referrer_id', userId).order('created_at', { ascending: false }).limit(10),
        []
      )

      const profileFallback = await safeQuery(
        supabase.from('profiles').select('*').eq('id', userId).maybeSingle(),
        null
      )

      setReferralData({
        referral_code: row?.referral_code || profileFallback?.referral_code || referralCode,
        referrals_count: Number(row?.referrals_count ?? profileFallback?.referrals_count ?? 0),
        buyers_count: Number(row?.buyers_count ?? profileFallback?.buyers_count ?? 0),
        reward_total: Number(row?.reward_total ?? profileFallback?.referral_reward_total ?? 0),
        referrals: Array.isArray(referralsRows) ? referralsRows : [],
        rewards: Array.isArray(rewardsRows) ? rewardsRows : []
      })
    } catch (error) {
      console.error('fetchReferralData error', error)
    } finally {
      setReferralLoading(false)
    }
  }

  async function registerReferralFromStoredCode(user = sessionUser) {
    const code = getStoredReferralCode()
    const userId = user?.id
    if (!code || !userId || !isSupabaseConfigured || !supabase) return false

    try {
      const { data, error } = await supabase.rpc('register_referral_signup', {
        p_referred_id: userId,
        p_referral_code: code,
        p_referred_email: normalizeEmail(user?.email || '')
      })
      if (error) throw error

      if (data) {
        try { localStorage.removeItem('betai_referral_code') } catch (_) {}
        await fetchReferralData(userId)
        await fetchCurrentTokenBalance()
        return true
      }

      return false
    } catch (error) {
      console.warn('register referral skipped', error)
      return false
    }
  }

  async function runAiBotMaintenanceFallback(options = {}) {
    const isAdmin = isAdminUser(effectiveAccountProfile || sessionUser)
    if (!isAdmin || typeof window === 'undefined') return null
    if (aiBotMaintenanceRunningRef.current) return null

    const now = Date.now()
    const force = Boolean(options?.force)
    const storageKey = 'betai_ai_bot_maintenance_last_v23'
    let lastStored = 0
    try { lastStored = Number(window.localStorage.getItem(storageKey) || 0) } catch (_) {}
    const lastRun = Math.max(Number(aiBotMaintenanceLastRunRef.current || 0), lastStored)

    // WERSJA 23: admin fallback nie czeka już 90 minut.
    // Ma sprawdzić minimum dzienne szybko po wejściu i po powrocie do karty.
    if (!force && now - lastRun < 20 * 60 * 1000) return null

    aiBotMaintenanceRunningRef.current = true
    aiBotMaintenanceLastRunRef.current = now
    try { window.localStorage.setItem(storageKey, String(now)) } catch (_) {}

    try {
      const response = await fetch('/.netlify/functions/force-daily-bot-tips?source=frontend-admin-v23&force_daily=1&daily_force=1&days=7&min_minutes_before_start=5&max_hours_ahead=168', {
        method: 'POST',
        cache: 'no-store',
        keepalive: true
      })

      // Nie pokazujemy toastów, bo to tylko zabezpieczenie w tle dla Typer Expert i Ograć Buka.
      if (!response.ok && response.status !== 202) {
        const raw = await response.text().catch(() => '')
        console.warn('ai bot maintenance skipped', response.status, raw.slice(0, 240))
      }

      window.setTimeout(() => {
        fetchTips(sessionUser?.id).catch(() => {})
        fetchRealRanking().catch(() => {})
      }, 18000)
      return true
    } catch (error) {
      console.warn('ai bot maintenance fallback skipped', error)
      return null
    } finally {
      aiBotMaintenanceRunningRef.current = false
    }
  }

  async function runLiveAiEngine() {
    setAiLiveGenerating(true)
    try {
      const response = await fetch("/.netlify/functions/publish-betai-multisport-ai?days=3&manual=1", { method: "POST" })
      const data = await response.json().catch(() => ({}))
      if (!response.ok) throw new Error(data.error || "Nie udało się wygenerować LIVE AI typów")
      const msg = data.queued ? 'Skan realnych meczów został uruchomiony w tle. Typ pojawi się po zakończeniu analizy.' : (data.inserted ? `Dodano ${data.inserted} realnych typów z ${data.matches_checked || data.live_matches_checked || 0} meczów.` : (data.message || 'Brak meczów albo brak value picków.'))
      showToast({ type: data.inserted ? "success" : "info", title: "LIVE AI", message: msg })
      await fetchTips(sessionUser?.id)
    } catch (error) {
      console.error("runLiveAiEngine error", error)
      showToast({ type: "error", title: "LIVE AI Engine", message: error.message || "Sprawdź API_FOOTBALL_KEY w Netlify ENV." })
    } finally {
      setAiLiveGenerating(false)
    }
  }

  async function runAiSettlement(options = {}) {
    const isAuto = Boolean(options?.auto)
    const now = Date.now()
    if (isAuto) {
      if (aiAutoSettleRunningRef.current) return null
      const lastLocal = Number(aiAutoSettleLastRunRef.current || 0)
      let lastStored = 0
      try { lastStored = Number(window.localStorage.getItem('betai_ai_bets_auto_settle_last_v1499') || 0) } catch (_) {}
      const last = Math.max(lastLocal, lastStored)
      if (now - last < 15 * 60 * 1000) return null
      aiAutoSettleRunningRef.current = true
      aiAutoSettleLastRunRef.current = now
      try { window.localStorage.setItem('betai_ai_bets_auto_settle_last_v1499', String(now)) } catch (_) {}
    }
    setAiSettleGenerating(true)
    try {
      const batchLimit = isAuto ? 8 : 20
      const endpoints = isAuto
        ? [{ key: 'betai', url: `/.netlify/functions/settle-live-ai-picks?limit=${batchLimit}` }]
        : [
            { key: 'betai', url: `/.netlify/functions/settle-live-ai-picks?limit=${batchLimit}` },
            { key: 'typer', url: '/.netlify/functions/settle-typer-expert' },
            { key: 'ograc', url: '/.netlify/functions/settle-ograc-buka' }
          ]

      const responses = await Promise.all(endpoints.map(async endpoint => {
        const response = await fetch(endpoint.url, { method: 'POST' })
        const raw = await response.text()
        let data = {}
        try { data = raw ? JSON.parse(raw) : {} } catch (_) { data = {} }
        if (!response.ok) {
          const gatewayHint = raw && !data.error ? raw.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 180) : ''
          throw new Error(`${endpoint.key}: ${data.error || gatewayHint || `HTTP ${response.status}`}`)
        }
        return { key: endpoint.key, data }
      }))

      let totalChecked = 0
      let totalSettled = 0
      let totalSkipped = 0
      let remaining = 0
      let errorCount = 0

      responses.forEach(({ key, data }) => {
        const settledCount = Array.isArray(data.settled) ? data.settled.length : Number(data.settled || 0)
        const skippedCount = Array.isArray(data.skipped) ? data.skipped.length : Number(data.skipped || 0)
        totalChecked += Number(data.checked || 0) + Number(data.directTipsChecked || 0)
        totalSettled += settledCount + Number(data.directTipsSettled || 0)
        totalSkipped += skippedCount + Number(data.directTipsSkipped || 0)
        remaining += Number(data.remainingCandidates || 0)
        errorCount += Array.isArray(data.errors) ? data.errors.length : 0
        if (key !== 'betai' && Array.isArray(data.skipped) && data.skipped.length) {
          console.warn(`${key} settlement skipped`, data.skipped)
        }
      })

      const extra = `${errorCount ? ` Błędy: ${errorCount}.` : ''}${remaining ? ` Zostało w kolejce: ${remaining}.` : ''}`
      if (!isAuto || totalSettled > 0) {
        showToast({ type: totalSettled ? "success" : "info", title: isAuto ? "Auto rozliczenie AI" : "Rozliczenie AI i botów", message: `Sprawdzono ${totalChecked}, rozliczono ${totalSettled}, pominięto ${totalSkipped}.${extra}` })
      }
      try { window.dispatchEvent(new CustomEvent('betai-ai-bets-settled', { detail: responses })) } catch (_) {}
      await fetchTips(sessionUser?.id)
    } catch (error) {
      console.error("runAiSettlement error", error)
      if (!isAuto) {
        showToast({ type: "error", title: "AI Settlement", message: error.message || "Sprawdź API_FOOTBALL_KEY / Supabase ENV." })
      }
    } finally {
      setAiSettleGenerating(false)
      if (isAuto) aiAutoSettleRunningRef.current = false
    }
  }

  useEffect(() => {
    if (view !== 'aiPicks' || !sessionUser?.id) return
    const timer = window.setTimeout(() => {
      runAiSettlement({ auto: true })
    }, 1600)
    return () => window.clearTimeout(timer)
  }, [view, sessionUser?.id])

  useEffect(() => {
    if (!sessionUser?.id) return
    if (!isAdminUser(effectiveAccountProfile || sessionUser)) return

    const timer = window.setTimeout(() => {
      runAiBotMaintenanceFallback().catch(() => {})
    }, 3500)

    // WERSJA 29: watchdog bota nie odpala już przy każdym powrocie z karty.
    // Cron Netlify pilnuje botów, a frontend robi tylko spokojny start po wejściu admina.
    return () => {
      window.clearTimeout(timer)
    }
  }, [sessionUser?.id, sessionUser?.email, accountProfile?.id, accountProfile?.email, accountProfile?.username])


  async function runUserTipsAutoSettlement({ force = false } = {}) {
    if (!sessionUser?.id) return null
    if (!force && !canRunBetaiHeavyTaskV29()) return null
    if (autoSettleRunningRef.current) return null

    const now = Date.now()
    if (!force && now - Number(autoSettleLastRunRef.current || 0) < 4 * 60 * 1000) return null

    autoSettleRunningRef.current = true
    autoSettleLastRunRef.current = now
    try {
      const response = await fetch('/.netlify/functions/auto-settle-tips?limit=500&repair_dnb=1', { method: 'GET' })
      const data = await response.json().catch(() => ({}))
      if (!response.ok) throw new Error(data.error || 'Nie udało się automatycznie rozliczyć typów użytkowników')
      const settledCount = Array.isArray(data.settled) ? data.settled.length : Number(data.settled || 0)
      const failedCount = Array.isArray(data.failed) ? data.failed.length : 0
      if (settledCount > 0) {
        showToast({ type: 'success', title: 'Rozliczono typy', message: `Automatycznie rozliczono ${settledCount} zakończonych kuponów.` })
        await fetchTips(sessionUser?.id)
        fetchRealRanking()
      } else if (failedCount > 0) {
        console.warn('auto-settle tips failed rows', data.failed)
      }
      return data
    } catch (error) {
      console.warn('auto-settle user tips skipped', error)
      return null
    } finally {
      autoSettleRunningRef.current = false
    }
  }

  async function fetchTips(userId = sessionUser?.id, options = {}) {
    const requestedUserId = userId || sessionUser?.id || null
    const force = Boolean(options?.force)

    if (!force && !isBetaiDocumentVisibleV29()) return
    if (!force && isBetaiResumeCoolingDownV29()) {
      fetchTipsQueuedUserRef.current = requestedUserId
      scheduleBetaiLightTaskV29('fetch-tips-after-resume-v29', () => fetchTips(fetchTipsQueuedUserRef.current || requestedUserId, { force: true }), 2400)
      return
    }

    if (fetchTipsRunningRef.current) {
      fetchTipsQueuedUserRef.current = requestedUserId
      return
    }

    const startedAt = Date.now()
    if (!force && startedAt - Number(fetchTipsLastStartRef.current || 0) < 1200) {
      fetchTipsQueuedUserRef.current = requestedUserId
      scheduleBetaiLightTaskV29('fetch-tips-dedupe-v29', () => fetchTips(fetchTipsQueuedUserRef.current || requestedUserId, { force: true }), 1300)
      return
    }

    fetchTipsRunningRef.current = true
    fetchTipsLastStartRef.current = startedAt

    if (!isSupabaseConfigured || !supabase) {
      setTips([])
      fetchTipsRunningRef.current = false
      return
    }

    setLoading(true)

    const publicTipsPromise = fetch(`/.netlify/functions/get-public-tips?limit=500&t=${Date.now()}`, { cache: 'no-store' })
      .then(response => response.ok ? response.json() : { tips: [] })
      .catch(() => ({ tips: [] }))

    const [{ data: tipsData, error: tipsError }, publicTipsPayload, { data: unlockedData, error: unlockedError }] = await Promise.all([
      supabase
        .from('tips').select('*')
        .order('created_at', { ascending: false })
        .limit(500),
      publicTipsPromise,
      userId
        ? supabase.from('unlocked_tips').select('tip_id').eq('user_id', userId)
        : Promise.resolve({ data: [], error: null })
    ])

    setLoading(false)

    if (tipsError) {
      console.error('FETCH TIPS ERROR:', tipsError)
      showToast({ type: 'error', title: 'Nie pobrano typów', message: formatAppErrorMessage(tipsError.message || String(tipsError)) })
      setTips([])
      fetchTipsRunningRef.current = false
      return
    }

    const unlockedSet = new Set((unlockedData || []).map(row => row.tip_id))
    setUnlockedTips(unlockedSet)

    const publicTipsData = Array.isArray(publicTipsPayload?.tips) ? publicTipsPayload.tips : []
    let sourceTips = [...publicTipsData, ...(tipsData || [])].map(normalizeTipRow).filter(tip => !isBetaiMultisportPublicTipHiddenV28(tip))
    if (sourceTips.length) {
      const byId = new Map()
      sourceTips.forEach(tip => {
        const key = String(tip.id || `${tip.author_id || tip.user_id || ''}-${tip.created_at || ''}-${tip.match || tip.team_home || ''}-${tip.bet_type || tip.prediction || tip.pick || ''}`)
        if (!key) return
        if (!byId.has(key)) byId.set(key, tip)
      })
      sourceTips = Array.from(byId.values())
        .sort((a, b) => new Date(b.created_at || b.match_time || 0) - new Date(a.created_at || a.match_time || 0))
    }

    // v1263: lokalny fallback dla świeżo dodanych typów ręcznych.
    // Jeżeli Supabase/restore/cache chwilowo nie odda nowego rekordu do głównego feedu,
    // dashboard nadal pokazuje własny typ, który już zapisał się w profilu.
    const recentSavedTips = readRecentSavedTips(userId).filter(isTipVisibleInActiveFeed)
    if (recentSavedTips.length) {
      const byId = new Map()
      ;[...recentSavedTips, ...sourceTips].forEach(tip => {
        const key = String(tip.id || `${tip.author_id || tip.user_id || ''}-${tip.created_at || ''}-${tip.match || ''}-${tip.bet_type || tip.prediction || ''}`)
        if (key) byId.set(key, tip)
      })
      sourceTips = Array.from(byId.values())
    }

    // v1100: Mój profil nie może zależeć od globalnego limitu ostatnich typów.
    // Wcześniej pobieraliśmy tylko najnowsze globalne rekordy, więc konto smilhytv
    // miało kafelki ze statystyk importu, ale tabele Typy/Wyniki/Historia były puste,
    // jeśli jego realne typy nie mieściły się w ostatnich 50 rekordach globalnie.
    // Teraz zawsze dokładamy własne typy aktualnie zalogowanego profilu i dopiero potem
    // robimy deduplikację. To nie dotyka Top typerów ani cudzych profili.
    try {
      const currentProfile = effectiveAccountProfile || sessionUser || {}
      const currentEmail = normalizeEmail(currentProfile.email || sessionUser?.email || '')
      const currentUsername = normalizeEmail(
        currentProfile.username ||
        currentProfile.public_slug ||
        currentProfile.user_metadata?.username ||
        currentProfile.user_metadata?.name ||
        (currentEmail ? currentEmail.split('@')[0] : '')
      )
      const ownQueries = []
      const pushOwnQuery = (column, value) => {
        const clean = String(value || '').trim()
        if (!clean) return
        ownQueries.push(
          supabase
            .from('tips').select('*')
            .eq(column, clean)
            .order('created_at', { ascending: false })
            .limit(150)
        )
      }

      if (userId) {
        pushOwnQuery('author_id', userId)
        pushOwnQuery('user_id', userId)
        pushOwnQuery('tipster_id', userId)
      }
      if (currentEmail) {
        pushOwnQuery('author_email', currentEmail)
        pushOwnQuery('user_email', currentEmail)
        pushOwnQuery('email', currentEmail)
      }
      if (currentUsername && !isGenericProfileName(currentUsername)) {
        pushOwnQuery('author_name', currentUsername)
        pushOwnQuery('username', currentUsername)
        pushOwnQuery('public_slug', currentUsername)
      }

      if (ownQueries.length) {
        const ownResults = await Promise.allSettled(ownQueries)
        const ownRows = ownResults.flatMap(result => {
          if (result.status !== 'fulfilled') return []
          const payload = result.value || {}
          if (payload.error) return []
          return Array.isArray(payload.data) ? payload.data : []
        })
        if (ownRows.length) {
          const byId = new Map()
          ;[...ownRows.map(normalizeTipRow).filter(tip => !isBetaiMultisportPublicTipHiddenV28(tip)), ...sourceTips].forEach(tip => {
            const key = String(tip.id || `${tip.author_id || tip.user_id || ''}-${tip.created_at || ''}-${tip.team_home || tip.home_team || ''}-${tip.team_away || tip.away_team || ''}-${tip.pick || tip.prediction || ''}`)
            if (key) byId.set(key, tip)
          })
          sourceTips = Array.from(byId.values()).sort((a, b) => new Date(b.created_at || b.match_time || 0) - new Date(a.created_at || a.match_time || 0))
        }
      }
    } catch (ownTipsError) {
      console.warn('own profile tips hydration skipped', ownTipsError)
    }
    const authorDynamicStatsMap = buildAuthorStatsFromTips(sourceTips)
    try {
      const authorIds = [...new Set(sourceTips.map(tip => getTipAuthorId(tip)).filter(Boolean).map(String))]
      const authorEmails = [...new Set(sourceTips.map(tip => normalizeEmail(tip.author_email || tip.email || tip.user_email)).filter(Boolean))]
      const authorNames = [...new Set(sourceTips.map(tip => normalizeEmail(tip.author_name || tip.username)).filter(Boolean).filter(name => !isGenericProfileName(name)))]
      const profileFilters = [
        ...authorIds.map(id => `id.eq.${id}`),
        ...authorEmails.map(email => `email.eq.${email}`),
        ...authorNames.map(name => `username.eq.${name}`)
      ].join(',')
      if (profileFilters) {
        const { data: authorProfiles, error: authorProfilesError } = await supabase
          .from('profiles').select('*')
          .or(profileFilters)
        if (!authorProfilesError && Array.isArray(authorProfiles)) {
          const authorProfileMap = new Map()
          authorProfiles.forEach(profile => {
            if (profile.id) authorProfileMap.set(String(profile.id), profile)
            if (profile.email) authorProfileMap.set(normalizeEmail(profile.email), profile)
            if (profile.username) authorProfileMap.set(normalizeEmail(profile.username), profile)
          })
          sourceTips = sourceTips.map(tip => {
            const profile =
              authorProfileMap.get(String(getTipAuthorId(tip) || '')) ||
              authorProfileMap.get(normalizeEmail(tip.author_email || tip.email || tip.user_email)) ||
              authorProfileMap.get(normalizeEmail(tip.author_name || tip.username))
            return profile
              ? {
                  ...tip,
                  author_name: profile.username || (profile.email ? String(profile.email).split('@')[0] : resolveRealProfileUsername(tip)),
                  username: profile.username || tip.username,
                  author_email: tip.author_email || profile.email || null,
                  author_avatar_url: tip.author_avatar_url || getProfileAvatarUrl(profile) || null,
                  author_visible_stats: finalizeAuthorStats(authorDynamicStatsMap.get(getTipAuthorStatsKey(tip)), getImportedProfileStats(profile)),
                }
              : {
                  ...tip,
                  author_name: resolveRealProfileUsername(tip)
                }
          })
        }
      }
    } catch (avatarEnrichError) {
      console.warn('tip avatar enrichment skipped', avatarEnrichError)
    }
    // WERSJA 912: cache aktualnego usera + RPC publicznych profili.
    // Naprawia przypadek, gdzie stare rekordy w DB miały avatar buchajson1988 przy smilhytv.
    try {
      cacheBetaiCurrentUserAvatar(sessionUser)
      const allProfiles = await fetchBetaiPublicProfiles()
      const profileMap = buildBetaiProfileMap(allProfiles)
      if (profileMap.size) {
        sourceTips = sourceTips.map(tip => applyProfileAvatarToTip(tip, profileMap))
      }
      const currentAvatar = getProfileAvatarUrl(sessionUser)
      if (currentAvatar) {
        const currentEmail = normalizeEmail(sessionUser?.email)
        const currentUsername = normalizeEmail(sessionUser?.username || sessionUser?.user_metadata?.username || sessionUser?.user_metadata?.name)
        sourceTips = sourceTips.map(tip => {
          const tipEmail = normalizeEmail(tip.author_email || tip.email || tip.user_email)
          const tipName = normalizeEmail(tip.author_name || tip.username)
          if ((currentEmail && tipEmail === currentEmail) || (currentUsername && tipName === currentUsername)) {
            return { ...tip, author_avatar_url: currentAvatar, avatar_url: currentAvatar, profile_avatar_url: currentAvatar }
          }
          return tip
        })
      }
    } catch (allProfileAvatarError) {
      console.warn('global tip avatar hydration skipped', allProfileAvatarError)
    }

    const finalAuthorDynamicStatsMap = buildAuthorStatsFromTips(sourceTips)
    sourceTips = sourceTips.map(tip => {
      const dynamicStats =
        finalAuthorDynamicStatsMap.get(getTipAuthorStatsKey(tip)) ||
        finalAuthorDynamicStatsMap.get(String(tip.author_id || tip.user_id || '').toLowerCase()) ||
        finalAuthorDynamicStatsMap.get(normalizeEmail(tip.author_email || tip.email || tip.user_email)) ||
        finalAuthorDynamicStatsMap.get(normalizeEmail(tip.author_name || tip.username))
      const importedStats = getImportedProfileStats(tip) || tip.author_visible_stats || tip.author_imported_stats || null
      return {
        ...tip,
        author_visible_stats: finalizeAuthorStats(dynamicStats, importedStats)
      }
    })
    let activeSubs = []
    if (userId) {
      try {
        const baseSelect = window.__betaiTipsterSubscriptionsNoExpiresAt ? 'tipster_id,status' : 'tipster_id,status,expires_at'
        let { data: subRows, error: subError } = await supabase
          .from('tipster_subscriptions')
          .select(baseSelect)
          .eq('user_id', userId)
          .eq('status', 'active')

        // Jeżeli baza nie ma kolumny expires_at, nie spamujemy więcej błędami 400.
        if (subError && !window.__betaiTipsterSubscriptionsNoExpiresAt) {
          window.__betaiTipsterSubscriptionsNoExpiresAt = true
          const fallback = await supabase
            .from('tipster_subscriptions')
            .select('tipster_id,status')
            .eq('user_id', userId)
            .eq('status', 'active')
          subRows = fallback.data
          subError = fallback.error
        }

        if (subError) throw subError
        activeSubs = Array.isArray(subRows) ? subRows.filter(row => !row.expires_at || new Date(row.expires_at).getTime() > Date.now()) : []
      } catch (error) {
        console.warn('tipster_subscriptions fetch skipped', error)
        activeSubs = []
      }
      setTipsterSubscriptions(activeSubs)
    }
    setTips(dedupeBetAiTipsByUserMatchV1746(sourceTips.filter(tip => !isBetaiMultisportPublicTipHiddenV28(tip))))
    setLastTipSaveStatus(readTipDebug())
    fetchRealRanking()
    fetchTipsRunningRef.current = false
    const queuedUserIdV29 = fetchTipsQueuedUserRef.current
    fetchTipsQueuedUserRef.current = null
    if (queuedUserIdV29 && queuedUserIdV29 !== requestedUserId && isBetaiDocumentVisibleV29()) {
      scheduleBetaiLightTaskV29('fetch-tips-queued-v29', () => fetchTips(queuedUserIdV29, { force: true }), 350)
    }
  }

  useEffect(() => {
    if (!isSupabaseConfigured || !supabase || !sessionUser?.id) return undefined

    let refreshTimer = null
    const scheduleFullRefresh = () => {
      window.clearTimeout(refreshTimer)
      refreshTimer = window.setTimeout(() => {
        fetchTips(sessionUser?.id)
        fetchRealRanking()
      }, 450)
    }

    const hydrateIncomingTip = (rawTip = {}) => {
      let incomingTip = normalizeTipRow(rawTip || {})
      if (!incomingTip?.id) return null
      if (isBetaiMultisportPublicTipHiddenV28(incomingTip)) return null
      if (isSameProfileIdentity(effectiveAccountProfile || sessionUser, incomingTip)) {
        incomingTip = normalizeTipRow({
          ...incomingTip,
          author_name: getProfileUsername(effectiveAccountProfile || sessionUser) || incomingTip.author_name,
          author_email: (effectiveAccountProfile || sessionUser)?.email || incomingTip.author_email,
          author_avatar_url: getProfileAvatarUrl(effectiveAccountProfile || sessionUser) || incomingTip.author_avatar_url,
          avatar_url: getProfileAvatarUrl(effectiveAccountProfile || sessionUser) || incomingTip.avatar_url
        })
      }
      return incomingTip
    }

    // CORE LOCK v983: realtime tips/profiles — auto-refresh bez F5, nie usuwać.
    const channel = supabase
      .channel(`betai-live-tip-center-${sessionUser.id}`)
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'tips' }, (payload) => {
        const incomingTip = hydrateIncomingTip(payload?.new || {})
        if (!incomingTip) return

        setTips(prev => dedupeBetAiTipsByUserMatchV1746([incomingTip, ...prev.filter(item => String(item.id) !== String(incomingTip.id))]).slice(0, 300))
        showLiveTipPopup(incomingTip)
        scheduleFullRefresh()
      })
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'tips' }, (payload) => {
        const incomingTip = hydrateIncomingTip(payload?.new || {})
        if (!incomingTip) return

        // v983: rozliczenie typu ma wejść w UI od razu, bez F5.
        setTips(prev => prev.map(item => String(item.id) === String(incomingTip.id) ? { ...item, ...incomingTip } : item))
        scheduleFullRefresh()
      })
      .on('postgres_changes', { event: 'DELETE', schema: 'public', table: 'tips' }, (payload) => {
        const deletedId = payload?.old?.id
        if (deletedId) setTips(prev => prev.filter(item => String(item.id) !== String(deletedId)))
        scheduleFullRefresh()
      })
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'profiles' }, (payload) => {
        const updatedProfile = payload?.new || {}
        if (!updatedProfile?.id) return

        setTips(prev => prev.map(tip => {
          const matches = String(getTipAuthorId(tip) || tip.user_id || tip.author_id || '') === String(updatedProfile.id) ||
            (updatedProfile.email && normalizeEmail(tip.author_email || tip.email || tip.user_email) === normalizeEmail(updatedProfile.email)) ||
            (updatedProfile.public_slug && normalizeEmail(tip.author_name || tip.username) === normalizeEmail(updatedProfile.public_slug)) ||
            (updatedProfile.username && !isGenericProfileName(updatedProfile.username) && normalizeEmail(tip.author_name || tip.username) === normalizeEmail(updatedProfile.username))

          if (!matches) return tip
          const importedStats = getImportedProfileStats(updatedProfile)
          return {
            ...tip,
            author_name: resolveRealProfileUsername(updatedProfile),
            author_email: updatedProfile.email || tip.author_email,
            author_avatar_url: getProfileAvatarUrl(updatedProfile) || tip.author_avatar_url,
            avatar_url: getProfileAvatarUrl(updatedProfile) || tip.avatar_url,
            imported_yield: updatedProfile.imported_yield ?? tip.imported_yield,
            imported_total_tips: updatedProfile.imported_total_tips ?? tip.imported_total_tips,
            imported_won_tips: updatedProfile.imported_won_tips ?? tip.imported_won_tips,
            imported_lost_tips: updatedProfile.imported_lost_tips ?? tip.imported_lost_tips,
            imported_pending_tips: updatedProfile.imported_pending_tips ?? tip.imported_pending_tips,
            imported_total_staked: updatedProfile.imported_total_staked ?? tip.imported_total_staked,
            imported_profit: updatedProfile.imported_profit ?? tip.imported_profit,
            imported_avg_odds: updatedProfile.imported_avg_odds ?? tip.imported_avg_odds,
            imported_highest_odds: updatedProfile.imported_highest_odds ?? tip.imported_highest_odds,
            imported_tips_currency: updatedProfile.imported_tips_currency ?? tip.imported_tips_currency,
            author_imported_stats: importedStats || tip.author_imported_stats,
            author_visible_stats: tip.author_visible_stats || importedStats
          }
        }))

        if (String(updatedProfile.id) === String((effectiveAccountProfile || sessionUser)?.id)) {
          setAccountProfile(prev => prev ? ({ ...prev, ...updatedProfile }) : updatedProfile)
        }

        fetchRealRanking()
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'referrals' }, () => {
        fetchReferralData(sessionUser?.id)
        fetchCurrentTokenBalance()
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'referral_rewards' }, () => {
        fetchReferralData(sessionUser?.id)
        fetchCurrentTokenBalance()
      })
      .subscribe()

    const softPoll = window.setInterval(() => {
      if (canRunBetaiHeavyTaskV29()) {
        fetchTips(sessionUser?.id)
      }
    }, 30000)

    const onFocusRefresh = () => {
      scheduleBetaiLightTaskV29('focus-refresh-main-v29', () => {
        fetchTips(sessionUser?.id)
        fetchRealRanking()
        fetchReferralData(sessionUser?.id)
      }, 2600)
    }
    window.addEventListener('focus', onFocusRefresh)
    window.addEventListener('betai:tab-resume-v29', onFocusRefresh)

    return () => {
      window.clearTimeout(refreshTimer)
      window.clearInterval(softPoll)
      window.removeEventListener('focus', onFocusRefresh)
      window.removeEventListener('betai:tab-resume-v29', onFocusRefresh)
      try { supabase.removeChannel(channel) } catch (_) {}
    }
  }, [sessionUser?.id, effectiveAccountProfile?.id, effectiveAccountProfile?.email])

  useEffect(() => {
    if (!sessionUser?.id) return undefined

    const viewsThatNeedSettlement = new Set(['dashboard', 'profile', 'unlockedTips'])
    const run = () => {
      if (document.visibilityState === 'visible' && viewsThatNeedSettlement.has(view)) {
        runUserTipsAutoSettlement({ force: false })
      }
    }

    const first = window.setTimeout(run, 1800)
    const interval = window.setInterval(run, 4 * 60 * 1000)
    const onFocus = () => scheduleBetaiLightTaskV29('user-tips-settlement-v29', run, 4200)
    window.addEventListener('focus', onFocus)
    window.addEventListener('betai:tab-resume-v29', onFocus)

    return () => {
      window.clearTimeout(first)
      window.clearInterval(interval)
      window.removeEventListener('focus', onFocus)
      window.removeEventListener('betai:tab-resume-v29', onFocus)
    }
  }, [sessionUser?.id, view])

  async function fetchFollowingTipsters(userId = sessionUser?.id) {
    if (!userId) {
      setFollowingTipsters(new Set())
      return
    }

    const localSet = readLocalFollowingTipsters(userId)
    let remoteSet = new Set()

    if (isSupabaseConfigured && supabase) {
      try {
        const { data, error } = await supabase
          .from('tipster_follows')
          .select('tipster_id')
          .eq('follower_id', userId)

        if (error) throw error
        remoteSet = new Set((data || []).map(row => String(row.tipster_id).toLowerCase()).filter(Boolean))
      } catch (error) {
        console.warn('fetchFollowingTipsters remote uuid skipped', error)
      }

      try {
        const email = normalizeEmail(sessionUser?.email || accountProfile?.email || '')
        let keyQuery = supabase
          .from('betai_tipster_follow_keys_v1033')
          .select('tipster_id,tipster_key,tipster_name,tipster_email')
        if (email) keyQuery = keyQuery.or(`follower_id.eq.${userId},follower_email.eq.${email}`)
        else keyQuery = keyQuery.eq('follower_id', userId)
        const { data: keyRows, error: keyError } = await keyQuery
        if (keyError) throw keyError
        ;(keyRows || []).forEach(row => {
          ;[row.tipster_id, row.tipster_key, row.tipster_name, row.tipster_email]
            .map(value => String(value || '').toLowerCase().trim())
            .filter(Boolean)
            .forEach(key => remoteSet.add(key))
        })
      } catch (error) {
        console.warn('fetchFollowingTipsters remote key skipped', error)
      }
    }

    const merged = mergeFollowingSets(localSet, remoteSet)
    writeLocalFollowingTipsters(userId, merged)
    setFollowingTipsters(merged)
  }


  async function fetchFollowStats() {
    const addFollowerStat = (stats, key, followerUnique) => {
      const cleanKey = normalizeEmail(key || '')
      if (!cleanKey) return
      stats[cleanKey] = stats[cleanKey] || { followers: 0, following: 0, _followers: new Set() }
      if (followerUnique) stats[cleanKey]._followers.add(String(followerUnique).toLowerCase())
      stats[cleanKey].followers = Math.max(Number(stats[cleanKey].followers || 0) || 0, stats[cleanKey]._followers.size)
    }

    const finishStats = (stats) => {
      Object.keys(stats).forEach(key => {
        if (stats[key]?._followers) {
          stats[key] = {
            followers: Math.max(Number(stats[key].followers || 0) || 0, stats[key]._followers.size),
            following: Number(stats[key].following || 0) || 0
          }
        }
      })
      const localSet = readLocalFollowingTipsters(sessionUser?.id)
      if (sessionUser?.id && localSet.size) {
        const viewerKey = String(sessionUser.id)
        stats[viewerKey] = stats[viewerKey] || { followers: 0, following: 0 }
        stats[viewerKey].following = Math.max(Number(stats[viewerKey].following || 0), localSet.size)
        ;[...localSet].forEach(key => {
          const cleanKey = normalizeEmail(key || '')
          if (!cleanKey) return
          stats[cleanKey] = stats[cleanKey] || { followers: 0, following: 0 }
          stats[cleanKey].followers = Math.max(Number(stats[cleanKey].followers || 0) || 0, 1)
        })
      }
      return stats
    }

    const stats = {}

    if (!isSupabaseConfigured || !supabase) {
      setFollowStats(finishStats(stats))
      return
    }

    try {
      const { data: rpcRows, error: rpcError } = await supabase.rpc('betai_get_tipster_follow_stats_v1123')
      if (rpcError) throw rpcError
      ;(rpcRows || []).forEach(row => {
        const key = normalizeEmail(row.tipster_key || row.key || '')
        const followers = Number(row.followers || row.followers_count || 0) || 0
        if (!key) return
        stats[key] = stats[key] || { followers: 0, following: 0 }
        stats[key].followers = Math.max(Number(stats[key].followers || 0) || 0, followers)
      })
    } catch (error) {
      console.warn('fetchFollowStats rpc skipped', error)
    }

    try {
      const { data, error } = await supabase
        .from('tipster_follows')
        .select('follower_id,tipster_id')

      if (error) throw error

      ;(data || []).forEach(row => {
        const followerId = String(row.follower_id || '').toLowerCase()
        const tipsterId = String(row.tipster_id || '').toLowerCase()
        if (tipsterId) addFollowerStat(stats, tipsterId, followerId)
        if (followerId) {
          stats[followerId] = stats[followerId] || { followers: 0, following: 0 }
          stats[followerId].following += 1
        }
      })
    } catch (error) {
      console.warn('fetchFollowStats uuid skipped', error)
    }

    try {
      const { data: keyRows, error: keyError } = await supabase
        .from('betai_tipster_follow_keys_v1033')
        .select('follower_id,follower_email,tipster_id,tipster_key,tipster_name,tipster_email')

      if (keyError) throw keyError

      ;(keyRows || []).forEach(row => {
        const followerUnique = normalizeEmail(row.follower_id || row.follower_email || '')
        const keys = [row.tipster_id, row.tipster_key, row.tipster_name, row.tipster_email]
        keys.forEach(key => addFollowerStat(stats, key, followerUnique))
        const followerId = String(row.follower_id || '').toLowerCase()
        if (followerId) {
          stats[followerId] = stats[followerId] || { followers: 0, following: 0 }
          stats[followerId].following += 1
        }
      })
    } catch (error) {
      console.warn('fetchFollowStats keys skipped', error)
    }

    setFollowStats(finishStats(stats))
  }


  async function fetchNotifications(userId = sessionUser?.id, options = {}) {
    const skipBalanceRefresh = Boolean(options?.skipBalanceRefresh)
    const email = normalizeEmail(sessionUser?.email || accountProfile?.email || '')
    if (!isSupabaseConfigured || !supabase || (!userId && !email)) {
      setNotifications([])
      setTokenBalance(0)
      return
    }

    const combined = []

    if (userId) {
      try {
        const { data, error } = await supabase
          .from('notifications')
          .select('*')
          .eq('user_id', userId)
          .order('created_at', { ascending: false })
          .limit(50)
        if (!error && Array.isArray(data)) combined.push(...data.map(row => ({ ...row, source: 'follow' })))
      } catch (error) {
        console.warn('fetch notifications table skipped', error)
      }
    }

    if (email) {
      try {
        const { data, error } = await supabase
          .from('betai_system_notifications')
          .select('*')
          .eq('recipient_email', email)
          .order('created_at', { ascending: false })
          .limit(100)
        if (!error && Array.isArray(data)) combined.push(...data.map(row => ({ ...row, source: 'system', message: row.body || row.message || '' })))
      } catch (error) {
        console.warn('fetch betai_system_notifications skipped', error)
      }

      if (!skipBalanceRefresh) {
        try {
          await fetchCurrentTokenBalance()
        } catch (error) {
          const localTokens = Number(localStorage.getItem('betai_tokens_' + email) || '0') || 0
          setTokenBalance(Math.max(Number(tokenBalance || 0) || 0, localTokens))
        }
      }
    }

    combined.sort((a,b) => new Date(b.created_at || 0) - new Date(a.created_at || 0))
    setNotifications(combined)
  }

  async function ensureUserWalletAndWelcome(user = sessionUser) {
    const email = normalizeEmail(user?.email || accountProfile?.email || '')
    if (!email || !isSupabaseConfigured || !supabase) return
    try {
      const { data: existing } = await supabase
        .from('betai_token_wallets')
        .select('*')
        .eq('email', email)
        .maybeSingle()

      if (!existing) {
        await supabase.from('betai_token_wallets').upsert({
          email,
          user_id: user?.id || null,
          balance: 100,
          welcome_bonus_claimed: true,
          updated_at: new Date().toISOString()
        }, { onConflict: 'email' })
        await supabase.from('betai_token_transactions').insert({
          email,
          delta_tokens: 100,
          delta_pln: 0,
          reason: 'welcome_bonus',
          ref_type: 'system'
        })
        await supabase.from('betai_system_notifications').insert({
          recipient_email: email,
          title: 'Witamy w BetAI 👋',
          body: 'Miło Cię widzieć! Na start dodaliśmy 100 coinów do Twojego konta. Możesz nimi tipować najlepsze wiadomości na czacie.',
          reward_tokens: 100,
          sent_by: 'betai',
          is_read: false
        })
        setTokenBalance(100)
        showToast({ type: 'success', title: 'Witaj w BetAI 👋', message: 'Miło Cię widzieć! Dodaliśmy 100 coinów na start.' })
      } else {
        const balance = Number(existing.balance || 0) || 0
        const localBalance = (() => { try { return Number(localStorage.getItem('betai_tokens_' + email) || '0') || 0 } catch (_) { return 0 } })()
        const displayBalance = Math.max(balance, localBalance, Number(tokenBalance || 0) || 0)
        setTokenBalance(displayBalance)
        try { localStorage.setItem('betai_tokens_' + email, String(displayBalance)) } catch (_) {}
        if (!existing.welcome_bonus_claimed) {
          const next = balance + 100
          await supabase.from('betai_token_wallets').update({ balance: next, welcome_bonus_claimed: true, updated_at: new Date().toISOString() }).eq('email', email)
          await supabase.from('betai_token_transactions').insert({ email, delta_tokens: 100, delta_pln: 0, reason: 'welcome_bonus', ref_type: 'system' })
          await supabase.from('betai_system_notifications').insert({
            recipient_email: email,
            title: 'Witamy w BetAI 👋',
            body: 'Miło Cię widzieć! Przyznaliśmy jednorazowy bonus powitalny: 100 coinów.',
            reward_tokens: 100,
            sent_by: 'betai',
            is_read: false
          })
          setTokenBalance(next)
          showToast({ type: 'success', title: 'Bonus powitalny', message: 'Dodaliśmy 100 coinów do Twojego konta.' })
        } else {
          const welcomeToastKey = `betai_welcome_toast_seen_${email}_${user?.id || ''}`
          let shouldShowWelcomeToast = true
          try {
            shouldShowWelcomeToast = sessionStorage.getItem(welcomeToastKey) !== '1'
            if (shouldShowWelcomeToast) sessionStorage.setItem(welcomeToastKey, '1')
          } catch (_) {}
          if (shouldShowWelcomeToast) {
            showToast({ type: 'success', title: 'Witaj ponownie 👋', message: 'Miło Cię widzieć z powrotem w BetAI.' })
          }
        }
      }
      await fetchNotifications(user?.id)
    } catch (error) {
      console.warn('ensure wallet/welcome skipped', error)
      try {
        const localTokens = Number(localStorage.getItem('betai_tokens_' + email) || '0') || 0
        setTokenBalance(localTokens)
      } catch (_) {}
    }
  }

  async function resolveTipsterProfile(tipsterRef, authorName) {
    const systemProfileV1838 = getBetaiSystemTipsterProfileV1838(tipsterRef, authorName)
    if (systemProfileV1838) return systemProfileV1838
    if (!isSupabaseConfigured || !supabase) return null

    const rawRef = String(tipsterRef || '').trim()
    const rawName = String(authorName || '').trim()
    const uuidLike = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i

    if (rawRef && uuidLike.test(rawRef)) {
      const { data, error } = await supabase
        .from('profiles').select('*')
        .eq('id', rawRef)
        .maybeSingle()
      if (!error && data?.id) return data
    }

    const candidates = [rawRef, rawName]
      .flatMap(value => {
        const clean = String(value || '').trim()
        if (!clean) return []
        const lower = clean.toLowerCase()
        const noAt = lower.startsWith('@') ? lower.slice(1) : lower
        const emailLocal = lower.includes('@') ? lower.split('@')[0] : ''
        return [lower, noAt, emailLocal].filter(Boolean)
      })
      .filter(Boolean)

    if (!candidates.length) return null

    const { data, error } = await supabase
      .from('profiles').select('*')
      .limit(150)

    if (error) {
      console.error('resolveTipsterProfile error', error)
      return null
    }

    return (data || []).find(profile => {
      const email = String(profile.email || '').toLowerCase()
      const emailLocal = email ? email.split('@')[0] : ''
      const username = String(profile.username || '').toLowerCase()
      const slug = String(profile.public_slug || '').toLowerCase()
      const id = String(profile.id || '').toLowerCase()
      return candidates.some(candidate =>
        candidate === id ||
        candidate === email ||
        candidate === emailLocal ||
        candidate === username ||
        candidate === slug
      )
    }) || null
  }

  async function resolveTipsterId(tipsterId, authorName) {
    const profile = await resolveTipsterProfile(tipsterId, authorName)
    return profile?.id ? String(profile.id) : null
  }

  async function openTipsterProfile(tipsterRef, authorName) {
    const profile = await resolveTipsterProfile(tipsterRef, authorName)
    try { cacheBetaiPublicProfileAvatar(profile || {}) } catch (_) {}
    const id = profile?.id ? String(profile.id) : null

    const fallbackLookup = String(authorName || tipsterRef || '').trim()
    if (!id && !fallbackLookup) {
      showToast({ type: 'error', title: 'Profil typera', message: 'Nie udało się otworzyć profilu tego użytkownika.' })
      return
    }

    const currentProfile = effectiveAccountProfile || sessionUser || {}
    const currentId = currentProfile?.id || sessionUser?.id
    const currentEmail = normalizeEmail(currentProfile?.email || sessionUser?.email || '')
    const currentUsername = normalizeEmail(resolveRealProfileUsername(currentProfile || sessionUser || {}))
    const targetEmail = normalizeEmail(profile?.email || '')
    const targetUsername = normalizeEmail(profile?.username || profile?.public_slug || '')

    const fallbackLookupKey = normalizeEmail(fallbackLookup)
    const isOwnProfile = Boolean(
      (id && currentId && String(currentId) === id) ||
      (currentEmail && targetEmail && currentEmail === targetEmail) ||
      (currentUsername && targetUsername && currentUsername === targetUsername) ||
      (!id && fallbackLookupKey && (fallbackLookupKey === currentUsername || fallbackLookupKey === currentEmail || fallbackLookupKey === String(currentEmail || '').split('@')[0]))
    )

    setSelectedTipsterId(null)
    if (isOwnProfile) {
      setView('profile')
    } else {
      setSelectedTipsterId(id || `lookup:${encodeURIComponent(fallbackLookup)}`)
      setView('dashboard')
    }
    try { window.scrollTo({ top: 0, behavior: 'smooth' }) } catch (_) {}
  }

  async function toggleFollowTipster(tipsterId, authorName, extraFollowKeys = []) {
    if (!sessionUser?.id) {
      showToast({ type: 'error', title: 'Zaloguj się', message: 'Musisz być zalogowany, aby obserwować typera.' })
      return
    }

    const currentNameKey = normalizeEmail(resolveRealProfileUsername(effectiveAccountProfile || sessionUser || {}))
    const currentEmailKey = normalizeEmail((effectiveAccountProfile || sessionUser || {})?.email || sessionUser?.email || '')
    const currentEmailLocalKey = currentEmailKey ? currentEmailKey.split('@')[0] : ''
    const rawTargetKey = normalizeEmail(authorName || tipsterId || '')
    const rawTargetLocalKey = rawTargetKey ? rawTargetKey.split('@')[0] : ''
    const extraFollowKeysList = (Array.isArray(extraFollowKeys) ? extraFollowKeys : [extraFollowKeys])
      .map(value => normalizeEmail(value || ''))
      .filter(Boolean)
    const extraFollowLocalKeys = extraFollowKeysList
      .map(value => value.includes('@') ? value.split('@')[0] : '')
      .filter(Boolean)
    const uuidLike = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i

    const isOwnByName = Boolean(
      rawTargetKey &&
      (
        rawTargetKey === currentNameKey ||
        rawTargetKey === currentEmailKey ||
        rawTargetKey === currentEmailLocalKey ||
        rawTargetLocalKey === currentNameKey ||
        rawTargetLocalKey === currentEmailLocalKey
      )
    )

    let resolvedId = null
    if (isSupabaseConfigured && supabase) {
      try { resolvedId = await resolveTipsterId(tipsterId, authorName) } catch (_) { resolvedId = null }
    }

    const id = resolvedId ? String(resolvedId) : null
    const isOwnById = Boolean(id && String(id) === String(sessionUser.id))
    if (isOwnByName || isOwnById) {
      showToast({ type: 'info', title: 'Follow', message: 'Nie możesz obserwować własnego konta.' })
      return
    }

    const idKey = id ? String(id).toLowerCase() : ''
    const localKey = rawTargetKey || idKey
    const localNameKey = rawTargetLocalKey || ''
    const followKeys = [...new Set([idKey, localKey, localNameKey, ...extraFollowKeysList, ...extraFollowLocalKeys].map(value => String(value || '').toLowerCase()).filter(Boolean))]
    if (!followKeys.length) {
      showToast({ type: 'error', title: 'Follow', message: 'Nie udało się odczytać nazwy typera.' })
      return
    }

    const alreadyFollowing = followKeys.some(key => followingTipsters.has(key))

    if (alreadyFollowing) removeLocalFollowingTipster(sessionUser.id, followKeys)
    else addLocalFollowingTipster(sessionUser.id, followKeys)

    setFollowingTipsters(prev => {
      const next = new Set([...(prev || [])].map(value => String(value).toLowerCase()))
      if (alreadyFollowing) {
        followKeys.forEach(key => next.delete(key))
      } else {
        followKeys.forEach(key => next.add(key))
      }
      return next
    })

    setFollowStats(prev => {
      const next = { ...(prev || {}) }
      const viewerKey = String(sessionUser.id || '')
      const delta = alreadyFollowing ? -1 : 1
      followKeys.forEach(key => {
        const cleanKey = String(key || '').toLowerCase().trim()
        if (!cleanKey) return
        const current = next[cleanKey] || { followers: 0, following: 0 }
        next[cleanKey] = { ...current, followers: Math.max(0, Number(current.followers || 0) + delta) }
      })
      if (viewerKey) {
        const current = next[viewerKey] || { followers: 0, following: 0 }
        next[viewerKey] = { ...current, following: Math.max(0, Number(current.following || 0) + delta) }
      }
      return next
    })

    const canPersistInSupabase = Boolean(isSupabaseConfigured && supabase && !isOwnById)
    if (canPersistInSupabase) {
      try {
        if (id && uuidLike.test(id)) {
          if (alreadyFollowing) {
            const { error } = await supabase.from('tipster_follows').delete().eq('follower_id', sessionUser.id).eq('tipster_id', id)
            if (error) throw error
          } else {
            const { error } = await supabase.from('tipster_follows').upsert({ follower_id: sessionUser.id, tipster_id: id }, { onConflict: 'follower_id,tipster_id' })
            if (error) throw error
          }
        }

        const followerEmail = normalizeEmail(sessionUser?.email || accountProfile?.email || '')
        const tipsterKey = String(localKey || idKey || rawTargetKey || authorName || tipsterId || '').toLowerCase().trim()
        if (tipsterKey) {
          if (alreadyFollowing) {
            const deleteKeys = [...new Set([tipsterKey, ...followKeys].map(value => String(value || '').toLowerCase().trim()).filter(Boolean))]
            const deleteAttempts = []
            if (id) {
              deleteAttempts.push(supabase.from('betai_tipster_follow_keys_v1033').delete().eq('follower_id', sessionUser.id).eq('tipster_id', id))
              if (followerEmail) deleteAttempts.push(supabase.from('betai_tipster_follow_keys_v1033').delete().eq('follower_email', followerEmail).eq('tipster_id', id))
            }
            if (deleteKeys.length) {
              deleteAttempts.push(supabase.from('betai_tipster_follow_keys_v1033').delete().eq('follower_id', sessionUser.id).in('tipster_key', deleteKeys))
              deleteAttempts.push(supabase.from('betai_tipster_follow_keys_v1033').delete().eq('follower_id', sessionUser.id).in('tipster_name', deleteKeys))
              if (followerEmail) {
                deleteAttempts.push(supabase.from('betai_tipster_follow_keys_v1033').delete().eq('follower_email', followerEmail).in('tipster_key', deleteKeys))
                deleteAttempts.push(supabase.from('betai_tipster_follow_keys_v1033').delete().eq('follower_email', followerEmail).in('tipster_name', deleteKeys))
              }
            }
            for (const attempt of deleteAttempts) {
              const { error } = await attempt
              if (error) throw error
            }
          } else {
            const { error } = await supabase.from('betai_tipster_follow_keys_v1033').upsert({
              follower_id: sessionUser.id,
              follower_email: followerEmail,
              tipster_id: id || null,
              tipster_key: tipsterKey,
              tipster_name: String(authorName || tipsterKey || '').trim(),
              tipster_email: String(authorName || '').includes('@') ? normalizeEmail(authorName) : null,
              created_at: new Date().toISOString()
            }, { onConflict: 'follower_id,tipster_key' })
            if (error) throw error
          }
        }
      } catch (error) {
        console.warn('follow remote save failed', error)
        showToast({ type: 'error', title: 'Follow nie zapisany', message: 'Supabase nie zapisał obserwowania. Odpal SQL 1033, żeby follow miał pamięć po deployu.' })
      }
    }

    await fetchFollowingTipsters(sessionUser.id)
    if (alreadyFollowing) {
      removeLocalFollowingTipster(sessionUser.id, followKeys)
      setFollowingTipsters(prev => {
        const next = new Set([...(prev || [])].map(value => String(value).toLowerCase()))
        followKeys.forEach(key => next.delete(key))
        return next
      })
    } else {
      addLocalFollowingTipster(sessionUser.id, followKeys)
      setFollowingTipsters(prev => new Set([...(prev || []), ...followKeys].map(value => String(value).toLowerCase())))
    }
    fetchFollowStats()
    showToast({ type: 'success', title: 'Follow', message: alreadyFollowing ? 'Przestałeś obserwować typera.' : 'Obserwujesz typera.' })
  }

  useEffect(() => {
    if (sessionUser?.id) fetchRankingChallengeClaims(sessionUser.id)
  }, [sessionUser?.id])

  async function fetchRankingChallengeClaims(userId = sessionUser?.id) {
    const email = normalizeEmail(sessionUser?.email || accountProfile?.email || '')
    if ((!userId && !email) || !isSupabaseConfigured || !supabase) {
      setRankingChallengeClaims([])
      return []
    }
    try {
      let query = supabase
        .from('betai_ranking_challenge_claims')
        .select('challenge_key,period_key,created_at,reward_tokens,email,user_id')
      if (userId && email) {
        query = query.or(`user_id.eq.${userId},email.eq.${email}`)
      } else if (userId) {
        query = query.eq('user_id', userId)
      } else {
        query = query.eq('email', email)
      }
      const { data, error } = await query
      if (error) throw error
      const rows = Array.from(new Map((Array.isArray(data) ? data : []).map(row => [`${row.challenge_key}_${row.period_key}`, row])).values())
      setRankingChallengeClaims(rows)
      return rows
    } catch (error) {
      console.warn('ranking challenge claims skipped', error)
      return []
    }
  }

  async function claimRankingChallengeReward(challenge) {
    const email = normalizeEmail(sessionUser?.email || accountProfile?.email || '')
    const userId = sessionUser?.id
    if (!userId || !email) {
      showToast({ type: 'error', title: 'Wyzwania', message: 'Zaloguj się, aby odebrać nagrodę.' })
      return
    }
    if (!challenge?.done) {
      showToast({ type: 'info', title: 'Wyzwania', message: 'Najpierw osiągnij cel wyzwania.' })
      return
    }

    const getRankingRewardPeriodKey = () => {
      const shifted = new Date(Date.now() - 60 * 60 * 1000)
      const day = shifted.getUTCDay() || 7
      shifted.setUTCDate(shifted.getUTCDate() + 4 - day)
      const yearStart = new Date(Date.UTC(shifted.getUTCFullYear(), 0, 1))
      const week = Math.ceil((((shifted - yearStart) / 86400000) + 1) / 7)
      return `${shifted.getUTCFullYear()}-${String(week).padStart(2, '0')}`
    }
    const period = getRankingRewardPeriodKey()
    const rewardKey = `ranking_challenge_${challenge.key}_${period}`
    const freshClaims = await fetchRankingChallengeClaims(userId)
    const alreadyClaimedInDb = (freshClaims || rankingChallengeClaims || []).some(row =>
      String(row.challenge_key) === String(challenge.key) && String(row.period_key) === String(period)
    )
    if (alreadyClaimedInDb) {
      showToast({ type: 'info', title: 'Wyzwania', message: 'Nagroda za to wyzwanie została już odebrana w tym tygodniu.' })
      return true
    }

    try {
      if (isSupabaseConfigured && supabase) {
        const { data, error } = await supabase.rpc('claim_ranking_challenge_reward', {
          p_user_id: userId,
          p_email: email,
          p_challenge_key: challenge.key,
          p_challenge_title: challenge.title
        })
        if (error) throw error
        if (data && data.claimed === false) {
          const existingBalance = Number(data.new_balance ?? data.balance ?? tokenBalance ?? 0) || 0
          persistTokenBalanceNoRollback(email, existingBalance, challenge.key)
          await fetchRankingChallengeClaims(userId)
          try { localStorage.setItem(`betai_ranking_claimed_v1015_${userId}`, JSON.stringify({ [`${challenge.key}_${period}`]: true })) } catch (_) {}
          showToast({ type: 'info', title: 'Wyzwania', message: 'Nagroda za to wyzwanie była już odebrana.' })
          return true
        }
        const nextBalance = Number(data?.new_balance ?? data?.balance ?? (Number(tokenBalance || 0) + 1)) || 0
        persistTokenBalanceNoRollback(email, nextBalance, challenge.key)
      } else {
        const next = Number(tokenBalance || 0) + 1
        persistTokenBalanceNoRollback(email, next, challenge.key)
      }
      try { localStorage.setItem(`betai_ranking_claimed_v1015_${userId}`, JSON.stringify({ [`${challenge.key}_${period}`]: true })) } catch (_) {}

      const localRewardNotification = {
        id: `ranking_reward_${rewardKey}`,
        title: 'Wyzwanie ukończone',
        body: `${challenge.title}: otrzymujesz 1 coin.`,
        message: `${challenge.title}: otrzymujesz 1 coin.`,
        reward_tokens: 1,
        created_at: new Date().toISOString(),
        is_read: false,
        source: 'ranking'
      }
      setNotifications(prev => [localRewardNotification, ...(prev || []).filter(item => String(item.id) !== String(localRewardNotification.id))])
      try { showReceivedTipFromNotification(localRewardNotification, false) } catch (_) {}
      try {
        window.dispatchEvent(new CustomEvent('betai-wallet-history-changed'))
        window.dispatchEvent(new CustomEvent('betai:notification-created', { detail: localRewardNotification }))
      } catch (_) {}

      await fetchNotifications(userId)
      await fetchRankingChallengeClaims(userId)
      // Opóźniony refresh nie może cofnąć salda, bo fetchCurrentTokenBalance respektuje reward lock.
      window.setTimeout(() => { try { fetchCurrentTokenBalance() } catch (_) {} }, 1200)
      showToast({ type: 'success', title: 'Wyzwanie ukończone', message: `${challenge.title}: +1 coin. Powiadomienie dodane.` })
      return true
    } catch (error) {
      console.warn('claimRankingChallengeReward blocked because DB claim failed', error)
      showToast({ type: 'error', title: 'Wyzwania', message: 'Nie zapisałem nagrody, bo Supabase zwrócił błąd. Nie dopisuję Coin lokalnie, żeby saldo nie cofało się po deployu.' })
      return false
    }
  }

  async function markAllNotificationsRead() {
    if (!isSupabaseConfigured || !supabase) return
    const email = normalizeEmail(sessionUser?.email || accountProfile?.email || '')
    let failed = false

    if (sessionUser?.id) {
      try {
        const { error } = await supabase
          .from('notifications')
          .update({ is_read: true })
          .eq('user_id', sessionUser.id)
          .eq('is_read', false)
        if (error) failed = true
      } catch (_) { failed = true }
    }

    if (email) {
      try {
        const { error } = await supabase
          .from('betai_system_notifications')
          .update({ is_read: true })
          .eq('recipient_email', email)
          .eq('is_read', false)
        if (error) failed = true
      } catch (_) { failed = true }
    }

    await fetchNotifications(sessionUser?.id)
    if (failed) showToast({ type: 'info', title: 'Powiadomienia', message: 'Część powiadomień mogła już być oznaczona albo tabela nie istnieje.' })
    else showToast({ type: 'success', title: 'Powiadomienia', message: 'Oznaczono jako przeczytane.' })
  }


